void
AM_getIslope
( mline_t* ml,
  islope_t* is )
{
    int dx, dy;
    dy = ml->a.y - ml->b.y;
    dx = ml->b.x - ml->a.x;
    if (!dy) is->islp = (dx<0?-((int)0x7fffffff):((int)0x7fffffff));
    else is->islp = FixedDiv(dx, dy);
    if (!dx) is->slp = (dy<0?-((int)0x7fffffff):((int)0x7fffffff));
    else is->slp = FixedDiv(dy, dx);
}
void AM_activateNewScale(void)
{
    m_x += m_w/2;
    m_y += m_h/2;
    m_w = FixedMul(((f_w)<<16),scale_ftom);
    m_h = FixedMul(((f_h)<<16),scale_ftom);
    m_x -= m_w/2;
    m_y -= m_h/2;
    m_x2 = m_x + m_w;
    m_y2 = m_y + m_h;
}
void AM_saveScaleAndLoc(void)
{
    old_m_x = m_x;
    old_m_y = m_y;
    old_m_w = m_w;
    old_m_h = m_h;
}
void AM_restoreScaleAndLoc(void)
{
    m_w = old_m_w;
    m_h = old_m_h;
    if (!followplayer)
    {
 m_x = old_m_x;
 m_y = old_m_y;
    } else {
 m_x = plr->mo->x - m_w/2;
 m_y = plr->mo->y - m_h/2;
    }
    m_x2 = m_x + m_w;
    m_y2 = m_y + m_h;
    scale_mtof = FixedDiv(f_w<<16, m_w);
    scale_ftom = FixedDiv((1<<16), scale_mtof);
}
void AM_addMark(void)
{
    markpoints[markpointnum].x = m_x + m_w/2;
    markpoints[markpointnum].y = m_y + m_h/2;
    markpointnum = (markpointnum + 1) % 10;
}
void AM_findMinMaxBoundaries(void)
{
    int i;
    fixed_t a;
    fixed_t b;
    min_x = min_y = ((int)0x7fffffff);
    max_x = max_y = -((int)0x7fffffff);
    for (i=0;i<numvertexes;i++)
    {
 if (vertexes[i].x < min_x)
     min_x = vertexes[i].x;
 else if (vertexes[i].x > max_x)
     max_x = vertexes[i].x;
 if (vertexes[i].y < min_y)
     min_y = vertexes[i].y;
 else if (vertexes[i].y > max_y)
     max_y = vertexes[i].y;
    }
    max_w = max_x - min_x;
    max_h = max_y - min_y;
    min_w = 2*16*(1<<16);
    min_h = 2*16*(1<<16);
    a = FixedDiv(f_w<<16, max_w);
    b = FixedDiv(f_h<<16, max_h);
    min_scale_mtof = a < b ? a : b;
    max_scale_mtof = FixedDiv(f_h<<16, 2*16*(1<<16));
}
void AM_changeWindowLoc(void)
{
    if (m_paninc.x || m_paninc.y)
    {
 followplayer = 0;
 f_oldloc.x = ((int)0x7fffffff);
    }
    m_x += m_paninc.x;
    m_y += m_paninc.y;
    if (m_x + m_w/2 > max_x)
 m_x = max_x - m_w/2;
    else if (m_x + m_w/2 < min_x)
 m_x = min_x - m_w/2;
    if (m_y + m_h/2 > max_y)
 m_y = max_y - m_h/2;
    else if (m_y + m_h/2 < min_y)
 m_y = min_y - m_h/2;
    m_x2 = m_x + m_w;
    m_y2 = m_y + m_h;
}
void AM_initVariables(void)
{
    int pnum;
    static event_t st_notify = { ev_keyup, ((('a'<<24)+('m'<<16)) | ('e'<<8)) };
    automapactive = true;
    fb = screens[0];
    f_oldloc.x = ((int)0x7fffffff);
    amclock = 0;
    lightlev = 0;
    m_paninc.x = m_paninc.y = 0;
    ftom_zoommul = (1<<16);
    mtof_zoommul = (1<<16);
    m_w = FixedMul(((f_w)<<16),scale_ftom);
    m_h = FixedMul(((f_h)<<16),scale_ftom);
    if (!playeringame[pnum = consoleplayer])
 for (pnum=0;pnum<4;pnum++)
     if (playeringame[pnum])
  break;
    plr = &players[pnum];
    m_x = plr->mo->x - m_w/2;
    m_y = plr->mo->y - m_h/2;
    AM_changeWindowLoc();
    old_m_x = m_x;
    old_m_y = m_y;
    old_m_w = m_w;
    old_m_h = m_h;
    ST_Responder(&st_notify);
}
