void AM_unloadPics(void)
{
    int i;
    for (i=0;i<10;i++)
 { if (( (memblock_t *)( (byte *)(marknums[i]) - sizeof(memblock_t)))->id!=0x1d4a11) I_Error("Z_CT at ""doom_amalg.c"":%i",520); Z_ChangeTag2(marknums[i],101); };;
}
