void D_PostEvent (event_t* ev)
{
    events[eventhead] = *ev;
    eventhead = (++eventhead)&(64 -1);
}
void D_ProcessEvents (void)
{
    event_t* ev;
    if ( ( gamemode == commercial )
  && (W_CheckNumForName("map01")<0) )
      return;
    for ( ; eventtail != eventhead ; eventtail = (++eventtail)&(64 -1) )
    {
 ev = &events[eventtail];
 if (M_Responder (ev))
     continue;
 G_Responder (ev);
    }
}
gamestate_t wipegamestate = GS_DEMOSCREEN;
extern boolean setsizeneeded;
extern int showMessages;
void R_ExecuteSetViewSize (void);
void D_Display (void)
{
    static boolean viewactivestate = false;
    static boolean menuactivestate = false;
    static boolean inhelpscreensstate = false;
    static boolean fullscreen = false;
    static gamestate_t oldgamestate = -1;
    static int borderdrawcount;
    int nowtime;
    int tics;
    int wipestart;
    int y;
    boolean done;
    boolean wipe;
    boolean redrawsbar;
    if (nodrawers)
 return;
    redrawsbar = false;
    if (setsizeneeded)
    {
 R_ExecuteSetViewSize ();
 oldgamestate = -1;
 borderdrawcount = 3;
    }
    if (gamestate != wipegamestate)
    {
 wipe = true;
 wipe_StartScreen(0, 0, 320, 200);
    }
    else
 wipe = false;
    if (gamestate == GS_LEVEL && gametic)
 HU_Erase();
    switch (gamestate)
    {
      case GS_LEVEL:
 if (!gametic)
     break;
 if (automapactive)
     AM_Drawer ();
 if (wipe || (viewheight != 200 && fullscreen) )
     redrawsbar = true;
 if (inhelpscreensstate && !inhelpscreens)
     redrawsbar = true;
 ST_Drawer (viewheight == 200, redrawsbar );
 fullscreen = viewheight == 200;
 break;
      case GS_INTERMISSION:
 WI_Drawer ();
 break;
      case GS_FINALE:
 F_Drawer ();
 break;
      case GS_DEMOSCREEN:
 D_PageDrawer ();
 break;
    }
    I_UpdateNoBlit ();
    if (gamestate == GS_LEVEL && !automapactive && gametic)
 R_RenderPlayerView (&players[displayplayer]);
    if (gamestate == GS_LEVEL && gametic)
 HU_Drawer ();
    if (gamestate != oldgamestate && gamestate != GS_LEVEL)
 I_SetPalette (W_CacheLumpName ("PLAYPAL",101));
    if (gamestate == GS_LEVEL && oldgamestate != GS_LEVEL)
    {
 viewactivestate = false;
 R_FillBackScreen ();
    }
    if (gamestate == GS_LEVEL && !automapactive && scaledviewwidth != 320)
    {
 if (menuactive || menuactivestate || !viewactivestate)
     borderdrawcount = 3;
 if (borderdrawcount)
 {
     R_DrawViewBorder ();
     borderdrawcount--;
 }
    }
    menuactivestate = menuactive;
    viewactivestate = viewactive;
    inhelpscreensstate = inhelpscreens;
    oldgamestate = wipegamestate = gamestate;
    if (paused)
    {
 if (automapactive)
     y = 4;
 else
     y = viewwindowy+4;
 V_DrawPatchDirect(viewwindowx+(scaledviewwidth-68)/2,
     y,0,W_CacheLumpName ("M_PAUSE", 101));
    }
    M_Drawer ();
    NetUpdate ();
    if (!wipe)
    {
 I_FinishUpdate ();
 return;
    }
    wipe_EndScreen(0, 0, 320, 200);
    wipestart = I_GetTime () - 1;
    do
    {
 do
 {
     nowtime = I_GetTime ();
     tics = nowtime - wipestart;
 } while (!tics);
 wipestart = nowtime;
 done = wipe_ScreenWipe(wipe_Melt
          , 0, 0, 320, 200, tics);
 I_UpdateNoBlit ();
 M_Drawer ();
 I_FinishUpdate ();
    } while (!done);
}
extern boolean demorecording;
void D_DoomLoop (void)
{
    if (demorecording)
 G_BeginRecording ();
    if (M_CheckParm ("-debugfile"))
    {
 char filename[20];
 sprintf (filename,"debug%i.txt",consoleplayer);
 printf ("debug output to: %s\n",filename);
 debugfile = fopen (filename,"w");
    }
    I_InitGraphics ();
    while (1)
    {
 I_StartFrame ();
 if (singletics)
 {
     I_StartTic ();
     D_ProcessEvents ();
     G_BuildTiccmd (&netcmds[consoleplayer][maketic%12]);
     if (advancedemo)
  D_DoAdvanceDemo ();
     M_Ticker ();
     G_Ticker ();
     gametic++;
     maketic++;
 }
 else
 {
     TryRunTics ();
 }
 S_UpdateSounds (players[consoleplayer].mo);
 D_Display ();
 I_SubmitSound();
    }
}
