void I_InitNetwork (void);
void I_NetCmd (void);
doomcom_t* doomcom;
doomdata_t* netbuffer;
ticcmd_t localcmds[12];
ticcmd_t netcmds[4][12];
int nettics[8];
boolean nodeingame[8];
boolean remoteresend[8];
int resendto[8];
int resendcount[8];
int nodeforplayer[4];
int maketic;
int lastnettic;
