void F_StartFinale (void)
{
    gameaction = ga_nothing;
    gamestate = GS_FINALE;
    viewactive = false;
    automapactive = false;
    switch ( gamemode )
    {
      case shareware:
      case registered:
      case retail:
      {
 S_ChangeMusic(mus_victor, true);
 switch (gameepisode)
 {
   case 1:
     finaleflat = "FLOOR4_8";
     finaletext = e1text;
     break;
   case 2:
     finaleflat = "SFLR6_1";
     finaletext = e2text;
     break;
   case 3:
     finaleflat = "MFLR8_4";
     finaletext = e3text;
     break;
   case 4:
     finaleflat = "MFLR8_3";
     finaletext = e4text;
     break;
   default:
     break;
 }
 break;
      }
      case commercial:
      {
   S_ChangeMusic(mus_read_m, true);
   switch (gamemap)
   {
     case 6:
       finaleflat = "SLIME16";
       finaletext = c1text;
       break;
     case 11:
       finaleflat = "RROCK14";
       finaletext = c2text;
       break;
     case 20:
       finaleflat = "RROCK07";
       finaletext = c3text;
       break;
     case 30:
       finaleflat = "RROCK17";
       finaletext = c4text;
       break;
     case 15:
       finaleflat = "RROCK13";
       finaletext = c5text;
       break;
     case 31:
       finaleflat = "RROCK19";
       finaletext = c6text;
       break;
     default:
       break;
   }
   break;
      }
      default:
 S_ChangeMusic(mus_read_m, true);
 finaleflat = "F_SKY1";
 finaletext = c1text;
 break;
    }
    finalestage = 0;
    finalecount = 0;
}
boolean F_Responder (event_t *event)
{
    if (finalestage == 2)
 return F_CastResponder (event);
    return false;
}
void F_Ticker (void)
{
    int i;
    if ( (gamemode == commercial)
      && ( finalecount > 50) )
    {
      for (i=0 ; i<4 ; i++)
 if (players[i].cmd.buttons)
   break;
      if (i < 4)
      {
 if (gamemap == 30)
   F_StartCast ();
 else
   gameaction = ga_worlddone;
      }
    }
    finalecount++;
    if (finalestage == 2)
    {
 F_CastTicker ();
 return;
    }
    if ( gamemode == commercial)
 return;
    if (!finalestage && finalecount>strlen (finaletext)*3 + 250)
    {
 finalecount = 0;
 finalestage = 1;
 wipegamestate = -1;
 if (gameepisode == 3)
     S_StartMusic (mus_bunny);
    }
}
extern patch_t *hu_font[('_' - '!' + 1)];
void F_TextWrite (void)
{
    byte* src;
    byte* dest;
    int x,y,w;
    int count;
    char* ch;
    int c;
    int cx;
    int cy;
    src = W_CacheLumpName ( finaleflat , 101);
    dest = screens[0];
    for (y=0 ; y<200 ; y++)
    {
 for (x=0 ; x<320/64 ; x++)
 {
     memcpy (dest, src+((y&63)<<6), 64);
     dest += 64;
 }
 if (320&63)
 {
     memcpy (dest, src+((y&63)<<6), 320&63);
     dest += (320&63);
 }
    }
    V_MarkRect (0, 0, 320, 200);
    cx = 10;
    cy = 10;
    ch = finaletext;
    count = (finalecount - 10)/3;
    if (count < 0)
 count = 0;
    for ( ; count ; count-- )
    {
 c = *ch++;
 if (!c)
     break;
 if (c == '\n')
 {
     cx = 10;
     cy += 11;
     continue;
 }
 c = toupper(c) - '!';
 if (c < 0 || c> ('_' - '!' + 1))
 {
     cx += 4;
     continue;
 }
 w = (hu_font[c]->width);
 if (cx+w > 320)
     break;
 V_DrawPatch(cx, cy, 0, hu_font[c]);
 cx+=w;
    }
}
