int castnum;
int casttics;
state_t* caststate;
boolean castdeath;
int castframes;
int castonmelee;
boolean castattacking;
extern gamestate_t wipegamestate;
void F_StartCast (void)
{
    wipegamestate = -1;
    castnum = 0;
    caststate = &states[mobjinfo[castorder[castnum].type].seestate];
    casttics = caststate->tics;
    castdeath = false;
    finalestage = 2;
    castframes = 0;
    castonmelee = 0;
    castattacking = false;
    S_ChangeMusic(mus_evil, true);
}
void F_CastTicker (void)
{
    int st;
    int sfx;
    if (--casttics > 0)
 return;
    if (caststate->tics == -1 || caststate->nextstate == S_NULL)
    {
 castnum++;
 castdeath = false;
 if (castorder[castnum].name == ((void *)0))
     castnum = 0;
 if (mobjinfo[castorder[castnum].type].seesound)
     S_StartSound (((void *)0), mobjinfo[castorder[castnum].type].seesound);
 caststate = &states[mobjinfo[castorder[castnum].type].seestate];
 castframes = 0;
    }
    else
    {
 if (caststate == &states[S_PLAY_ATK1])
     goto stopattack;
 st = caststate->nextstate;
 caststate = &states[st];
 castframes++;
 switch (st)
 {
   case S_PLAY_ATK1: sfx = sfx_dshtgn; break;
   case S_POSS_ATK2: sfx = sfx_pistol; break;
   case S_SPOS_ATK2: sfx = sfx_shotgn; break;
   case S_VILE_ATK2: sfx = sfx_vilatk; break;
   case S_SKEL_FIST2: sfx = sfx_skeswg; break;
   case S_SKEL_FIST4: sfx = sfx_skepch; break;
   case S_SKEL_MISS2: sfx = sfx_skeatk; break;
   case S_FATT_ATK8:
   case S_FATT_ATK5:
   case S_FATT_ATK2: sfx = sfx_firsht; break;
   case S_CPOS_ATK2:
   case S_CPOS_ATK3:
   case S_CPOS_ATK4: sfx = sfx_shotgn; break;
   case S_TROO_ATK3: sfx = sfx_claw; break;
   case S_SARG_ATK2: sfx = sfx_sgtatk; break;
   case S_BOSS_ATK2:
   case S_BOS2_ATK2:
   case S_HEAD_ATK2: sfx = sfx_firsht; break;
   case S_SKULL_ATK2: sfx = sfx_sklatk; break;
   case S_SPID_ATK2:
   case S_SPID_ATK3: sfx = sfx_shotgn; break;
   case S_BSPI_ATK2: sfx = sfx_plasma; break;
   case S_CYBER_ATK2:
   case S_CYBER_ATK4:
   case S_CYBER_ATK6: sfx = sfx_rlaunc; break;
   case S_PAIN_ATK3: sfx = sfx_sklatk; break;
   default: sfx = 0; break;
 }
 if (sfx)
     S_StartSound (((void *)0), sfx);
    }
    if (castframes == 12)
    {
 castattacking = true;
 if (castonmelee)
     caststate=&states[mobjinfo[castorder[castnum].type].meleestate];
 else
     caststate=&states[mobjinfo[castorder[castnum].type].missilestate];
 castonmelee ^= 1;
 if (caststate == &states[S_NULL])
 {
     if (castonmelee)
  caststate=
      &states[mobjinfo[castorder[castnum].type].meleestate];
     else
  caststate=
      &states[mobjinfo[castorder[castnum].type].missilestate];
 }
    }
    if (castattacking)
    {
 if (castframes == 24
     || caststate == &states[mobjinfo[castorder[castnum].type].seestate] )
 {
   stopattack:
     castattacking = false;
     castframes = 0;
     caststate = &states[mobjinfo[castorder[castnum].type].seestate];
 }
    }
    casttics = caststate->tics;
    if (casttics == -1)
 casttics = 15;
}
boolean F_CastResponder (event_t* ev)
{
    if (ev->type != ev_keydown)
 return false;
    if (castdeath)
 return true;
    castdeath = true;
    caststate = &states[mobjinfo[castorder[castnum].type].deathstate];
    casttics = caststate->tics;
    castframes = 0;
    castattacking = false;
    if (mobjinfo[castorder[castnum].type].deathsound)
 S_StartSound (((void *)0), mobjinfo[castorder[castnum].type].deathsound);
    return true;
}
void F_CastPrint (char* text)
{
    char* ch;
    int c;
    int cx;
    int w;
    int width;
    ch = text;
    width = 0;
    while (ch)
    {
 c = *ch++;
 if (!c)
     break;
 c = toupper(c) - '!';
 if (c < 0 || c> ('_' - '!' + 1))
 {
     width += 4;
     continue;
 }
 w = (hu_font[c]->width);
 width += w;
    }
    cx = 160-width/2;
    ch = text;
    while (ch)
    {
 c = *ch++;
 if (!c)
     break;
 c = toupper(c) - '!';
 if (c < 0 || c> ('_' - '!' + 1))
 {
     cx += 4;
     continue;
 }
 w = (hu_font[c]->width);
 V_DrawPatch(cx, 180, 0, hu_font[c]);
 cx+=w;
    }
}
void V_DrawPatchFlipped (int x, int y, int scrn, patch_t *patch);
void F_CastDrawer (void)
{
    spritedef_t* sprdef;
    spriteframe_t* sprframe;
    int lump;
    boolean flip;
    patch_t* patch;
    V_DrawPatch (0,0,0, W_CacheLumpName ("BOSSBACK", 101));
    F_CastPrint (castorder[castnum].name);
    sprdef = &sprites[caststate->sprite];
    sprframe = &sprdef->spriteframes[ caststate->frame & 0x7fff];
    lump = sprframe->lump[0];
    flip = (boolean)sprframe->flip[0];
    patch = W_CacheLumpNum (lump+firstspritelump, 101);
    if (flip)
 V_DrawPatchFlipped (160,170,0,patch);
    else
 V_DrawPatch (160,170,0,patch);
}
void
F_DrawPatchCol
( int x,
  patch_t* patch,
  int col )
{
    column_t* column;
    byte* source;
    byte* dest;
    byte* desttop;
    int count;
    column = (column_t *)((byte *)patch + (patch->columnofs[col]));
    desttop = screens[0]+x;
    while (column->topdelta != 0xff )
    {
 source = (byte *)column + 3;
 dest = desttop + column->topdelta*320;
 count = column->length;
 while (count--)
 {
     *dest = *source++;
     dest += 320;
 }
 column = (column_t *)( (byte *)column + column->length + 4 );
    }
}
void F_BunnyScroll (void)
{
    int scrolled;
    int x;
    patch_t* p1;
    patch_t* p2;
    char name[10];
    int stage;
    static int laststage;
    p1 = W_CacheLumpName ("PFUB2", 50);
    p2 = W_CacheLumpName ("PFUB1", 50);
    V_MarkRect (0, 0, 320, 200);
    scrolled = 320 - (finalecount-230)/2;
    if (scrolled > 320)
 scrolled = 320;
    if (scrolled < 0)
 scrolled = 0;
    for ( x=0 ; x<320 ; x++)
    {
 if (x+scrolled < 320)
     F_DrawPatchCol (x, p1, x+scrolled);
 else
     F_DrawPatchCol (x, p2, x+scrolled - 320);
    }
    if (finalecount < 1130)
 return;
    if (finalecount < 1180)
    {
 V_DrawPatch ((320 -13*8)/2,
       (200 -8*8)/2,0, W_CacheLumpName ("END0",101));
 laststage = 0;
 return;
    }
    stage = (finalecount-1180) / 5;
    if (stage > 6)
 stage = 6;
    if (stage > laststage)
    {
 S_StartSound (((void *)0), sfx_pistol);
 laststage = stage;
    }
    sprintf (name,"END%i",stage);
    V_DrawPatch ((320 -13*8)/2, (200 -8*8)/2,0, W_CacheLumpName (name,101));
}
void F_Drawer (void)
{
    if (finalestage == 2)
    {
 F_CastDrawer ();
 return;
    }
    if (!finalestage)
 F_TextWrite ();
    else
    {
 switch (gameepisode)
 {
   case 1:
     if ( gamemode == retail )
       V_DrawPatch (0,0,0,
    W_CacheLumpName("CREDIT",101));
     else
       V_DrawPatch (0,0,0,
    W_CacheLumpName("HELP2",101));
     break;
   case 2:
     V_DrawPatch(0,0,0,
   W_CacheLumpName("VICTORY2",101));
     break;
   case 3:
     F_BunnyScroll ();
     break;
   case 4:
     V_DrawPatch (0,0,0,
    W_CacheLumpName("ENDPIC",101));
     break;
 }
    }
}
static const char rcsid[] = "$Id: f_wipe.c,v 1.2 1997/02/03 22:45:09 b1 Exp $";
int M_Random (void);
int P_Random (void);
void M_ClearRandom (void);
static boolean go = 0;
static byte* wipe_scr_start;
static byte* wipe_scr_end;
static byte* wipe_scr;
void
wipe_shittyColMajorXform
( short* array,
  int width,
  int height )
{
    int x;
    int y;
    short* dest;
    dest = (short*) Z_Malloc(width*height*2, 1, 0);
    for(y=0;y<height;y++)
 for(x=0;x<width;x++)
     dest[x*height+y] = array[y*width+x];
    memcpy(array, dest, width*height*2);
    Z_Free(dest);
}
int
wipe_initColorXForm
( int width,
  int height,
  int ticks )
{
    memcpy(wipe_scr, wipe_scr_start, width*height);
    return 0;
}
int
wipe_doColorXForm
( int width,
  int height,
  int ticks )
{
    boolean changed;
    byte* w;
    byte* e;
    int newval;
    changed = false;
    w = wipe_scr;
    e = wipe_scr_end;
    while (w!=wipe_scr+width*height)
    {
 if (*w != *e)
 {
     if (*w > *e)
     {
  newval = *w - ticks;
  if (newval < *e)
      *w = *e;
  else
      *w = newval;
  changed = true;
     }
     else if (*w < *e)
     {
  newval = *w + ticks;
  if (newval > *e)
      *w = *e;
  else
      *w = newval;
  changed = true;
     }
 }
 w++;
 e++;
    }
    return !changed;
}
int
wipe_exitColorXForm
( int width,
  int height,
  int ticks )
{
    return 0;
}
static int* y;
int
wipe_initMelt
( int width,
  int height,
  int ticks )
{
    int i, r;
    memcpy(wipe_scr, wipe_scr_start, width*height);
    wipe_shittyColMajorXform((short*)wipe_scr_start, width/2, height);
    wipe_shittyColMajorXform((short*)wipe_scr_end, width/2, height);
    y = (int *) Z_Malloc(width*sizeof(int), 1, 0);
    y[0] = -(M_Random()%16);
    for (i=1;i<width;i++)
    {
 r = (M_Random()%3) - 1;
 y[i] = y[i-1] + r;
 if (y[i] > 0) y[i] = 0;
 else if (y[i] == -16) y[i] = -15;
    }
    return 0;
}
int
wipe_doMelt
( int width,
  int height,
  int ticks )
{
    int i;
    int j;
    int dy;
    int idx;
    short* s;
    short* d;
    boolean done = true;
    width/=2;
    while (ticks--)
    {
 for (i=0;i<width;i++)
 {
     if (y[i]<0)
     {
  y[i]++; done = false;
     }
     else if (y[i] < height)
     {
  dy = (y[i] < 16) ? y[i]+1 : 8;
  if (y[i]+dy >= height) dy = height - y[i];
  s = &((short *)wipe_scr_end)[i*height+y[i]];
  d = &((short *)wipe_scr)[y[i]*width+i];
  idx = 0;
  for (j=dy;j;j--)
  {
      d[idx] = *(s++);
      idx += width;
  }
  y[i] += dy;
  s = &((short *)wipe_scr_start)[i*height];
  d = &((short *)wipe_scr)[y[i]*width+i];
  idx = 0;
  for (j=height-y[i];j;j--)
  {
      d[idx] = *(s++);
      idx += width;
  }
  done = false;
     }
 }
    }
    return done;
}
int
wipe_exitMelt
( int width,
  int height,
  int ticks )
{
    Z_Free(y);
    return 0;
}
int
wipe_StartScreen
( int x,
  int y,
  int width,
  int height )
{
    wipe_scr_start = screens[2];
    I_ReadScreen(wipe_scr_start);
    return 0;
}
int
wipe_EndScreen
( int x,
  int y,
  int width,
  int height )
{
    wipe_scr_end = screens[3];
    I_ReadScreen(wipe_scr_end);
    V_DrawBlock(x, y, 0, width, height, wipe_scr_start);
    return 0;
}
int
wipe_ScreenWipe
( int wipeno,
  int x,
  int y,
  int width,
  int height,
  int ticks )
{
    int rc;
    static int (*wipes[])(int, int, int) =
    {
 wipe_initColorXForm, wipe_doColorXForm, wipe_exitColorXForm,
 wipe_initMelt, wipe_doMelt, wipe_exitMelt
    };
    void V_MarkRect(int, int, int, int);
    if (!go)
    {
 go = 1;
 wipe_scr = screens[0];
 (*wipes[wipeno*3])(width, height, ticks);
    }
    V_MarkRect(0, 0, width, height);
    rc = (*wipes[wipeno*3+1])(width, height, ticks);
    if (rc)
    {
 go = 0;
 (*wipes[wipeno*3+2])(width, height, ticks);
    }
    return !go;
}
