int G_CmdChecksum (ticcmd_t* cmd)
{
    int i;
    int sum = 0;
    for (i=0 ; i< sizeof(*cmd)/4 - 1 ; i++)
 sum += ((int *)cmd)[i];
    return sum;
}
void G_BuildTiccmd (ticcmd_t* cmd)
{
    int i;
    boolean strafe;
    boolean bstrafe;
    int speed;
    int tspeed;
    int forward;
    int side;
    ticcmd_t* base;
    base = I_BaseTiccmd ();
    memcpy (cmd,base,sizeof(*cmd));
    cmd->consistancy =
 consistancy[consoleplayer][maketic%12];
    strafe = gamekeydown[key_strafe] || mousebuttons[mousebstrafe]
 || joybuttons[joybstrafe];
    speed = gamekeydown[key_speed] || joybuttons[joybspeed];
    forward = side = 0;
    if (joyxmove < 0
 || joyxmove > 0
 || gamekeydown[key_right]
 || gamekeydown[key_left])
 turnheld += ticdup;
    else
 turnheld = 0;
    if (turnheld < 6)
 tspeed = 2;
    else
 tspeed = speed;
    if (strafe)
    {
 if (gamekeydown[key_right])
 {
     side += sidemove[speed];
 }
 if (gamekeydown[key_left])
 {
     side -= sidemove[speed];
 }
 if (joyxmove > 0)
     side += sidemove[speed];
 if (joyxmove < 0)
     side -= sidemove[speed];
    }
    else
    {
 if (gamekeydown[key_right])
     cmd->angleturn -= angleturn[tspeed];
 if (gamekeydown[key_left])
     cmd->angleturn += angleturn[tspeed];
 if (joyxmove > 0)
     cmd->angleturn -= angleturn[tspeed];
 if (joyxmove < 0)
     cmd->angleturn += angleturn[tspeed];
    }
    if (gamekeydown[key_up])
    {
 forward += forwardmove[speed];
    }
    if (gamekeydown[key_down])
    {
 forward -= forwardmove[speed];
    }
    if (joyymove < 0)
 forward += forwardmove[speed];
    if (joyymove > 0)
 forward -= forwardmove[speed];
    if (gamekeydown[key_straferight])
 side += sidemove[speed];
    if (gamekeydown[key_strafeleft])
 side -= sidemove[speed];
    cmd->chatchar = HU_dequeueChatChar();
    if (gamekeydown[key_fire] || mousebuttons[mousebfire]
 || joybuttons[joybfire])
 cmd->buttons |= BT_ATTACK;
    if (gamekeydown[key_use] || joybuttons[joybuse] )
    {
 cmd->buttons |= BT_USE;
 dclicks = 0;
    }
    for (i=0 ; i<NUMWEAPONS-1 ; i++)
 if (gamekeydown['1'+i])
 {
     cmd->buttons |= BT_CHANGE;
     cmd->buttons |= i<<BT_WEAPONSHIFT;
     break;
 }
    if (mousebuttons[mousebforward])
 forward += forwardmove[speed];
    if (mousebuttons[mousebforward] != dclickstate && dclicktime > 1 )
    {
 dclickstate = mousebuttons[mousebforward];
 if (dclickstate)
     dclicks++;
 if (dclicks == 2)
 {
     cmd->buttons |= BT_USE;
     dclicks = 0;
 }
 else
     dclicktime = 0;
    }
    else
    {
 dclicktime += ticdup;
 if (dclicktime > 20)
 {
     dclicks = 0;
     dclickstate = 0;
 }
    }
    bstrafe =
 mousebuttons[mousebstrafe]
 || joybuttons[joybstrafe];
    if (bstrafe != dclickstate2 && dclicktime2 > 1 )
    {
 dclickstate2 = bstrafe;
 if (dclickstate2)
     dclicks2++;
 if (dclicks2 == 2)
 {
     cmd->buttons |= BT_USE;
     dclicks2 = 0;
 }
 else
     dclicktime2 = 0;
    }
    else
    {
 dclicktime2 += ticdup;
 if (dclicktime2 > 20)
 {
     dclicks2 = 0;
     dclickstate2 = 0;
 }
    }
    forward += mousey;
    if (strafe)
 side += mousex*2;
    else
 cmd->angleturn -= mousex*0x8;
    mousex = mousey = 0;
    if (forward > (forwardmove[1]))
 forward = (forwardmove[1]);
    else if (forward < -(forwardmove[1]))
 forward = -(forwardmove[1]);
    if (side > (forwardmove[1]))
 side = (forwardmove[1]);
    else if (side < -(forwardmove[1]))
 side = -(forwardmove[1]);
    cmd->forwardmove += forward;
    cmd->sidemove += side;
    if (sendpause)
    {
 sendpause = false;
 cmd->buttons = BT_SPECIAL | BTS_PAUSE;
    }
    if (sendsave)
    {
 sendsave = false;
 cmd->buttons = BT_SPECIAL | BTS_SAVEGAME | (savegameslot<<BTS_SAVESHIFT);
    }
}
extern gamestate_t wipegamestate;
void G_DoLoadLevel (void)
{
    int i;
    skyflatnum = R_FlatNumForName ( "F_SKY1" );
    if ( (gamemode == commercial)
  || ( gamemode == pack_tnt )
  || ( gamemode == pack_plut ) )
    {
 skytexture = R_TextureNumForName ("SKY3");
 if (gamemap < 12)
     skytexture = R_TextureNumForName ("SKY1");
 else
     if (gamemap < 21)
  skytexture = R_TextureNumForName ("SKY2");
    }
    levelstarttic = gametic;
    if (wipegamestate == GS_LEVEL)
 wipegamestate = -1;
    gamestate = GS_LEVEL;
    for (i=0 ; i<4 ; i++)
    {
 if (playeringame[i] && players[i].playerstate == PST_DEAD)
     players[i].playerstate = PST_REBORN;
 memset (players[i].frags,0,sizeof(players[i].frags));
    }
    P_SetupLevel (gameepisode, gamemap, 0, gameskill);
    displayplayer = consoleplayer;
    starttime = I_GetTime ();
    gameaction = ga_nothing;
    Z_CheckHeap ();
    memset (gamekeydown, 0, sizeof(gamekeydown));
    joyxmove = joyymove = 0;
    mousex = mousey = 0;
    sendpause = sendsave = paused = false;
    memset (mousebuttons, 0, sizeof(mousebuttons));
    memset (joybuttons, 0, sizeof(joybuttons));
}
boolean G_Responder (event_t* ev)
{
    if (gamestate == GS_LEVEL && ev->type == ev_keydown
 && ev->data1 == (0x80+0x58) && (singledemo || !deathmatch) )
    {
 do
 {
     displayplayer++;
     if (displayplayer == 4)
  displayplayer = 0;
 } while (!playeringame[displayplayer] && displayplayer != consoleplayer);
 return true;
    }
    if (gameaction == ga_nothing && !singledemo &&
 (demoplayback || gamestate == GS_DEMOSCREEN)
 )
    {
 if (ev->type == ev_keydown ||
     (ev->type == ev_mouse && ev->data1) ||
     (ev->type == ev_joystick && ev->data1) )
 {
     M_StartControlPanel ();
     return true;
 }
 return false;
    }
    if (gamestate == GS_LEVEL)
    {
 if (HU_Responder (ev))
     return true;
 if (ST_Responder (ev))
     return true;
 if (AM_Responder (ev))
     return true;
    }
    if (gamestate == GS_FINALE)
    {
 if (F_Responder (ev))
     return true;
    }
    switch (ev->type)
    {
      case ev_keydown:
 if (ev->data1 == 0xff)
 {
     sendpause = true;
     return true;
 }
 if (ev->data1 <256)
     gamekeydown[ev->data1] = true;
 return true;
      case ev_keyup:
 if (ev->data1 <256)
     gamekeydown[ev->data1] = false;
 return false;
      case ev_mouse:
 mousebuttons[0] = ev->data1 & 1;
 mousebuttons[1] = ev->data1 & 2;
 mousebuttons[2] = ev->data1 & 4;
 mousex = ev->data2*(mouseSensitivity+5)/10;
 mousey = ev->data3*(mouseSensitivity+5)/10;
 return true;
      case ev_joystick:
 joybuttons[0] = ev->data1 & 1;
 joybuttons[1] = ev->data1 & 2;
 joybuttons[2] = ev->data1 & 4;
 joybuttons[3] = ev->data1 & 8;
 joyxmove = ev->data2;
 joyymove = ev->data3;
 return true;
      default:
 break;
    }
    return false;
}
void G_Ticker (void)
{
    int i;
    int buf;
    ticcmd_t* cmd;
    for (i=0 ; i<4 ; i++)
 if (playeringame[i] && players[i].playerstate == PST_REBORN)
     G_DoReborn (i);
    while (gameaction != ga_nothing)
    {
 switch (gameaction)
 {
   case ga_loadlevel:
     G_DoLoadLevel ();
     break;
   case ga_newgame:
     G_DoNewGame ();
     break;
   case ga_loadgame:
     G_DoLoadGame ();
     break;
   case ga_savegame:
     G_DoSaveGame ();
     break;
   case ga_playdemo:
     G_DoPlayDemo ();
     break;
   case ga_completed:
     G_DoCompleted ();
     break;
   case ga_victory:
     F_StartFinale ();
     break;
   case ga_worlddone:
     G_DoWorldDone ();
     break;
   case ga_screenshot:
     M_ScreenShot ();
     gameaction = ga_nothing;
     break;
   case ga_nothing:
     break;
 }
    }
    buf = (gametic/ticdup)%12;
    for (i=0 ; i<4 ; i++)
    {
 if (playeringame[i])
 {
     cmd = &players[i].cmd;
     memcpy (cmd, &netcmds[i][buf], sizeof(ticcmd_t));
     if (demoplayback)
  G_ReadDemoTiccmd (cmd);
     if (demorecording)
  G_WriteDemoTiccmd (cmd);
     if (cmd->forwardmove > 0x32
  && !(gametic&31) && ((gametic>>5)&3) == i )
     {
  static char turbomessage[80];
  extern char *player_names[4];
  sprintf (turbomessage, "%s is turbo!",player_names[i]);
  players[consoleplayer].message = turbomessage;
     }
     if (netgame && !netdemo && !(gametic%ticdup) )
     {
  if (gametic > 12
      && consistancy[i][buf] != cmd->consistancy)
  {
      I_Error ("consistency failure (%i should be %i)",
        cmd->consistancy, consistancy[i][buf]);
  }
  if (players[i].mo)
      consistancy[i][buf] = players[i].mo->x;
  else
      consistancy[i][buf] = rndindex;
     }
 }
    }
    for (i=0 ; i<4 ; i++)
    {
 if (playeringame[i])
 {
     if (players[i].cmd.buttons & BT_SPECIAL)
     {
  switch (players[i].cmd.buttons & BT_SPECIALMASK)
  {
    case BTS_PAUSE:
      paused ^= 1;
      if (paused)
   S_PauseSound ();
      else
   S_ResumeSound ();
      break;
    case BTS_SAVEGAME:
      if (!savedescription[0])
   strcpy (savedescription, "NET GAME");
      savegameslot =
   (players[i].cmd.buttons & BTS_SAVEMASK)>>BTS_SAVESHIFT;
      gameaction = ga_savegame;
      break;
  }
     }
 }
    }
    switch (gamestate)
    {
      case GS_LEVEL:
 P_Ticker ();
 ST_Ticker ();
 AM_Ticker ();
 HU_Ticker ();
 break;
      case GS_INTERMISSION:
 WI_Ticker ();
 break;
      case GS_FINALE:
 F_Ticker ();
 break;
      case GS_DEMOSCREEN:
 D_PageTicker ();
 break;
    }
}
void G_InitPlayer (int player)
{
    player_t* p;
    p = &players[player];
    G_PlayerReborn (player);
}
void G_PlayerFinishLevel (int player)
{
    player_t* p;
    p = &players[player];
    memset (p->powers, 0, sizeof (p->powers));
    memset (p->cards, 0, sizeof (p->cards));
    p->mo->flags &= ~MF_SHADOW;
    p->extralight = 0;
    p->fixedcolormap = 0;
    p->damagecount = 0;
    p->bonuscount = 0;
}
void G_PlayerReborn (int player)
{
    player_t* p;
    int i;
    int frags[4];
    int killcount;
    int itemcount;
    int secretcount;
    memcpy (frags,players[player].frags,sizeof(frags));
    killcount = players[player].killcount;
    itemcount = players[player].itemcount;
    secretcount = players[player].secretcount;
    p = &players[player];
    memset (p, 0, sizeof(*p));
    memcpy (players[player].frags, frags, sizeof(players[player].frags));
    players[player].killcount = killcount;
    players[player].itemcount = itemcount;
    players[player].secretcount = secretcount;
    p->usedown = p->attackdown = true;
    p->playerstate = PST_LIVE;
    p->health = 100;
    p->readyweapon = p->pendingweapon = wp_pistol;
    p->weaponowned[wp_fist] = true;
    p->weaponowned[wp_pistol] = true;
    p->ammo[am_clip] = 50;
    for (i=0 ; i<NUMAMMO ; i++)
 p->maxammo[i] = maxammo[i];
}
void P_SpawnPlayer (mapthing_t* mthing);
boolean
G_CheckSpot
( int playernum,
  mapthing_t* mthing )
{
    fixed_t x;
    fixed_t y;
    subsector_t* ss;
    unsigned an;
    mobj_t* mo;
    int i;
    if (!players[playernum].mo)
    {
 for (i=0 ; i<playernum ; i++)
     if (players[i].mo->x == mthing->x << 16
  && players[i].mo->y == mthing->y << 16)
  return false;
 return true;
    }
    x = mthing->x << 16;
    y = mthing->y << 16;
    if (!P_CheckPosition (players[playernum].mo, x, y) )
 return false;
    if (bodyqueslot >= 32)
 P_RemoveMobj (bodyque[bodyqueslot%32]);
    bodyque[bodyqueslot%32] = players[playernum].mo;
    bodyqueslot++;
    ss = R_PointInSubsector (x,y);
    an = ( 0x20000000 * (mthing->angle/45) ) >> 19;
    mo = P_SpawnMobj (x+20*finecosine[an], y+20*finesine[an]
        , ss->sector->floorheight
        , MT_TFOG);
    if (players[consoleplayer].viewz != 1)
 S_StartSound (mo, sfx_telept);
    return true;
}
void G_DeathMatchSpawnPlayer (int playernum)
{
    int i,j;
    int selections;
    selections = deathmatch_p - deathmatchstarts;
    if (selections < 4)
 I_Error ("Only %i deathmatch spots, 4 required", selections);
    for (j=0 ; j<20 ; j++)
    {
 i = P_Random() % selections;
 if (G_CheckSpot (playernum, &deathmatchstarts[i]) )
 {
     deathmatchstarts[i].type = playernum+1;
     P_SpawnPlayer (&deathmatchstarts[i]);
     return;
 }
    }
    P_SpawnPlayer (&playerstarts[playernum]);
}
void G_DoReborn (int playernum)
{
    int i;
    if (!netgame)
    {
 gameaction = ga_loadlevel;
    }
    else
    {
 players[playernum].mo->player = ((void *)0);
 if (deathmatch)
 {
     G_DeathMatchSpawnPlayer (playernum);
     return;
 }
 if (G_CheckSpot (playernum, &playerstarts[playernum]) )
 {
     P_SpawnPlayer (&playerstarts[playernum]);
     return;
 }
 for (i=0 ; i<4 ; i++)
 {
     if (G_CheckSpot (playernum, &playerstarts[i]) )
     {
  playerstarts[i].type = playernum+1;
  P_SpawnPlayer (&playerstarts[i]);
  playerstarts[i].type = i+1;
  return;
     }
 }
 P_SpawnPlayer (&playerstarts[playernum]);
    }
}
