extern int skytexture;
void
G_InitNew
( skill_t skill,
  int episode,
  int map )
{
    int i;
    if (paused)
    {
 paused = false;
 S_ResumeSound ();
    }
    if (skill > sk_nightmare)
 skill = sk_nightmare;
    if (episode < 1)
      episode = 1;
    if ( gamemode == retail )
    {
      if (episode > 4)
 episode = 4;
    }
    else if ( gamemode == shareware )
    {
      if (episode > 1)
    episode = 1;
    }
    else
    {
      if (episode > 3)
 episode = 3;
    }
    if (map < 1)
 map = 1;
    if ( (map > 9)
  && ( gamemode != commercial) )
      map = 9;
    M_ClearRandom ();
    if (skill == sk_nightmare || respawnparm )
 respawnmonsters = true;
    else
 respawnmonsters = false;
    if (fastparm || (skill == sk_nightmare && gameskill != sk_nightmare) )
    {
 for (i=S_SARG_RUN1 ; i<=S_SARG_PAIN2 ; i++)
     states[i].tics >>= 1;
 mobjinfo[MT_BRUISERSHOT].speed = 20*(1<<16);
 mobjinfo[MT_HEADSHOT].speed = 20*(1<<16);
 mobjinfo[MT_TROOPSHOT].speed = 20*(1<<16);
    }
    else if (skill != sk_nightmare && gameskill == sk_nightmare)
    {
 for (i=S_SARG_RUN1 ; i<=S_SARG_PAIN2 ; i++)
     states[i].tics <<= 1;
 mobjinfo[MT_BRUISERSHOT].speed = 15*(1<<16);
 mobjinfo[MT_HEADSHOT].speed = 10*(1<<16);
 mobjinfo[MT_TROOPSHOT].speed = 10*(1<<16);
    }
    for (i=0 ; i<4 ; i++)
 players[i].playerstate = PST_REBORN;
    usergame = true;
    paused = false;
    demoplayback = false;
    automapactive = false;
    viewactive = true;
    gameepisode = episode;
    gamemap = map;
    gameskill = skill;
    viewactive = true;
    if ( gamemode == commercial)
    {
 skytexture = R_TextureNumForName ("SKY3");
 if (gamemap < 12)
     skytexture = R_TextureNumForName ("SKY1");
 else
     if (gamemap < 21)
  skytexture = R_TextureNumForName ("SKY2");
    }
    else
 switch (episode)
 {
   case 1:
     skytexture = R_TextureNumForName ("SKY1");
     break;
   case 2:
     skytexture = R_TextureNumForName ("SKY2");
     break;
   case 3:
     skytexture = R_TextureNumForName ("SKY3");
     break;
   case 4:
     skytexture = R_TextureNumForName ("SKY4");
     break;
 }
    G_DoLoadLevel ();
}
void G_ReadDemoTiccmd (ticcmd_t* cmd)
{
    if (*demo_p == 0x80)
    {
 G_CheckDemoStatus ();
 return;
    }
    cmd->forwardmove = ((signed char)*demo_p++);
    cmd->sidemove = ((signed char)*demo_p++);
    cmd->angleturn = ((unsigned char)*demo_p++)<<8;
    cmd->buttons = (unsigned char)*demo_p++;
}
void G_WriteDemoTiccmd (ticcmd_t* cmd)
{
    if (gamekeydown['q'])
 G_CheckDemoStatus ();
    *demo_p++ = cmd->forwardmove;
    *demo_p++ = cmd->sidemove;
    *demo_p++ = (cmd->angleturn+128)>>8;
    *demo_p++ = cmd->buttons;
    demo_p -= 4;
    if (demo_p > demoend - 16)
    {
 G_CheckDemoStatus ();
 return;
    }
    G_ReadDemoTiccmd (cmd);
}
void G_RecordDemo (char* name)
{
    int i;
    int maxsize;
    usergame = false;
    strcpy (demoname, name);
    strcat (demoname, ".lmp");
    maxsize = 0x20000;
    i = M_CheckParm ("-maxdemo");
    if (i && i<myargc-1)
 maxsize = atoi(myargv[i+1])*1024;
    demobuffer = Z_Malloc (maxsize,1,((void *)0));
    demoend = demobuffer + maxsize;
    demorecording = true;
}
void G_BeginRecording (void)
{
    int i;
    demo_p = demobuffer;
    *demo_p++ = VERSION;
    *demo_p++ = gameskill;
    *demo_p++ = gameepisode;
    *demo_p++ = gamemap;
    *demo_p++ = deathmatch;
    *demo_p++ = respawnparm;
    *demo_p++ = fastparm;
    *demo_p++ = nomonsters;
    *demo_p++ = consoleplayer;
    for (i=0 ; i<4 ; i++)
 *demo_p++ = playeringame[i];
}
char* defdemoname;
void G_DeferedPlayDemo (char* name)
{
    defdemoname = name;
    gameaction = ga_playdemo;
}
void G_DoPlayDemo (void)
{
    skill_t skill;
    int i, episode, map;
    gameaction = ga_nothing;
    demobuffer = demo_p = W_CacheLumpName (defdemoname, 1);
    if ( *demo_p++ != VERSION)
    {
      fprintf( stderr, "Demo is from a different game version!\n");
      gameaction = ga_nothing;
      return;
    }
    skill = *demo_p++;
    episode = *demo_p++;
    map = *demo_p++;
    deathmatch = *demo_p++;
    respawnparm = *demo_p++;
    fastparm = *demo_p++;
    nomonsters = *demo_p++;
    consoleplayer = *demo_p++;
    for (i=0 ; i<4 ; i++)
 playeringame[i] = *demo_p++;
    if (playeringame[1])
    {
 netgame = true;
 netdemo = true;
    }
    precache = false;
    G_InitNew (skill, episode, map);
    precache = true;
    usergame = false;
    demoplayback = true;
}
void G_TimeDemo (char* name)
{
    nodrawers = M_CheckParm ("-nodraw");
    noblit = M_CheckParm ("-noblit");
    timingdemo = true;
    singletics = true;
    defdemoname = name;
    gameaction = ga_playdemo;
}
boolean G_CheckDemoStatus (void)
{
    int endtime;
    if (timingdemo)
    {
 endtime = I_GetTime ();
 I_Error ("timed %i gametics in %i realtics",gametic
   , endtime-starttime);
    }
    if (demoplayback)
    {
 if (singledemo)
     I_Quit ();
 { if (( (memblock_t *)( (byte *)(demobuffer) - sizeof(memblock_t)))->id!=0x1d4a11) I_Error("Z_CT at ""doom_amalg.c"":%i",6284); Z_ChangeTag2(demobuffer,101); };;
 demoplayback = false;
 netdemo = false;
 netgame = false;
 deathmatch = false;
 playeringame[1] = playeringame[2] = playeringame[3] = 0;
 respawnparm = false;
 fastparm = false;
 nomonsters = false;
 consoleplayer = 0;
 D_AdvanceDemo ();
 return true;
    }
    if (demorecording)
    {
 *demo_p++ = 0x80;
 M_WriteFile (demoname, demobuffer, demo_p - demobuffer);
 Z_Free (demobuffer);
 demorecording = false;
 I_Error ("Demo %s recorded",demoname);
    }
    return false;
}
static const char
rcsid[] = "$Id: hu_lib.c,v 1.3 1997/01/26 07:44:58 b1 Exp $";
typedef struct
{
    int x;
    int y;
    patch_t** f;
    int sc;
    char l[80 +1];
    int len;
    int needsupdate;
} hu_textline_t;
typedef struct
{
    hu_textline_t l[4];
    int h;
    int cl;
    boolean* on;
    boolean laston;
} hu_stext_t;
typedef struct
{
    hu_textline_t l;
    int lm;
    boolean* on;
    boolean laston;
} hu_itext_t;
void HUlib_init(void);
void HUlib_clearTextLine(hu_textline_t *t);
void HUlib_initTextLine(hu_textline_t *t, int x, int y, patch_t **f, int sc);
boolean HUlib_addCharToTextLine(hu_textline_t *t, char ch);
boolean HUlib_delCharFromTextLine(hu_textline_t *t);
void HUlib_drawTextLine(hu_textline_t *l, boolean drawcursor);
void HUlib_eraseTextLine(hu_textline_t *l);
void
HUlib_initSText
( hu_stext_t* s,
  int x,
  int y,
  int h,
  patch_t** font,
  int startchar,
  boolean* on );
void HUlib_addLineToSText(hu_stext_t* s);
void
HUlib_addMessageToSText
( hu_stext_t* s,
  char* prefix,
  char* msg );
void HUlib_drawSText(hu_stext_t* s);
void HUlib_eraseSText(hu_stext_t* s);
void
HUlib_initIText
( hu_itext_t* it,
  int x,
  int y,
  patch_t** font,
  int startchar,
  boolean* on );
void HUlib_delCharFromIText(hu_itext_t* it);
void HUlib_eraseLineFromIText(hu_itext_t* it);
void HUlib_resetIText(hu_itext_t* it);
void
HUlib_addPrefixToIText
( hu_itext_t* it,
  char* str );
boolean
HUlib_keyInIText
( hu_itext_t* it,
  unsigned char ch );
void HUlib_drawIText(hu_itext_t* it);
void HUlib_eraseIText(hu_itext_t* it);
extern boolean automapactive;
void HUlib_init(void)
{
}
void HUlib_clearTextLine(hu_textline_t* t)
{
    t->len = 0;
    t->l[0] = 0;
    t->needsupdate = true;
}
void
HUlib_initTextLine
( hu_textline_t* t,
  int x,
  int y,
  patch_t** f,
  int sc )
{
    t->x = x;
    t->y = y;
    t->f = f;
    t->sc = sc;
    HUlib_clearTextLine(t);
}
boolean
HUlib_addCharToTextLine
( hu_textline_t* t,
  char ch )
{
    if (t->len == 80)
 return false;
    else
    {
 t->l[t->len++] = ch;
 t->l[t->len] = 0;
 t->needsupdate = 4;
 return true;
    }
}
boolean HUlib_delCharFromTextLine(hu_textline_t* t)
{
    if (!t->len) return false;
    else
    {
 t->l[--t->len] = 0;
 t->needsupdate = 4;
 return true;
    }
}
void
HUlib_drawTextLine
( hu_textline_t* l,
  boolean drawcursor )
{
    int i;
    int w;
    int x;
    unsigned char c;
    x = l->x;
    for (i=0;i<l->len;i++)
    {
 c = toupper(l->l[i]);
 if (c != ' '
     && c >= l->sc
     && c <= '_')
 {
     w = (l->f[c - l->sc]->width);
     if (x+w > 320)
  break;
     V_DrawPatchDirect(x, l->y, 0, l->f[c - l->sc]);
     x += w;
 }
 else
 {
     x += 4;
     if (x >= 320)
  break;
 }
    }
    if (drawcursor
 && x + (l->f['_' - l->sc]->width) <= 320)
    {
 V_DrawPatchDirect(x, l->y, 0, l->f['_' - l->sc]);
    }
}
void HUlib_eraseTextLine(hu_textline_t* l)
{
    int lh;
    int y;
    int yoffset;
    static boolean lastautomapactive = true;
    if (!automapactive &&
 viewwindowx && l->needsupdate)
    {
 lh = (l->f[0]->height) + 1;
 for (y=l->y,yoffset=y*320 ; y<l->y+lh ; y++,yoffset+=320)
 {
     if (y < viewwindowy || y >= viewwindowy + viewheight)
  R_VideoErase(yoffset, 320);
     else
     {
  R_VideoErase(yoffset, viewwindowx);
  R_VideoErase(yoffset + viewwindowx + viewwidth, viewwindowx);
     }
 }
    }
    lastautomapactive = automapactive;
    if (l->needsupdate) l->needsupdate--;
}
void
HUlib_initSText
( hu_stext_t* s,
  int x,
  int y,
  int h,
  patch_t** font,
  int startchar,
  boolean* on )
{
    int i;
    s->h = h;
    s->on = on;
    s->laston = true;
    s->cl = 0;
    for (i=0;i<h;i++)
 HUlib_initTextLine(&s->l[i],
      x, y - i*((font[0]->height)+1),
      font, startchar);
}
void HUlib_addLineToSText(hu_stext_t* s)
{
    int i;
    if (++s->cl == s->h)
 s->cl = 0;
    HUlib_clearTextLine(&s->l[s->cl]);
    for (i=0 ; i<s->h ; i++)
 s->l[i].needsupdate = 4;
}
void
HUlib_addMessageToSText
( hu_stext_t* s,
  char* prefix,
  char* msg )
{
    HUlib_addLineToSText(s);
    if (prefix)
 while (*prefix)
     HUlib_addCharToTextLine(&s->l[s->cl], *(prefix++));
    while (*msg)
 HUlib_addCharToTextLine(&s->l[s->cl], *(msg++));
}
void HUlib_drawSText(hu_stext_t* s)
{
    int i, idx;
    hu_textline_t *l;
    if (!*s->on)
 return;
    for (i=0 ; i<s->h ; i++)
    {
 idx = s->cl - i;
 if (idx < 0)
     idx += s->h;
 l = &s->l[idx];
 HUlib_drawTextLine(l, false);
    }
}
void HUlib_eraseSText(hu_stext_t* s)
{
    int i;
    for (i=0 ; i<s->h ; i++)
    {
 if (s->laston && !*s->on)
     s->l[i].needsupdate = 4;
 HUlib_eraseTextLine(&s->l[i]);
    }
    s->laston = *s->on;
}
void
HUlib_initIText
( hu_itext_t* it,
  int x,
  int y,
  patch_t** font,
  int startchar,
  boolean* on )
{
    it->lm = 0;
    it->on = on;
    it->laston = true;
    HUlib_initTextLine(&it->l, x, y, font, startchar);
}
void HUlib_delCharFromIText(hu_itext_t* it)
{
    if (it->l.len != it->lm)
 HUlib_delCharFromTextLine(&it->l);
}
void HUlib_eraseLineFromIText(hu_itext_t* it)
{
    while (it->lm != it->l.len)
 HUlib_delCharFromTextLine(&it->l);
}
void HUlib_resetIText(hu_itext_t* it)
{
    it->lm = 0;
    HUlib_clearTextLine(&it->l);
}
void
HUlib_addPrefixToIText
( hu_itext_t* it,
  char* str )
{
    while (*str)
 HUlib_addCharToTextLine(&it->l, *(str++));
    it->lm = it->l.len;
}
boolean
HUlib_keyInIText
( hu_itext_t* it,
  unsigned char ch )
{
    if (ch >= ' ' && ch <= '_')
   HUlib_addCharToTextLine(&it->l, (char) ch);
    else
 if (ch == 127)
     HUlib_delCharFromIText(it);
 else
     if (ch != 13)
  return false;
    return true;
}
void HUlib_drawIText(hu_itext_t* it)
{
    hu_textline_t *l = &it->l;
    if (!*it->on)
 return;
    HUlib_drawTextLine(l, true);
}
void HUlib_eraseIText(hu_itext_t* it)
{
    if (it->laston && !*it->on)
 it->l.needsupdate = 4;
    HUlib_eraseTextLine(&it->l);
    it->laston = *it->on;
}
