void HU_Init(void)
{
    int i;
    int j;
    char buffer[9];
    if (french)
 shiftxform = french_shiftxform;
    else
 shiftxform = english_shiftxform;
    j = '!';
    for (i=0;i<('_' - '!' + 1);i++)
    {
 sprintf(buffer, "STCFN%.3d", j++);
 hu_font[i] = (patch_t *) W_CacheLumpName(buffer, 1);
    }
}
void HU_Stop(void)
{
    headsupactive = false;
}
void HU_Start(void)
{
    int i;
    char* s;
    if (headsupactive)
 HU_Stop();
    plr = &players[consoleplayer];
    message_on = false;
    message_dontfuckwithme = false;
    message_nottobefuckedwith = false;
    chat_on = false;
    HUlib_initSText(&w_message,
      0, 0, 1,
      hu_font,
      '!', &message_on);
    HUlib_initTextLine(&w_title,
         0, (167 - (hu_font[0]->height)),
         hu_font,
         '!');
    switch ( gamemode )
    {
      case shareware:
      case registered:
      case retail:
 s = (mapnames[(gameepisode-1)*9+gamemap-1]);
 break;
      case commercial:
      default:
  s = (mapnames2[gamemap-1]);
  break;
    }
    while (*s)
 HUlib_addCharToTextLine(&w_title, *(s++));
    HUlib_initIText(&w_chat,
      0, (0 + 1*((hu_font[0]->height) +1)),
      hu_font,
      '!', &chat_on);
    for (i=0 ; i<4 ; i++)
 HUlib_initIText(&w_inputbuffer[i], 0, 0, 0, 0, &always_off);
    headsupactive = true;
}
void HU_Drawer(void)
{
    HUlib_drawSText(&w_message);
    HUlib_drawIText(&w_chat);
    if (automapactive)
 HUlib_drawTextLine(&w_title, false);
}
void HU_Erase(void)
{
    HUlib_eraseSText(&w_message);
    HUlib_eraseIText(&w_chat);
    HUlib_eraseTextLine(&w_title);
}
void HU_Ticker(void)
{
    int i, rc;
    char c;
    if (message_counter && !--message_counter)
    {
 message_on = false;
 message_nottobefuckedwith = false;
    }
    if (showMessages || message_dontfuckwithme)
    {
 if ((plr->message && !message_nottobefuckedwith)
     || (plr->message && message_dontfuckwithme))
 {
     HUlib_addMessageToSText(&w_message, 0, plr->message);
     plr->message = 0;
     message_on = true;
     message_counter = (4*35);
     message_nottobefuckedwith = message_dontfuckwithme;
     message_dontfuckwithme = 0;
 }
    }
    if (netgame)
    {
 for (i=0 ; i<4; i++)
 {
     if (!playeringame[i])
  continue;
     if (i != consoleplayer
  && (c = players[i].cmd.chatchar))
     {
  if (c <= 5)
      chat_dest[i] = c;
  else
  {
      if (c >= 'a' && c <= 'z')
   c = (char) shiftxform[(unsigned char) c];
      rc = HUlib_keyInIText(&w_inputbuffer[i], c);
      if (rc && c == 13)
      {
   if (w_inputbuffer[i].l.len
       && (chat_dest[i] == consoleplayer+1
    || chat_dest[i] == 5))
   {
       HUlib_addMessageToSText(&w_message,
          player_names[i],
          w_inputbuffer[i].l.l);
       message_nottobefuckedwith = true;
       message_on = true;
       message_counter = (4*35);
       if ( gamemode == commercial )
         S_StartSound(0, sfx_radio);
       else
         S_StartSound(0, sfx_tink);
   }
   HUlib_resetIText(&w_inputbuffer[i]);
      }
  }
  players[i].cmd.chatchar = 0;
     }
 }
    }
}
static char chatchars[128];
static int head = 0;
static int tail = 0;
void HU_queueChatChar(char c)
{
    if (((head + 1) & (128 -1)) == tail)
    {
 plr->message = "[Message unsent]";
    }
    else
    {
 chatchars[head] = c;
 head = (head + 1) & (128 -1);
    }
}
char HU_dequeueChatChar(void)
{
    char c;
    if (head != tail)
    {
 c = chatchars[tail];
 tail = (tail + 1) & (128 -1);
    }
    else
    {
 c = 0;
    }
    return c;
}
boolean HU_Responder(event_t *ev)
{
    static char lastmessage[80 +1];
    char* macromessage;
    boolean eatkey = false;
    static boolean shiftdown = false;
    static boolean altdown = false;
    unsigned char c;
    int i;
    int numplayers;
    static char destination_keys[4] =
    {
 'g',
 'i',
 'b',
 'r'
    };
    static int num_nobrainers = 0;
    numplayers = 0;
    for (i=0 ; i<4 ; i++)
 numplayers += playeringame[i];
    if (ev->data1 == (0x80+0x36))
    {
 shiftdown = ev->type == ev_keydown;
 return false;
    }
    else if (ev->data1 == (0x80+0x38) || ev->data1 == (0x80+0x38))
    {
 altdown = ev->type == ev_keydown;
 return false;
    }
    if (ev->type != ev_keydown)
 return false;
    if (!chat_on)
    {
 if (ev->data1 == 13)
 {
     message_on = true;
     message_counter = (4*35);
     eatkey = true;
 }
 else if (netgame && ev->data1 == 't')
 {
     eatkey = chat_on = true;
     HUlib_resetIText(&w_chat);
     HU_queueChatChar(5);
 }
 else if (netgame && numplayers > 2)
 {
     for (i=0; i<4 ; i++)
     {
  if (ev->data1 == destination_keys[i])
  {
      if (playeringame[i] && i!=consoleplayer)
      {
   eatkey = chat_on = true;
   HUlib_resetIText(&w_chat);
   HU_queueChatChar(i+1);
   break;
      }
      else if (i == consoleplayer)
      {
   num_nobrainers++;
   if (num_nobrainers < 3)
       plr->message = "You mumble to yourself";
   else if (num_nobrainers < 6)
       plr->message = "Who's there?";
   else if (num_nobrainers < 9)
       plr->message = "You scare yourself";
   else if (num_nobrainers < 32)
       plr->message = "You start to rave";
   else
       plr->message = "You've lost it...";
      }
  }
     }
 }
    }
    else
    {
 c = ev->data1;
 if (altdown)
 {
     c = c - '0';
     if (c > 9)
  return false;
     macromessage = chat_macros[c];
     HU_queueChatChar(13);
     while (*macromessage)
  HU_queueChatChar(*macromessage++);
     HU_queueChatChar(13);
     chat_on = false;
     strcpy(lastmessage, chat_macros[c]);
     plr->message = lastmessage;
     eatkey = true;
 }
 else
 {
     if (french)
  c = ForeignTranslation(c);
     if (shiftdown || (c >= 'a' && c <= 'z'))
  c = shiftxform[c];
     eatkey = HUlib_keyInIText(&w_chat, c);
     if (eatkey)
     {
  HU_queueChatChar(c);
     }
     if (c == 13)
     {
  chat_on = false;
  if (w_chat.l.len)
  {
      strcpy(lastmessage, w_chat.l.l);
      plr->message = lastmessage;
  }
     }
     else if (c == 27)
  chat_on = false;
 }
    }
    return eatkey;
}
