int UDPsocket (void)
{
    int s;
    s = socket (2, SOCK_DGRAM, IPPROTO_UDP);
    if (s<0)
 I_Error ("can't create socket: %s",strerror((*__errno_location ())));
    return s;
}
void
BindToLocalPort
( int s,
  int port )
{
    int v;
    struct sockaddr_in address;
    memset (&address, 0, sizeof(address));
    address.sin_family = 2;
    address.sin_addr.s_addr = ((in_addr_t) 0x00000000);
    address.sin_port = port;
    v = bind (s, (void *)&address, sizeof(address));
    if (v == -1)
 I_Error ("BindToPort: bind: %s", strerror((*__errno_location ())));
}
void PacketSend (void)
{
    int c;
    doomdata_t sw;
    sw.checksum = ((unsigned long int)((((unsigned long int)(netbuffer->checksum) & 0x000000ffU) << 24) | (((unsigned long int)(netbuffer->checksum) & 0x0000ff00U) << 8) | (((unsigned long int)(netbuffer->checksum) & 0x00ff0000U) >> 8) | (((unsigned long int)(netbuffer->checksum) & 0xff000000U) >> 24)));
    sw.player = netbuffer->player;
    sw.retransmitfrom = netbuffer->retransmitfrom;
    sw.starttic = netbuffer->starttic;
    sw.numtics = netbuffer->numtics;
    for (c=0 ; c< netbuffer->numtics ; c++)
    {
 sw.cmds[c].forwardmove = netbuffer->cmds[c].forwardmove;
 sw.cmds[c].sidemove = netbuffer->cmds[c].sidemove;
 sw.cmds[c].angleturn = ((unsigned short int)((((unsigned short int)(netbuffer->cmds[c].angleturn) & 0x00ff) << 8) | (((unsigned short int)(netbuffer->cmds[c].angleturn) & 0xff00) >> 8)));
 sw.cmds[c].consistancy = ((unsigned short int)((((unsigned short int)(netbuffer->cmds[c].consistancy) & 0x00ff) << 8) | (((unsigned short int)(netbuffer->cmds[c].consistancy) & 0xff00) >> 8)));
 sw.cmds[c].chatchar = netbuffer->cmds[c].chatchar;
 sw.cmds[c].buttons = netbuffer->cmds[c].buttons;
    }
    c = sendto (sendsocket , &sw, doomcom->datalength
  ,0,(void *)&sendaddress[doomcom->remotenode]
  ,sizeof(sendaddress[doomcom->remotenode]));
}
void PacketGet (void)
{
    int i;
    int c;
    struct sockaddr_in fromaddress;
    int fromlen;
    doomdata_t sw;
    fromlen = sizeof(fromaddress);
    c = recvfrom (insocket, &sw, sizeof(sw), 0
    , (struct sockaddr *)&fromaddress, &fromlen );
    if (c == -1 )
    {
 if ((*__errno_location ()) != 11)
     I_Error ("GetPacket: %s",strerror((*__errno_location ())));
 doomcom->remotenode = -1;
 return;
    }
    {
 static int first=1;
 if (first)
     printf("len=%d:p=[0x%x 0x%x] \n", c, *(int*)&sw, *((int*)&sw+1));
 first = 0;
    }
    for (i=0 ; i<doomcom->numnodes ; i++)
 if ( fromaddress.sin_addr.s_addr == sendaddress[i].sin_addr.s_addr )
     break;
    if (i == doomcom->numnodes)
    {
 doomcom->remotenode = -1;
 return;
    }
    doomcom->remotenode = i;
    doomcom->datalength = c;
    netbuffer->checksum = ((unsigned long int)((((unsigned long int)(sw.checksum) & 0x000000ffU) << 24) | (((unsigned long int)(sw.checksum) & 0x0000ff00U) << 8) | (((unsigned long int)(sw.checksum) & 0x00ff0000U) >> 8) | (((unsigned long int)(sw.checksum) & 0xff000000U) >> 24)));
    netbuffer->player = sw.player;
    netbuffer->retransmitfrom = sw.retransmitfrom;
    netbuffer->starttic = sw.starttic;
    netbuffer->numtics = sw.numtics;
    for (c=0 ; c< netbuffer->numtics ; c++)
    {
 netbuffer->cmds[c].forwardmove = sw.cmds[c].forwardmove;
 netbuffer->cmds[c].sidemove = sw.cmds[c].sidemove;
 netbuffer->cmds[c].angleturn = ((unsigned short int)((((unsigned short int)(sw.cmds[c].angleturn) & 0x00ff) << 8) | (((unsigned short int)(sw.cmds[c].angleturn) & 0xff00) >> 8)));
 netbuffer->cmds[c].consistancy = ((unsigned short int)((((unsigned short int)(sw.cmds[c].consistancy) & 0x00ff) << 8) | (((unsigned short int)(sw.cmds[c].consistancy) & 0xff00) >> 8)));
 netbuffer->cmds[c].chatchar = sw.cmds[c].chatchar;
 netbuffer->cmds[c].buttons = sw.cmds[c].buttons;
    }
}
int GetLocalAddress (void)
{
    char hostname[1024];
    struct hostent* hostentry;
    int v;
    v = gethostname (hostname, sizeof(hostname));
    if (v == -1)
 I_Error ("GetLocalAddress : gethostname: errno %d",(*__errno_location ()));
    hostentry = gethostbyname (hostname);
    if (!hostentry)
 I_Error ("GetLocalAddress : gethostbyname: couldn't get local host");
    return *(int *)hostentry->h_addr_list[0];
}
void I_InitNetwork (void)
{
    boolean trueval = true;
    int i;
    int p;
    struct hostent* hostentry;
    doomcom = malloc (sizeof (*doomcom) );
    memset (doomcom, 0, sizeof(*doomcom) );
    i = M_CheckParm ("-dup");
    if (i && i< myargc-1)
    {
 doomcom->ticdup = myargv[i+1][0]-'0';
 if (doomcom->ticdup < 1)
     doomcom->ticdup = 1;
 if (doomcom->ticdup > 9)
     doomcom->ticdup = 9;
    }
    else
 doomcom-> ticdup = 1;
    if (M_CheckParm ("-extratic"))
 doomcom-> extratics = 1;
    else
 doomcom-> extratics = 0;
    p = M_CheckParm ("-port");
    if (p && p<myargc-1)
    {
 DOOMPORT = atoi (myargv[p+1]);
 printf ("using alternate port %i\n",DOOMPORT);
    }
    i = M_CheckParm ("-net");
    if (!i)
    {
 netgame = false;
 doomcom->id = 0x12345678l;
 doomcom->numplayers = doomcom->numnodes = 1;
 doomcom->deathmatch = false;
 doomcom->consoleplayer = 0;
 return;
    }
    netsend = PacketSend;
    netget = PacketGet;
    netgame = true;
    doomcom->consoleplayer = myargv[i+1][0]-'1';
    doomcom->numnodes = 1;
    i++;
    while (++i < myargc && myargv[i][0] != '-')
    {
 sendaddress[doomcom->numnodes].sin_family = 2;
 sendaddress[doomcom->numnodes].sin_port = ((unsigned short int)((((unsigned short int)(DOOMPORT) & 0x00ff) << 8) | (((unsigned short int)(DOOMPORT) & 0xff00) >> 8)));
 if (myargv[i][0] == '.')
 {
     sendaddress[doomcom->numnodes].sin_addr.s_addr
  = inet_addr (myargv[i]+1);
 }
 else
 {
     hostentry = gethostbyname (myargv[i]);
     if (!hostentry)
  I_Error ("gethostbyname: couldn't find %s", myargv[i]);
     sendaddress[doomcom->numnodes].sin_addr.s_addr
  = *(int *)hostentry->h_addr_list[0];
 }
 doomcom->numnodes++;
    }
    doomcom->id = 0x12345678l;
    doomcom->numplayers = doomcom->numnodes;
    insocket = UDPsocket ();
    BindToLocalPort (insocket,((unsigned short int)((((unsigned short int)(DOOMPORT) & 0x00ff) << 8) | (((unsigned short int)(DOOMPORT) & 0xff00) >> 8))));
    ioctl (insocket, 0x5421, &trueval);
    sendsocket = UDPsocket ();
}
void I_NetCmd (void)
{
    if (doomcom->command == CMD_SEND)
    {
 netsend ();
    }
    else if (doomcom->command == CMD_GET)
    {
 netget ();
    }
    else
 I_Error ("Bad net cmd: %i\n",doomcom->command);
}
