{
  if (sndserver)
  {
    fprintf(sndserver, "q\n");
    fflush(sndserver);
  }
  return;
}
void
I_InitSound()
{
  char buffer[256];
  if (getenv("DOOMWADDIR"))
    sprintf(buffer, "%s/%s",
     getenv("DOOMWADDIR"),
     sndserver_filename);
  else
    sprintf(buffer, "%s", sndserver_filename);
  if ( !access(buffer, 1) )
  {
    strcat(buffer, " -quiet");
    sndserver = popen(buffer, "w");
  }
  else
    fprintf(stderr, "Could not start sound server [%s]\n", buffer);
}
