int I_GetTime (void)
{
    struct timeval tp;
    struct timezone tzp;
    int newtics;
    static int basetime=0;
    gettimeofday(&tp, &tzp);
    if (!basetime)
 basetime = tp.tv_sec;
    newtics = (tp.tv_sec-basetime)*35 + tp.tv_usec*35/1000000;
    return newtics;
}
