int xlatekey(void)
{
    int rc;
    switch(rc = XKeycodeToKeysym(X_display, X_event.xkey.keycode, 0))
    {
      case 0xff51: rc = 0xac; break;
      case 0xff53: rc = 0xae; break;
      case 0xff54: rc = 0xaf; break;
      case 0xff52: rc = 0xad; break;
      case 0xff1b: rc = 27; break;
      case 0xff0d: rc = 13; break;
      case 0xff09: rc = 9; break;
      case 0xffbe: rc = (0x80+0x3b); break;
      case 0xffbf: rc = (0x80+0x3c); break;
      case 0xffc0: rc = (0x80+0x3d); break;
      case 0xffc1: rc = (0x80+0x3e); break;
      case 0xffc2: rc = (0x80+0x3f); break;
      case 0xffc3: rc = (0x80+0x40); break;
      case 0xffc4: rc = (0x80+0x41); break;
      case 0xffc5: rc = (0x80+0x42); break;
      case 0xffc6: rc = (0x80+0x43); break;
      case 0xffc7: rc = (0x80+0x44); break;
      case 0xffc8: rc = (0x80+0x57); break;
      case 0xffc9: rc = (0x80+0x58); break;
      case 0xff08:
      case 0xffff: rc = 127; break;
      case 0xff13: rc = 0xff; break;
      case 0xffbd:
      case 0x003d: rc = 0x3d; break;
      case 0xffad:
      case 0x002d: rc = 0x2d; break;
      case 0xffe1:
      case 0xffe2:
 rc = (0x80+0x36);
 break;
      case 0xffe3:
      case 0xffe4:
 rc = (0x80+0x1d);
 break;
      case 0xffe9:
      case 0xffe7:
      case 0xffea:
      case 0xffe8:
 rc = (0x80+0x38);
 break;
      default:
 if (rc >= 0x0020 && rc <= 0x007e)
     rc = rc - 0x0020 + ' ';
 if (rc >= 'A' && rc <= 'Z')
     rc = rc - 'A' + 'a';
 break;
    }
    return rc;
}
void I_ShutdownGraphics(void)
{
  if (!XShmDetach(X_display, &X_shminfo))
     I_Error("XShmDetach() failed in I_ShutdownGraphics()");
  shmdt(X_shminfo.shmaddr);
  shmctl(X_shminfo.shmid, 0, 0);
  image->data = ((void *)0);
}
