static int lastmousex = 0;
static int lastmousey = 0;
boolean mousemoved = false;
boolean shmFinished;
void I_GetEvent(void)
{
    event_t event;
    XNextEvent(X_display, &X_event);
    switch (X_event.type)
    {
      case 2:
 event.type = ev_keydown;
 event.data1 = xlatekey();
 D_PostEvent(&event);
 break;
      case 3:
 event.type = ev_keyup;
 event.data1 = xlatekey();
 D_PostEvent(&event);
 break;
      case 4:
 event.type = ev_mouse;
 event.data1 =
     (X_event.xbutton.state & (1<<8))
     | (X_event.xbutton.state & (1<<9) ? 2 : 0)
     | (X_event.xbutton.state & (1<<10) ? 4 : 0)
     | (X_event.xbutton.button == 1)
     | (X_event.xbutton.button == 2 ? 2 : 0)
     | (X_event.xbutton.button == 3 ? 4 : 0);
 event.data2 = event.data3 = 0;
 D_PostEvent(&event);
 break;
      case 5:
 event.type = ev_mouse;
 event.data1 =
     (X_event.xbutton.state & (1<<8))
     | (X_event.xbutton.state & (1<<9) ? 2 : 0)
     | (X_event.xbutton.state & (1<<10) ? 4 : 0);
 event.data1 =
     event.data1
     ^ (X_event.xbutton.button == 1 ? 1 : 0)
     ^ (X_event.xbutton.button == 2 ? 2 : 0)
     ^ (X_event.xbutton.button == 3 ? 4 : 0);
 event.data2 = event.data3 = 0;
 D_PostEvent(&event);
 break;
      case 6:
 event.type = ev_mouse;
 event.data1 =
     (X_event.xmotion.state & (1<<8))
     | (X_event.xmotion.state & (1<<9) ? 2 : 0)
     | (X_event.xmotion.state & (1<<10) ? 4 : 0);
 event.data2 = (X_event.xmotion.x - lastmousex) << 2;
 event.data3 = (lastmousey - X_event.xmotion.y) << 2;
 if (event.data2 || event.data3)
 {
     lastmousex = X_event.xmotion.x;
     lastmousey = X_event.xmotion.y;
     if (X_event.xmotion.x != X_width/2 &&
  X_event.xmotion.y != X_height/2)
     {
  D_PostEvent(&event);
  mousemoved = false;
     } else
     {
  mousemoved = true;
     }
 }
 break;
      case 12:
      case 22:
 break;
      default:
 if (doShm && X_event.type == X_shmeventtype) shmFinished = true;
 break;
    }
}
Cursor
createnullcursor
( Display* display,
  Window root )
{
    Pixmap cursormask;
    XGCValues xgc;
    GC gc;
    XColor dummycolour;
    Cursor cursor;
    cursormask = XCreatePixmap(display, root, 1, 1, 1 );
    xgc.function = 0x0;
    gc = XCreateGC(display, cursormask, (1L<<0), &xgc);
    XFillRectangle(display, cursormask, gc, 0, 0, 1, 1);
    dummycolour.pixel = 0;
    dummycolour.red = 0;
    dummycolour.flags = 04;
    cursor = XCreatePixmapCursor(display, cursormask, cursormask,
     &dummycolour,&dummycolour, 0,0);
    XFreePixmap(display,cursormask);
    XFreeGC(display,gc);
    return cursor;
}
void I_StartTic (void)
{
    if (!X_display)
 return;
    while (XPending(X_display))
 I_GetEvent();
    if (grabMouse)
    {
 if (!--doPointerWarp)
 {
     XWarpPointer( X_display,
     0L,
     X_mainWindow,
     0, 0,
     0, 0,
     X_width/2, X_height/2);
     doPointerWarp = 1;
 }
    }
    mousemoved = false;
}
void I_UpdateNoBlit (void)
{
}
void I_FinishUpdate (void)
{
    static int lasttic;
    int tics;
    int i;
    if (devparm)
    {
 i = I_GetTime();
 tics = i - lasttic;
 lasttic = i;
 if (tics > 20) tics = 20;
 for (i=0 ; i<tics*2 ; i+=2)
     screens[0][ (200 -1)*320 + i] = 0xff;
 for ( ; i<20*2 ; i+=2)
     screens[0][ (200 -1)*320 + i] = 0x0;
    }
    if (multiply == 2)
    {
 unsigned int *olineptrs[2];
 unsigned int *ilineptr;
 int x, y, i;
 unsigned int twoopixels;
 unsigned int twomoreopixels;
 unsigned int fouripixels;
 ilineptr = (unsigned int *) (screens[0]);
 for (i=0 ; i<2 ; i++)
     olineptrs[i] = (unsigned int *) &image->data[i*X_width];
 y = 200;
 while (y--)
 {
     x = 320;
     do
     {
  fouripixels = *ilineptr++;
  twoopixels = (fouripixels & 0xff000000)
      | ((fouripixels>>8) & 0xffff00)
      | ((fouripixels>>16) & 0xff);
  twomoreopixels = ((fouripixels<<16) & 0xff000000)
      | ((fouripixels<<8) & 0xffff00)
      | (fouripixels & 0xff);
  *olineptrs[0]++ = twomoreopixels;
  *olineptrs[1]++ = twomoreopixels;
  *olineptrs[0]++ = twoopixels;
  *olineptrs[1]++ = twoopixels;
     } while (x-=4);
     olineptrs[0] += X_width/4;
     olineptrs[1] += X_width/4;
 }
    }
    else if (multiply == 3)
    {
 unsigned int *olineptrs[3];
 unsigned int *ilineptr;
 int x, y, i;
 unsigned int fouropixels[3];
 unsigned int fouripixels;
 ilineptr = (unsigned int *) (screens[0]);
 for (i=0 ; i<3 ; i++)
     olineptrs[i] = (unsigned int *) &image->data[i*X_width];
 y = 200;
 while (y--)
 {
     x = 320;
     do
     {
  fouripixels = *ilineptr++;
  fouropixels[0] = (fouripixels & 0xff000000)
      | ((fouripixels>>8) & 0xff0000)
      | ((fouripixels>>16) & 0xffff);
  fouropixels[1] = ((fouripixels<<8) & 0xff000000)
      | (fouripixels & 0xffff00)
      | ((fouripixels>>8) & 0xff);
  fouropixels[2] = ((fouripixels<<16) & 0xffff0000)
      | ((fouripixels<<8) & 0xff00)
      | (fouripixels & 0xff);
  *olineptrs[0]++ = fouropixels[2];
  *olineptrs[1]++ = fouropixels[2];
  *olineptrs[2]++ = fouropixels[2];
  *olineptrs[0]++ = fouropixels[1];
  *olineptrs[1]++ = fouropixels[1];
  *olineptrs[2]++ = fouropixels[1];
  *olineptrs[0]++ = fouropixels[0];
  *olineptrs[1]++ = fouropixels[0];
  *olineptrs[2]++ = fouropixels[0];
     } while (x-=4);
     olineptrs[0] += 2*X_width/4;
     olineptrs[1] += 2*X_width/4;
     olineptrs[2] += 2*X_width/4;
 }
    }
    else if (multiply == 4)
    {
 void Expand4(unsigned *, double *);
   Expand4 ((unsigned *)(screens[0]), (double *) (image->data));
    }
    if (doShm)
    {
 if (!XShmPutImage( X_display,
    X_mainWindow,
    X_gc,
    image,
    0, 0,
    0, 0,
    X_width, X_height,
    1 ))
     I_Error("XShmPutImage() failed\n");
 shmFinished = false;
 do
 {
     I_GetEvent();
 } while (!shmFinished);
    }
    else
    {
 XPutImage( X_display,
   X_mainWindow,
   X_gc,
   image,
   0, 0,
   0, 0,
   X_width, X_height );
 XSync(X_display, 0);
    }
}
