static XColor colors[256];
void UploadNewPalette(Colormap cmap, byte *palette)
{
    register int i;
    register int c;
    static boolean firstcall = true;
    if (X_visualinfo.class == 3 && X_visualinfo.depth == 8)
 {
     if (firstcall)
     {
  firstcall = false;
  for (i=0 ; i<256 ; i++)
  {
      colors[i].pixel = i;
      colors[i].flags = (1<<0)|(1<<1)|(1<<2);
  }
     }
     for (i=0 ; i<256 ; i++)
     {
  c = gammatable[usegamma][*palette++];
  colors[i].red = (c<<8) + c;
  c = gammatable[usegamma][*palette++];
  colors[i].green = (c<<8) + c;
  c = gammatable[usegamma][*palette++];
  colors[i].blue = (c<<8) + c;
     }
     XStoreColors(X_display, cmap, colors, 256);
 }
}
void I_SetPalette (byte* palette)
{
    UploadNewPalette(X_cmap, palette);
}
void grabsharedmemory(int size)
{
  int key = ('d'<<24) | ('o'<<16) | ('o'<<8) | 'm';
  struct shmid_ds shminfo;
  int minsize = 320*200;
  int id;
  int rc;
  int pollution=5;
  do
  {
    id = shmget((key_t) key, minsize, 0777);
    if (id != -1)
    {
      rc=shmctl(id, 2, &shminfo);
      if (!rc)
      {
 if (shminfo.shm_nattch)
 {
   fprintf(stderr, "User %d appears to be running "
    "DOOM.  Is that wise?\n", shminfo.shm_cpid);
   key++;
 }
 else
 {
   if (getuid() == shminfo.shm_perm.cuid)
   {
     rc = shmctl(id, 0, 0);
     if (!rc)
       fprintf(stderr,
        "Was able to kill my old shared memory\n");
     else
       I_Error("Was NOT able to kill my old shared memory");
     id = shmget((key_t)key, size, 01000|0777);
     if (id==-1)
       I_Error("Could not get shared memory");
     rc=shmctl(id, 2, &shminfo);
     break;
   }
   if (size >= shminfo.shm_segsz)
   {
     fprintf(stderr,
      "will use %d's stale shared memory\n",
      shminfo.shm_cpid);
     break;
   }
   else
   {
     fprintf(stderr,
      "warning: can't use stale "
      "shared memory belonging to id %d, "
      "key=0x%x\n",
      shminfo.shm_cpid, key);
     key++;
   }
 }
      }
      else
      {
 I_Error("could not get stats on key=%d", key);
      }
    }
    else
    {
      id = shmget((key_t)key, size, 01000|0777);
      if (id==-1)
      {
 extern int (*__errno_location ());
 fprintf(stderr, "errno=%d\n", (*__errno_location ()));
 I_Error("Could not get any shared memory");
      }
      break;
    }
  } while (--pollution);
  if (!pollution)
  {
    I_Error("Sorry, system too polluted with stale "
     "shared memory segments.\n");
    }
  X_shminfo.shmid = id;
  image->data = X_shminfo.shmaddr = shmat(id, 0, 0);
  fprintf(stderr, "shared memory id=%d, addr=0x%x\n", id,
   (int) (image->data));
}
void I_InitGraphics(void)
{
    char* displayname;
    char* d;
    int n;
    int pnum;
    int x=0;
    int y=0;
    char xsign=' ';
    char ysign=' ';
    int oktodraw;
    unsigned long attribmask;
    XSetWindowAttributes attribs;
    XGCValues xgcvalues;
    int valuemask;
    static int firsttime=1;
    if (!firsttime)
 return;
    firsttime = 0;
    signal(2, (void (*)(int)) I_Quit);
    if (M_CheckParm("-2"))
 multiply = 2;
    if (M_CheckParm("-3"))
 multiply = 3;
    if (M_CheckParm("-4"))
 multiply = 4;
    X_width = 320 * multiply;
    X_height = 200 * multiply;
    if ( (pnum=M_CheckParm("-disp")) )
 displayname = myargv[pnum+1];
    else
 displayname = 0;
    grabMouse = !!M_CheckParm("-grabmouse");
    if ( (pnum=M_CheckParm("-geom")) )
    {
 n = sscanf(myargv[pnum+1], "%c%d%c%d", &xsign, &x, &ysign, &y);
 if (n==2)
     x = y = 0;
 else if (n==6)
 {
     if (xsign == '-')
  x = -x;
     if (ysign == '-')
  y = -y;
 }
 else
     I_Error("bad -geom parameter");
    }
    X_display = XOpenDisplay(displayname);
    if (!X_display)
    {
 if (displayname)
     I_Error("Could not open display [%s]", displayname);
 else
     I_Error("Could not open display (DISPLAY=[%s])", getenv("DISPLAY"));
    }
    X_screen = (((_XPrivDisplay)(X_display))->default_screen);
    if (!XMatchVisualInfo(X_display, X_screen, 8, 3, &X_visualinfo))
 I_Error("xdoom currently only supports 256-color PseudoColor screens");
    X_visual = X_visualinfo.visual;
    doShm = XShmQueryExtension(X_display);
    if (doShm)
    {
 if (!displayname) displayname = (char *) getenv("DISPLAY");
 if (displayname)
 {
     d = displayname;
     while (*d && (*d != ':')) d++;
     if (*d) *d = 0;
     if (!(!strcasecmp(displayname, "unix") || !*displayname)) doShm = false;
 }
    }
    fprintf(stderr, "Using MITSHM extension\n");
    X_cmap = XCreateColormap(X_display, ((&((_XPrivDisplay)(X_display))->screens[X_screen])->root), X_visual, 1);
    attribmask = (1L<<11) | (1L<<13) | (1L<<3);
    attribs.event_mask =
 (1L<<0)
 | (1L<<1)
 | (1L<<15);
    attribs.colormap = X_cmap;
    attribs.border_pixel = 0;
    X_mainWindow = XCreateWindow( X_display,
     ((&((_XPrivDisplay)(X_display))->screens[X_screen])->root),
     x, y,
     X_width, X_height,
     0,
     8,
     1,
     X_visual,
     attribmask,
     &attribs );
    XDefineCursor(X_display, X_mainWindow,
    createnullcursor( X_display, X_mainWindow ) );
    valuemask = (1L<<16);
    xgcvalues.graphics_exposures = 0;
    X_gc = XCreateGC( X_display,
     X_mainWindow,
     valuemask,
     &xgcvalues );
    XMapWindow(X_display, X_mainWindow);
    oktodraw = 0;
    while (!oktodraw)
    {
 XNextEvent(X_display, &X_event);
 if (X_event.type == 12
     && !X_event.xexpose.count)
 {
     oktodraw = 1;
 }
    }
    if (grabMouse)
 XGrabPointer(X_display, X_mainWindow, 1,
       (1L<<2)|(1L<<3)|(1L<<6),
       1, 1,
       X_mainWindow, 0L, 0L);
    if (doShm)
    {
 X_shmeventtype = XShmGetEventBase(X_display) + 0;
 image = XShmCreateImage( X_display,
     X_visual,
     8,
     2,
     0,
     &X_shminfo,
     X_width,
     X_height );
 grabsharedmemory(image->bytes_per_line * image->height);
 if (!image->data)
 {
     perror("");
     I_Error("shmat() failed in InitGraphics()");
 }
 if (!XShmAttach(X_display, &X_shminfo))
     I_Error("XShmAttach() failed in InitGraphics()");
    }
    else
    {
 image = XCreateImage( X_display,
        X_visual,
        8,
        2,
        0,
        (char*)malloc(X_width * X_height),
        X_width, X_height,
        8,
        X_width );
    }
    if (multiply == 1)
 screens[0] = (unsigned char *) (image->data);
    else
 screens[0] = (unsigned char *) malloc (320 * 200);
}
unsigned exptable[256];
void InitExpand (void)
{
    int i;
    for (i=0 ; i<256 ; i++)
 exptable[i] = i | (i<<8) | (i<<16) | (i<<24);
}
double exptable2[256*256];
void InitExpand2 (void)
{
    int i;
    int j;
    double* exp;
    union
    {
 double d;
 unsigned u[2];
    } pixel;
    printf ("building exptable2...\n");
    exp = exptable2;
    for (i=0 ; i<256 ; i++)
    {
 pixel.u[0] = i | (i<<8) | (i<<16) | (i<<24);
 for (j=0 ; j<256 ; j++)
 {
     pixel.u[1] = j | (j<<8) | (j<<16) | (j<<24);
     *exp++ = pixel.d;
 }
    }
    printf ("done.\n");
}
int inited;
void
Expand4
( unsigned* lineptr,
  double* xline )
{
    double dpixel;
    unsigned x;
    unsigned y;
    unsigned fourpixels;
    unsigned step;
    double* exp;
    exp = exptable2;
    if (!inited)
    {
 inited = 1;
 InitExpand2 ();
    }
    step = 3*320/2;
    y = 200 -1;
    do
    {
 x = 320;
 do
 {
     fourpixels = lineptr[0];
     dpixel = *(double *)( (int)exp + ( (fourpixels&0xffff0000)>>13) );
     xline[0] = dpixel;
     xline[160] = dpixel;
     xline[320] = dpixel;
     xline[480] = dpixel;
     dpixel = *(double *)( (int)exp + ( (fourpixels&0xffff)<<3 ) );
     xline[1] = dpixel;
     xline[161] = dpixel;
     xline[321] = dpixel;
     xline[481] = dpixel;
     fourpixels = lineptr[1];
     dpixel = *(double *)( (int)exp + ( (fourpixels&0xffff0000)>>13) );
     xline[2] = dpixel;
     xline[162] = dpixel;
     xline[322] = dpixel;
     xline[482] = dpixel;
     dpixel = *(double *)( (int)exp + ( (fourpixels&0xffff)<<3 ) );
     xline[3] = dpixel;
     xline[163] = dpixel;
     xline[323] = dpixel;
     xline[483] = dpixel;
     fourpixels = lineptr[2];
     dpixel = *(double *)( (int)exp + ( (fourpixels&0xffff0000)>>13) );
     xline[4] = dpixel;
     xline[164] = dpixel;
     xline[324] = dpixel;
     xline[484] = dpixel;
     dpixel = *(double *)( (int)exp + ( (fourpixels&0xffff)<<3 ) );
     xline[5] = dpixel;
     xline[165] = dpixel;
     xline[325] = dpixel;
     xline[485] = dpixel;
     fourpixels = lineptr[3];
     dpixel = *(double *)( (int)exp + ( (fourpixels&0xffff0000)>>13) );
     xline[6] = dpixel;
     xline[166] = dpixel;
     xline[326] = dpixel;
     xline[486] = dpixel;
     dpixel = *(double *)( (int)exp + ( (fourpixels&0xffff)<<3 ) );
     xline[7] = dpixel;
     xline[167] = dpixel;
     xline[327] = dpixel;
     xline[487] = dpixel;
     lineptr+=4;
     xline+=8;
 } while (x-=16);
 xline += step;
    } while (y--);
}
