static const char
rcsid[] = "$Id: m_argv.c,v 1.1 1997/02/03 22:45:10 b1 Exp $";
int myargc;
char** myargv;
int M_CheckParm (char *check)
{
    int i;
    for (i = 1;i<myargc;i++)
    {
 if ( !strcasecmp(check, myargv[i]) )
     return i;
    }
    return 0;
}
static const char
rcsid[] = "$Id: m_bbox.c,v 1.1 1997/02/03 22:45:10 b1 Exp $";
enum
{
    BOXTOP,
    BOXBOTTOM,
    BOXLEFT,
    BOXRIGHT
};
void M_ClearBox (fixed_t* box);
void
M_AddToBox
( fixed_t* box,
  fixed_t x,
  fixed_t y );
void M_ClearBox (fixed_t *box)
{
    box[BOXTOP] = box[BOXRIGHT] = (-0x7fffffff - 1);
    box[BOXBOTTOM] = box[BOXLEFT] = 0x7fffffff;
}
void
M_AddToBox
( fixed_t* box,
  fixed_t x,
  fixed_t y )
{
    if (x<box[BOXLEFT])
 box[BOXLEFT] = x;
    else if (x>box[BOXRIGHT])
 box[BOXRIGHT] = x;
    if (y<box[BOXBOTTOM])
 box[BOXBOTTOM] = y;
    else if (y>box[BOXTOP])
 box[BOXTOP] = y;
}
static const char
rcsid[] = "$Id: m_cheat.c,v 1.1 1997/02/03 21:24:34 b1 Exp $";
static int firsttime = 1;
static unsigned char cheat_xlate_table[256];
int
cht_CheckCheat
( cheatseq_t* cht,
  char key )
{
    int i;
    int rc = 0;
    if (firsttime)
    {
 firsttime = 0;
 for (i=0;i<256;i++) cheat_xlate_table[i] = ((((i)&1)<<7) + (((i)&2)<<5) + ((i)&4) + (((i)&8)<<1) + (((i)&16)>>1) + ((i)&32) + (((i)&64)>>5) + (((i)&128)>>7));
    }
    if (!cht->p)
 cht->p = cht->sequence;
    if (*cht->p == 0)
 *(cht->p++) = key;
    else if
 (cheat_xlate_table[(unsigned char)key] == *cht->p) cht->p++;
    else
 cht->p = cht->sequence;
    if (*cht->p == 1)
 cht->p++;
    else if (*cht->p == 0xff)
    {
 cht->p = cht->sequence;
 rc = 1;
    }
    return rc;
}
void
cht_GetParam
( cheatseq_t* cht,
  char* buffer )
{
    unsigned char *p, c;
    p = cht->sequence;
    while (*(p++) != 1);
    do
    {
 c = *p;
 *(buffer++) = c;
 *(p++) = 0;
    }
    while (c && *p!=0xff );
    if (*p==0xff)
 *buffer = 0;
}
static const char
rcsid[] = "$Id: m_bbox.c,v 1.1 1997/02/03 22:45:10 b1 Exp $";
fixed_t
FixedMul
( fixed_t a,
  fixed_t b )
{
    return ((long long) a * (long long) b) >> 16;
}
fixed_t
FixedDiv
( fixed_t a,
  fixed_t b )
{
    if ( (abs(a)>>14) >= abs(b))
 return (a^b)<0 ? (-0x7fffffff - 1) : 0x7fffffff;
    return FixedDiv2 (a,b);
}
fixed_t
FixedDiv2
( fixed_t a,
  fixed_t b )
{
    double c;
    c = ((double)a) / ((double)b) * (1<<16);
    if (c >= 2147483648.0 || c < -2147483648.0)
 I_Error("FixedDiv: divide by zero");
    return (fixed_t) c;
}
