int M_StringWidth(char* string)
{
    int i;
    int w = 0;
    int c;
    for (i = 0;i < strlen(string);i++)
    {
 c = toupper(string[i]) - '!';
 if (c < 0 || c >= ('_' - '!' + 1))
     w += 4;
 else
     w += (hu_font[c]->width);
    }
    return w;
}
int M_StringHeight(char* string)
{
    int i;
    int h;
    int height = (hu_font[0]->height);
    h = height;
    for (i = 0;i < strlen(string);i++)
 if (string[i] == '\n')
     h += height;
    return h;
}
void
M_WriteText
( int x,
  int y,
  char* string)
{
    int w;
    char* ch;
    int c;
    int cx;
    int cy;
    ch = string;
    cx = x;
    cy = y;
    while(1)
    {
 c = *ch++;
 if (!c)
     break;
 if (c == '\n')
 {
     cx = x;
     cy += 12;
     continue;
 }
 c = toupper(c) - '!';
 if (c < 0 || c>= ('_' - '!' + 1))
 {
     cx += 4;
     continue;
 }
 w = (hu_font[c]->width);
 if (cx+w > 320)
     break;
 V_DrawPatchDirect(cx, cy, 0, hu_font[c]);
 cx+=w;
    }
}
boolean M_Responder (event_t* ev)
{
    int ch;
    int i;
    static int joywait = 0;
    static int mousewait = 0;
    static int mousey = 0;
    static int lasty = 0;
    static int mousex = 0;
    static int lastx = 0;
    ch = -1;
    if (ev->type == ev_joystick && joywait < I_GetTime())
    {
 if (ev->data3 == -1)
 {
     ch = 0xad;
     joywait = I_GetTime() + 5;
 }
 else if (ev->data3 == 1)
 {
     ch = 0xaf;
     joywait = I_GetTime() + 5;
 }
 if (ev->data2 == -1)
 {
     ch = 0xac;
     joywait = I_GetTime() + 2;
 }
 else if (ev->data2 == 1)
 {
     ch = 0xae;
     joywait = I_GetTime() + 2;
 }
 if (ev->data1&1)
 {
     ch = 13;
     joywait = I_GetTime() + 5;
 }
 if (ev->data1&2)
 {
     ch = 127;
     joywait = I_GetTime() + 5;
 }
    }
    else
    {
 if (ev->type == ev_mouse && mousewait < I_GetTime())
 {
     mousey += ev->data3;
     if (mousey < lasty-30)
     {
  ch = 0xaf;
  mousewait = I_GetTime() + 5;
  mousey = lasty -= 30;
     }
     else if (mousey > lasty+30)
     {
  ch = 0xad;
  mousewait = I_GetTime() + 5;
  mousey = lasty += 30;
     }
     mousex += ev->data2;
     if (mousex < lastx-30)
     {
  ch = 0xac;
  mousewait = I_GetTime() + 5;
  mousex = lastx -= 30;
     }
     else if (mousex > lastx+30)
     {
  ch = 0xae;
  mousewait = I_GetTime() + 5;
  mousex = lastx += 30;
     }
     if (ev->data1&1)
     {
  ch = 13;
  mousewait = I_GetTime() + 15;
     }
     if (ev->data1&2)
     {
  ch = 127;
  mousewait = I_GetTime() + 15;
     }
 }
 else
     if (ev->type == ev_keydown)
     {
  ch = ev->data1;
     }
    }
    if (ch == -1)
 return false;
    if (saveStringEnter)
    {
 switch(ch)
 {
   case 127:
     if (saveCharIndex > 0)
     {
  saveCharIndex--;
  savegamestrings[saveSlot][saveCharIndex] = 0;
     }
     break;
   case 27:
     saveStringEnter = 0;
     strcpy(&savegamestrings[saveSlot][0],saveOldString);
     break;
   case 13:
     saveStringEnter = 0;
     if (savegamestrings[saveSlot][0])
  M_DoSave(saveSlot);
     break;
   default:
     ch = toupper(ch);
     if (ch != 32)
  if (ch-'!' < 0 || ch-'!' >= ('_' - '!' + 1))
      break;
     if (ch >= 32 && ch <= 127 &&
  saveCharIndex < 24 -1 &&
  M_StringWidth(savegamestrings[saveSlot]) <
  (24 -2)*8)
     {
  savegamestrings[saveSlot][saveCharIndex++] = ch;
  savegamestrings[saveSlot][saveCharIndex] = 0;
     }
     break;
 }
 return true;
    }
    if (messageToPrint)
    {
 if (messageNeedsInput == true &&
     !(ch == ' ' || ch == 'n' || ch == 'y' || ch == 27))
     return false;
 menuactive = messageLastMenuActive;
 messageToPrint = 0;
 if (messageRoutine)
     messageRoutine(ch);
 menuactive = false;
 S_StartSound(((void *)0),sfx_swtchx);
 return true;
    }
    if (devparm && ch == (0x80+0x3b))
    {
 G_ScreenShot ();
 return true;
    }
    if (!menuactive)
 switch(ch)
 {
   case 0x2d:
     if (automapactive || chat_on)
  return false;
     M_SizeDisplay(0);
     S_StartSound(((void *)0),sfx_stnmov);
     return true;
   case 0x3d:
     if (automapactive || chat_on)
  return false;
     M_SizeDisplay(1);
     S_StartSound(((void *)0),sfx_stnmov);
     return true;
   case (0x80+0x3b):
     M_StartControlPanel ();
     if ( gamemode == retail )
       currentMenu = &ReadDef2;
     else
       currentMenu = &ReadDef1;
     itemOn = 0;
     S_StartSound(((void *)0),sfx_swtchn);
     return true;
   case (0x80+0x3c):
     M_StartControlPanel();
     S_StartSound(((void *)0),sfx_swtchn);
     M_SaveGame(0);
     return true;
   case (0x80+0x3d):
     M_StartControlPanel();
     S_StartSound(((void *)0),sfx_swtchn);
     M_LoadGame(0);
     return true;
   case (0x80+0x3e):
     M_StartControlPanel ();
     currentMenu = &SoundDef;
     itemOn = sfx_vol;
     S_StartSound(((void *)0),sfx_swtchn);
     return true;
   case (0x80+0x3f):
     M_ChangeDetail(0);
     S_StartSound(((void *)0),sfx_swtchn);
     return true;
   case (0x80+0x40):
     S_StartSound(((void *)0),sfx_swtchn);
     M_QuickSave();
     return true;
   case (0x80+0x41):
     S_StartSound(((void *)0),sfx_swtchn);
     M_EndGame(0);
     return true;
   case (0x80+0x42):
     M_ChangeMessages(0);
     S_StartSound(((void *)0),sfx_swtchn);
     return true;
   case (0x80+0x43):
     S_StartSound(((void *)0),sfx_swtchn);
     M_QuickLoad();
     return true;
   case (0x80+0x44):
     S_StartSound(((void *)0),sfx_swtchn);
     M_QuitDOOM(0);
     return true;
   case (0x80+0x57):
     usegamma++;
     if (usegamma > 4)
  usegamma = 0;
     players[consoleplayer].message = gammamsg[usegamma];
     I_SetPalette (W_CacheLumpName ("PLAYPAL",101));
     return true;
 }
    if (!menuactive)
    {
 if (ch == 27)
 {
     M_StartControlPanel ();
     S_StartSound(((void *)0),sfx_swtchn);
     return true;
 }
 return false;
    }
    switch (ch)
    {
      case 0xaf:
 do
 {
     if (itemOn+1 > currentMenu->numitems-1)
  itemOn = 0;
     else itemOn++;
     S_StartSound(((void *)0),sfx_pstop);
 } while(currentMenu->menuitems[itemOn].status==-1);
 return true;
      case 0xad:
 do
 {
     if (!itemOn)
  itemOn = currentMenu->numitems-1;
     else itemOn--;
     S_StartSound(((void *)0),sfx_pstop);
 } while(currentMenu->menuitems[itemOn].status==-1);
 return true;
      case 0xac:
 if (currentMenu->menuitems[itemOn].routine &&
     currentMenu->menuitems[itemOn].status == 2)
 {
     S_StartSound(((void *)0),sfx_stnmov);
     currentMenu->menuitems[itemOn].routine(0);
 }
 return true;
      case 0xae:
 if (currentMenu->menuitems[itemOn].routine &&
     currentMenu->menuitems[itemOn].status == 2)
 {
     S_StartSound(((void *)0),sfx_stnmov);
     currentMenu->menuitems[itemOn].routine(1);
 }
 return true;
      case 13:
 if (currentMenu->menuitems[itemOn].routine &&
     currentMenu->menuitems[itemOn].status)
 {
     currentMenu->lastOn = itemOn;
     if (currentMenu->menuitems[itemOn].status == 2)
     {
  currentMenu->menuitems[itemOn].routine(1);
  S_StartSound(((void *)0),sfx_stnmov);
     }
     else
     {
  currentMenu->menuitems[itemOn].routine(itemOn);
  S_StartSound(((void *)0),sfx_pistol);
     }
 }
 return true;
      case 27:
 currentMenu->lastOn = itemOn;
 M_ClearMenus ();
 S_StartSound(((void *)0),sfx_swtchx);
 return true;
      case 127:
 currentMenu->lastOn = itemOn;
 if (currentMenu->prevMenu)
 {
     currentMenu = currentMenu->prevMenu;
     itemOn = currentMenu->lastOn;
     S_StartSound(((void *)0),sfx_swtchn);
 }
 return true;
      default:
 for (i = itemOn+1;i < currentMenu->numitems;i++)
     if (currentMenu->menuitems[i].alphaKey == ch)
     {
  itemOn = i;
  S_StartSound(((void *)0),sfx_pstop);
  return true;
     }
 for (i = 0;i <= itemOn;i++)
     if (currentMenu->menuitems[i].alphaKey == ch)
     {
  itemOn = i;
  S_StartSound(((void *)0),sfx_pstop);
  return true;
     }
 break;
    }
    return false;
}
void M_StartControlPanel (void)
{
    if (menuactive)
 return;
    menuactive = 1;
    currentMenu = &MainDef;
    itemOn = currentMenu->lastOn;
}
void M_Drawer (void)
{
    static short x;
    static short y;
    short i;
    short max;
    char string[40];
    int start;
    inhelpscreens = false;
    if (messageToPrint)
    {
 start = 0;
 y = 100 - M_StringHeight(messageString)/2;
 while(*(messageString+start))
 {
     for (i = 0;i < strlen(messageString+start);i++)
  if (*(messageString+start+i) == '\n')
  {
      memset(string,0,40);
      strncpy(string,messageString+start,i);
      start += i+1;
      break;
  }
     if (i == strlen(messageString+start))
     {
  strcpy(string,messageString+start);
  start += i;
     }
     x = 160 - M_StringWidth(string)/2;
     M_WriteText(x,y,string);
     y += (hu_font[0]->height);
 }
 return;
    }
    if (!menuactive)
 return;
    if (currentMenu->routine)
 currentMenu->routine();
    x = currentMenu->x;
    y = currentMenu->y;
    max = currentMenu->numitems;
    for (i=0;i<max;i++)
    {
 if (currentMenu->menuitems[i].name[0])
     V_DrawPatchDirect (x,y,0,
          W_CacheLumpName(currentMenu->menuitems[i].name ,101));
 y += 16;
    }
    V_DrawPatchDirect(x + -32,currentMenu->y - 5 + itemOn*16, 0,
        W_CacheLumpName(skullName[whichSkull],101));
}
