extern patch_t* hu_font[('_' - '!' + 1)];
int
M_DrawText
( int x,
  int y,
  boolean direct,
  char* string )
{
    int c;
    int w;
    while (*string)
    {
 c = toupper(*string) - '!';
 string++;
 if (c < 0 || c> ('_' - '!' + 1))
 {
     x += 4;
     continue;
 }
 w = (hu_font[c]->width);
 if (x+w > 320)
     break;
 if (direct)
     V_DrawPatchDirect(x, y, 0, hu_font[c]);
 else
     V_DrawPatch(x, y, 0, hu_font[c]);
 x+=w;
    }
    return x;
}
boolean
M_WriteFile
( char const* name,
  void* source,
  int length )
{
    int handle;
    int count;
    handle = open ( name, 01 | 0100 | 01000 | 0, 0666);
    if (handle == -1)
 return false;
    count = write (handle, source, length);
    close (handle);
    if (count < length)
 return false;
    return true;
}
int
M_ReadFile
( char const* name,
  byte** buffer )
{
    int handle, count, length;
    struct stat fileinfo;
    byte *buf;
    handle = open (name, 00 | 0, 0666);
    if (handle == -1)
 I_Error ("Couldn't read file %s", name);
    if (fstat (handle,&fileinfo) == -1)
 I_Error ("Couldn't read file %s", name);
    length = fileinfo.st_size;
    buf = Z_Malloc (length, 1, ((void *)0));
    count = read (handle, buf, length);
    close (handle);
    if (count < length)
 I_Error ("Couldn't read file %s", name);
    *buffer = buf;
    return length;
}
