int
EV_DoLockedDoor
( line_t* line,
  vldoor_e type,
  mobj_t* thing )
{
    player_t* p;
    p = thing->player;
    if (!p)
 return 0;
    switch(line->special)
    {
      case 99:
      case 133:
 if ( !p )
     return 0;
 if (!p->cards[it_bluecard] && !p->cards[it_blueskull])
 {
     p->message = "You need a blue key to activate this object";
     S_StartSound(((void *)0),sfx_oof);
     return 0;
 }
 break;
      case 134:
      case 135:
 if ( !p )
     return 0;
 if (!p->cards[it_redcard] && !p->cards[it_redskull])
 {
     p->message = "You need a red key to activate this object";
     S_StartSound(((void *)0),sfx_oof);
     return 0;
 }
 break;
      case 136:
      case 137:
 if ( !p )
     return 0;
 if (!p->cards[it_yellowcard] &&
     !p->cards[it_yellowskull])
 {
     p->message = "You need a yellow key to activate this object";
     S_StartSound(((void *)0),sfx_oof);
     return 0;
 }
 break;
    }
    return EV_DoDoor(line,type);
}
int
EV_DoDoor
( line_t* line,
  vldoor_e type )
{
    int secnum,rtn;
    sector_t* sec;
    vldoor_t* door;
    secnum = -1;
    rtn = 0;
    while ((secnum = P_FindSectorFromLineTag(line,secnum)) >= 0)
    {
 sec = &sectors[secnum];
 if (sec->specialdata)
     continue;
 rtn = 1;
 door = Z_Malloc (sizeof(*door), 51, 0);
 P_AddThinker (&door->thinker);
 sec->specialdata = door;
 door->thinker.function.acp1 = (actionf_p1) T_VerticalDoor;
 door->sector = sec;
 door->type = type;
 door->topwait = 150;
 door->speed = (1<<16)*2;
 switch(type)
 {
   case blazeClose:
     door->topheight = P_FindLowestCeilingSurrounding(sec);
     door->topheight -= 4*(1<<16);
     door->direction = -1;
     door->speed = (1<<16)*2 * 4;
     S_StartSound((mobj_t *)&door->sector->soundorg,
    sfx_bdcls);
     break;
   case close:
     door->topheight = P_FindLowestCeilingSurrounding(sec);
     door->topheight -= 4*(1<<16);
     door->direction = -1;
     S_StartSound((mobj_t *)&door->sector->soundorg,
    sfx_dorcls);
     break;
   case close30ThenOpen:
     door->topheight = sec->ceilingheight;
     door->direction = -1;
     S_StartSound((mobj_t *)&door->sector->soundorg,
    sfx_dorcls);
     break;
   case blazeRaise:
   case blazeOpen:
     door->direction = 1;
     door->topheight = P_FindLowestCeilingSurrounding(sec);
     door->topheight -= 4*(1<<16);
     door->speed = (1<<16)*2 * 4;
     if (door->topheight != sec->ceilingheight)
  S_StartSound((mobj_t *)&door->sector->soundorg,
        sfx_bdopn);
     break;
   case normal:
   case open:
     door->direction = 1;
     door->topheight = P_FindLowestCeilingSurrounding(sec);
     door->topheight -= 4*(1<<16);
     if (door->topheight != sec->ceilingheight)
  S_StartSound((mobj_t *)&door->sector->soundorg,
        sfx_doropn);
     break;
   default:
     break;
 }
    }
    return rtn;
}
void
EV_VerticalDoor
( line_t* line,
  mobj_t* thing )
{
    player_t* player;
    int secnum;
    sector_t* sec;
    vldoor_t* door;
    int side;
    side = 0;
    player = thing->player;
    switch(line->special)
    {
      case 26:
      case 32:
 if ( !player )
     return;
 if (!player->cards[it_bluecard] && !player->cards[it_blueskull])
 {
     player->message = "You need a blue key to open this door";
     S_StartSound(((void *)0),sfx_oof);
     return;
 }
 break;
      case 27:
      case 34:
 if ( !player )
     return;
 if (!player->cards[it_yellowcard] &&
     !player->cards[it_yellowskull])
 {
     player->message = "You need a yellow key to open this door";
     S_StartSound(((void *)0),sfx_oof);
     return;
 }
 break;
      case 28:
      case 33:
 if ( !player )
     return;
 if (!player->cards[it_redcard] && !player->cards[it_redskull])
 {
     player->message = "You need a red key to open this door";
     S_StartSound(((void *)0),sfx_oof);
     return;
 }
 break;
    }
    sec = sides[ line->sidenum[side^1]] .sector;
    secnum = sec-sectors;
    if (sec->specialdata)
    {
 door = sec->specialdata;
 switch(line->special)
 {
   case 1:
   case 26:
   case 27:
   case 28:
   case 117:
     if (door->direction == -1)
  door->direction = 1;
     else
     {
  if (!thing->player)
      return;
  door->direction = -1;
     }
     return;
 }
    }
    switch(line->special)
    {
      case 117:
      case 118:
 S_StartSound((mobj_t *)&sec->soundorg,sfx_bdopn);
 break;
      case 1:
      case 31:
 S_StartSound((mobj_t *)&sec->soundorg,sfx_doropn);
 break;
      default:
 S_StartSound((mobj_t *)&sec->soundorg,sfx_doropn);
 break;
    }
    door = Z_Malloc (sizeof(*door), 51, 0);
    P_AddThinker (&door->thinker);
    sec->specialdata = door;
    door->thinker.function.acp1 = (actionf_p1) T_VerticalDoor;
    door->sector = sec;
    door->direction = 1;
    door->speed = (1<<16)*2;
    door->topwait = 150;
    switch(line->special)
    {
      case 1:
      case 26:
      case 27:
      case 28:
 door->type = normal;
 break;
      case 31:
      case 32:
      case 33:
      case 34:
 door->type = open;
 line->special = 0;
 break;
      case 117:
 door->type = blazeRaise;
 door->speed = (1<<16)*2*4;
 break;
      case 118:
 door->type = blazeOpen;
 line->special = 0;
 door->speed = (1<<16)*2*4;
 break;
    }
    door->topheight = P_FindLowestCeilingSurrounding(sec);
    door->topheight -= 4*(1<<16);
}
