void A_BossDeath (mobj_t* mo)
{
    thinker_t* th;
    mobj_t* mo2;
    line_t junk;
    int i;
    if ( gamemode == commercial)
    {
 if (gamemap != 7)
     return;
 if ((mo->type != MT_FATSO)
     && (mo->type != MT_BABY))
     return;
    }
    else
    {
 switch(gameepisode)
 {
   case 1:
     if (gamemap != 8)
  return;
     if (mo->type != MT_BRUISER)
  return;
     break;
   case 2:
     if (gamemap != 8)
  return;
     if (mo->type != MT_CYBORG)
  return;
     break;
   case 3:
     if (gamemap != 8)
  return;
     if (mo->type != MT_SPIDER)
  return;
     break;
   case 4:
     switch(gamemap)
     {
       case 6:
  if (mo->type != MT_CYBORG)
      return;
  break;
       case 8:
  if (mo->type != MT_SPIDER)
      return;
  break;
       default:
  return;
  break;
     }
     break;
   default:
     if (gamemap != 8)
  return;
     break;
 }
    }
    for (i=0 ; i<4 ; i++)
 if (playeringame[i] && players[i].health > 0)
     break;
    if (i==4)
 return;
    for (th = thinkercap.next ; th != &thinkercap ; th=th->next)
    {
 if (th->function.acp1 != (actionf_p1)P_MobjThinker)
     continue;
 mo2 = (mobj_t *)th;
 if (mo2 != mo
     && mo2->type == mo->type
     && mo2->health > 0)
 {
     return;
 }
    }
    if ( gamemode == commercial)
    {
 if (gamemap == 7)
 {
     if (mo->type == MT_FATSO)
     {
  junk.tag = 666;
  EV_DoFloor(&junk,lowerFloorToLowest);
  return;
     }
     if (mo->type == MT_BABY)
     {
  junk.tag = 667;
  EV_DoFloor(&junk,raiseToTexture);
  return;
     }
 }
    }
    else
    {
 switch(gameepisode)
 {
   case 1:
     junk.tag = 666;
     EV_DoFloor (&junk, lowerFloorToLowest);
     return;
     break;
   case 4:
     switch(gamemap)
     {
       case 6:
  junk.tag = 666;
  EV_DoDoor (&junk, blazeOpen);
  return;
  break;
       case 8:
  junk.tag = 666;
  EV_DoFloor (&junk, lowerFloorToLowest);
  return;
  break;
     }
 }
    }
    G_ExitLevel ();
}
