void A_SpawnFly (mobj_t* mo)
{
    mobj_t* newmobj;
    mobj_t* fog;
    mobj_t* targ;
    int r;
    mobjtype_t type;
    if (--mo->reactiontime)
 return;
    targ = mo->target;
    fog = P_SpawnMobj (targ->x, targ->y, targ->z, MT_SPAWNFIRE);
    S_StartSound (fog, sfx_telept);
    r = P_Random ();
    if ( r<50 )
 type = MT_TROOP;
    else if (r<90)
 type = MT_SERGEANT;
    else if (r<120)
 type = MT_SHADOWS;
    else if (r<130)
 type = MT_PAIN;
    else if (r<160)
 type = MT_HEAD;
    else if (r<162)
 type = MT_VILE;
    else if (r<172)
 type = MT_UNDEAD;
    else if (r<192)
 type = MT_BABY;
    else if (r<222)
 type = MT_FATSO;
    else if (r<246)
 type = MT_KNIGHT;
    else
 type = MT_BRUISER;
    newmobj = P_SpawnMobj (targ->x, targ->y, targ->z, type);
    if (P_LookForPlayers (newmobj, true) )
 P_SetMobjState (newmobj, newmobj->info->seestate);
    P_TeleportMove (newmobj, newmobj->x, newmobj->y);
    P_RemoveMobj (mo);
}
