static const char
rcsid[] = "$Id: p_floor.c,v 1.4 1997/02/03 16:47:54 b1 Exp $";
result_e
T_MovePlane
( sector_t* sector,
  fixed_t speed,
  fixed_t dest,
  boolean crush,
  int floorOrCeiling,
  int direction )
{
    boolean flag;
    fixed_t lastpos;
    switch(floorOrCeiling)
    {
      case 0:
 switch(direction)
 {
   case -1:
     if (sector->floorheight - speed < dest)
     {
  lastpos = sector->floorheight;
  sector->floorheight = dest;
  flag = P_ChangeSector(sector,crush);
  if (flag == true)
  {
      sector->floorheight =lastpos;
      P_ChangeSector(sector,crush);
  }
  return pastdest;
     }
     else
     {
  lastpos = sector->floorheight;
  sector->floorheight -= speed;
  flag = P_ChangeSector(sector,crush);
  if (flag == true)
  {
      sector->floorheight = lastpos;
      P_ChangeSector(sector,crush);
      return crushed;
  }
     }
     break;
   case 1:
     if (sector->floorheight + speed > dest)
     {
  lastpos = sector->floorheight;
  sector->floorheight = dest;
  flag = P_ChangeSector(sector,crush);
  if (flag == true)
  {
      sector->floorheight = lastpos;
      P_ChangeSector(sector,crush);
  }
  return pastdest;
     }
     else
     {
  lastpos = sector->floorheight;
  sector->floorheight += speed;
  flag = P_ChangeSector(sector,crush);
  if (flag == true)
  {
      if (crush == true)
   return crushed;
      sector->floorheight = lastpos;
      P_ChangeSector(sector,crush);
      return crushed;
  }
     }
     break;
 }
 break;
      case 1:
 switch(direction)
 {
   case -1:
     if (sector->ceilingheight - speed < dest)
     {
  lastpos = sector->ceilingheight;
  sector->ceilingheight = dest;
  flag = P_ChangeSector(sector,crush);
  if (flag == true)
  {
      sector->ceilingheight = lastpos;
      P_ChangeSector(sector,crush);
  }
  return pastdest;
     }
     else
     {
  lastpos = sector->ceilingheight;
  sector->ceilingheight -= speed;
  flag = P_ChangeSector(sector,crush);
  if (flag == true)
  {
      if (crush == true)
   return crushed;
      sector->ceilingheight = lastpos;
      P_ChangeSector(sector,crush);
      return crushed;
  }
     }
     break;
   case 1:
     if (sector->ceilingheight + speed > dest)
     {
  lastpos = sector->ceilingheight;
  sector->ceilingheight = dest;
  flag = P_ChangeSector(sector,crush);
  if (flag == true)
  {
      sector->ceilingheight = lastpos;
      P_ChangeSector(sector,crush);
  }
  return pastdest;
     }
     else
     {
  lastpos = sector->ceilingheight;
  sector->ceilingheight += speed;
  flag = P_ChangeSector(sector,crush);
     }
     break;
 }
 break;
    }
    return ok;
}
void T_MoveFloor(floormove_t* floor)
{
    result_e res;
    res = T_MovePlane(floor->sector,
        floor->speed,
        floor->floordestheight,
        floor->crush,0,floor->direction);
    if (!(leveltime&7))
 S_StartSound((mobj_t *)&floor->sector->soundorg,
       sfx_stnmov);
    if (res == pastdest)
    {
 floor->sector->specialdata = ((void *)0);
 if (floor->direction == 1)
 {
     switch(floor->type)
     {
       case donutRaise:
  floor->sector->special = floor->newspecial;
  floor->sector->floorpic = floor->texture;
       default:
  break;
     }
 }
 else if (floor->direction == -1)
 {
     switch(floor->type)
     {
       case lowerAndChange:
  floor->sector->special = floor->newspecial;
  floor->sector->floorpic = floor->texture;
       default:
  break;
     }
 }
 P_RemoveThinker(&floor->thinker);
 S_StartSound((mobj_t *)&floor->sector->soundorg,
       sfx_pstop);
    }
}
int
EV_DoFloor
( line_t* line,
  floor_e floortype )
{
    int secnum;
    int rtn;
    int i;
    sector_t* sec;
    floormove_t* floor;
    secnum = -1;
    rtn = 0;
    while ((secnum = P_FindSectorFromLineTag(line,secnum)) >= 0)
    {
 sec = &sectors[secnum];
 if (sec->specialdata)
     continue;
 rtn = 1;
 floor = Z_Malloc (sizeof(*floor), 51, 0);
 P_AddThinker (&floor->thinker);
 sec->specialdata = floor;
 floor->thinker.function.acp1 = (actionf_p1) T_MoveFloor;
 floor->type = floortype;
 floor->crush = false;
 switch(floortype)
 {
   case lowerFloor:
     floor->direction = -1;
     floor->sector = sec;
     floor->speed = (1<<16);
     floor->floordestheight =
  P_FindHighestFloorSurrounding(sec);
     break;
   case lowerFloorToLowest:
     floor->direction = -1;
     floor->sector = sec;
     floor->speed = (1<<16);
     floor->floordestheight =
  P_FindLowestFloorSurrounding(sec);
     break;
   case turboLower:
     floor->direction = -1;
     floor->sector = sec;
     floor->speed = (1<<16) * 4;
     floor->floordestheight =
  P_FindHighestFloorSurrounding(sec);
     if (floor->floordestheight != sec->floorheight)
  floor->floordestheight += 8*(1<<16);
     break;
   case raiseFloorCrush:
     floor->crush = true;
   case raiseFloor:
     floor->direction = 1;
     floor->sector = sec;
     floor->speed = (1<<16);
     floor->floordestheight =
  P_FindLowestCeilingSurrounding(sec);
     if (floor->floordestheight > sec->ceilingheight)
  floor->floordestheight = sec->ceilingheight;
     floor->floordestheight -= (8*(1<<16))*
  (floortype == raiseFloorCrush);
     break;
   case raiseFloorTurbo:
     floor->direction = 1;
     floor->sector = sec;
     floor->speed = (1<<16)*4;
     floor->floordestheight =
  P_FindNextHighestFloor(sec,sec->floorheight);
     break;
   case raiseFloorToNearest:
     floor->direction = 1;
     floor->sector = sec;
     floor->speed = (1<<16);
     floor->floordestheight =
  P_FindNextHighestFloor(sec,sec->floorheight);
     break;
   case raiseFloor24:
     floor->direction = 1;
     floor->sector = sec;
     floor->speed = (1<<16);
     floor->floordestheight = floor->sector->floorheight +
  24 * (1<<16);
     break;
   case raiseFloor512:
     floor->direction = 1;
     floor->sector = sec;
     floor->speed = (1<<16);
     floor->floordestheight = floor->sector->floorheight +
  512 * (1<<16);
     break;
   case raiseFloor24AndChange:
     floor->direction = 1;
     floor->sector = sec;
     floor->speed = (1<<16);
     floor->floordestheight = floor->sector->floorheight +
  24 * (1<<16);
     sec->floorpic = line->frontsector->floorpic;
     sec->special = line->frontsector->special;
     break;
   case raiseToTexture:
   {
       int minsize = 0x7fffffff;
       side_t* side;
       floor->direction = 1;
       floor->sector = sec;
       floor->speed = (1<<16);
       for (i = 0; i < sec->linecount; i++)
       {
    if (twoSided (secnum, i) )
    {
        side = getSide(secnum,i,0);
        if (side->bottomtexture >= 0)
     if (textureheight[side->bottomtexture] <
         minsize)
         minsize =
      textureheight[side->bottomtexture];
        side = getSide(secnum,i,1);
        if (side->bottomtexture >= 0)
     if (textureheight[side->bottomtexture] <
         minsize)
         minsize =
      textureheight[side->bottomtexture];
    }
       }
       floor->floordestheight =
    floor->sector->floorheight + minsize;
   }
   break;
   case lowerAndChange:
     floor->direction = -1;
     floor->sector = sec;
     floor->speed = (1<<16);
     floor->floordestheight =
  P_FindLowestFloorSurrounding(sec);
     floor->texture = sec->floorpic;
     for (i = 0; i < sec->linecount; i++)
     {
  if ( twoSided(secnum, i) )
  {
      if (getSide(secnum,i,0)->sector-sectors == secnum)
      {
   sec = getSector(secnum,i,1);
   if (sec->floorheight == floor->floordestheight)
   {
       floor->texture = sec->floorpic;
       floor->newspecial = sec->special;
       break;
   }
      }
      else
      {
   sec = getSector(secnum,i,0);
   if (sec->floorheight == floor->floordestheight)
   {
       floor->texture = sec->floorpic;
       floor->newspecial = sec->special;
       break;
   }
      }
  }
     }
   default:
     break;
 }
    }
    return rtn;
}
int
EV_BuildStairs
( line_t* line,
  stair_e type )
{
    int secnum;
    int height;
    int i;
    int newsecnum;
    int texture;
    int ok;
    int rtn;
    sector_t* sec;
    sector_t* tsec;
    floormove_t* floor;
    fixed_t stairsize;
    fixed_t speed;
    secnum = -1;
    rtn = 0;
    while ((secnum = P_FindSectorFromLineTag(line,secnum)) >= 0)
    {
 sec = &sectors[secnum];
 if (sec->specialdata)
     continue;
 rtn = 1;
 floor = Z_Malloc (sizeof(*floor), 51, 0);
 P_AddThinker (&floor->thinker);
 sec->specialdata = floor;
 floor->thinker.function.acp1 = (actionf_p1) T_MoveFloor;
 floor->direction = 1;
 floor->sector = sec;
 switch(type)
 {
   case build8:
     speed = (1<<16)/4;
     stairsize = 8*(1<<16);
     break;
   case turbo16:
     speed = (1<<16)*4;
     stairsize = 16*(1<<16);
     break;
 }
 floor->speed = speed;
 height = sec->floorheight + stairsize;
 floor->floordestheight = height;
 texture = sec->floorpic;
 do
 {
     ok = 0;
     for (i = 0;i < sec->linecount;i++)
     {
  if ( !((sec->lines[i])->flags & 4) )
      continue;
  tsec = (sec->lines[i])->frontsector;
  newsecnum = tsec-sectors;
  if (secnum != newsecnum)
      continue;
  tsec = (sec->lines[i])->backsector;
  newsecnum = tsec - sectors;
  if (tsec->floorpic != texture)
      continue;
  height += stairsize;
  if (tsec->specialdata)
      continue;
  sec = tsec;
  secnum = newsecnum;
  floor = Z_Malloc (sizeof(*floor), 51, 0);
  P_AddThinker (&floor->thinker);
  sec->specialdata = floor;
  floor->thinker.function.acp1 = (actionf_p1) T_MoveFloor;
  floor->direction = 1;
  floor->sector = sec;
  floor->speed = speed;
  floor->floordestheight = height;
  ok = 1;
  break;
     }
 } while(ok);
    }
    return rtn;
}
static const char
rcsid[] = "$Id: p_inter.c,v 1.4 1997/02/03 22:45:11 b1 Exp $";
boolean P_GivePower(player_t*, int);
int maxammo[NUMAMMO] = {200, 50, 300, 50};
int clipammo[NUMAMMO] = {10, 4, 20, 1};
boolean
P_GiveAmmo
( player_t* player,
  ammotype_t ammo,
  int num )
{
    int oldammo;
    if (ammo == am_noammo)
 return false;
    if (ammo < 0 || ammo > NUMAMMO)
 I_Error ("P_GiveAmmo: bad type %i", ammo);
    if ( player->ammo[ammo] == player->maxammo[ammo] )
 return false;
    if (num)
 num *= clipammo[ammo];
    else
 num = clipammo[ammo]/2;
    if (gameskill == sk_baby
 || gameskill == sk_nightmare)
    {
 num <<= 1;
    }
    oldammo = player->ammo[ammo];
    player->ammo[ammo] += num;
    if (player->ammo[ammo] > player->maxammo[ammo])
 player->ammo[ammo] = player->maxammo[ammo];
    if (oldammo)
 return true;
    switch (ammo)
    {
      case am_clip:
 if (player->readyweapon == wp_fist)
 {
     if (player->weaponowned[wp_chaingun])
  player->pendingweapon = wp_chaingun;
     else
  player->pendingweapon = wp_pistol;
 }
 break;
      case am_shell:
 if (player->readyweapon == wp_fist
     || player->readyweapon == wp_pistol)
 {
     if (player->weaponowned[wp_shotgun])
  player->pendingweapon = wp_shotgun;
 }
 break;
      case am_cell:
 if (player->readyweapon == wp_fist
     || player->readyweapon == wp_pistol)
 {
     if (player->weaponowned[wp_plasma])
  player->pendingweapon = wp_plasma;
 }
 break;
      case am_misl:
 if (player->readyweapon == wp_fist)
 {
     if (player->weaponowned[wp_missile])
  player->pendingweapon = wp_missile;
 }
      default:
 break;
    }
    return true;
}
boolean
P_GiveWeapon
( player_t* player,
  weapontype_t weapon,
  boolean dropped )
{
    boolean gaveammo;
    boolean gaveweapon;
    if (netgame
 && (deathmatch!=2)
  && !dropped )
    {
 if (player->weaponowned[weapon])
     return false;
 player->bonuscount += 6;
 player->weaponowned[weapon] = true;
 if (deathmatch)
     P_GiveAmmo (player, weaponinfo[weapon].ammo, 5);
 else
     P_GiveAmmo (player, weaponinfo[weapon].ammo, 2);
 player->pendingweapon = weapon;
 if (player == &players[consoleplayer])
     S_StartSound (((void *)0), sfx_wpnup);
 return false;
    }
    if (weaponinfo[weapon].ammo != am_noammo)
    {
 if (dropped)
     gaveammo = P_GiveAmmo (player, weaponinfo[weapon].ammo, 1);
 else
     gaveammo = P_GiveAmmo (player, weaponinfo[weapon].ammo, 2);
    }
    else
 gaveammo = false;
    if (player->weaponowned[weapon])
 gaveweapon = false;
    else
    {
 gaveweapon = true;
 player->weaponowned[weapon] = true;
 player->pendingweapon = weapon;
    }
    return (gaveweapon || gaveammo);
}
boolean
P_GiveBody
( player_t* player,
  int num )
{
    if (player->health >= 100)
 return false;
    player->health += num;
    if (player->health > 100)
 player->health = 100;
    player->mo->health = player->health;
    return true;
}
boolean
P_GiveArmor
( player_t* player,
  int armortype )
{
    int hits;
    hits = armortype*100;
    if (player->armorpoints >= hits)
 return false;
    player->armortype = armortype;
    player->armorpoints = hits;
    return true;
}
void
P_GiveCard
( player_t* player,
  card_t card )
{
    if (player->cards[card])
 return;
    player->bonuscount = 6;
    player->cards[card] = 1;
}
boolean
P_GivePower
( player_t* player,
  int power )
{
    if (power == pw_invulnerability)
    {
 player->powers[power] = INVULNTICS;
 return true;
    }
    if (power == pw_invisibility)
    {
 player->powers[power] = INVISTICS;
 player->mo->flags |= MF_SHADOW;
 return true;
    }
    if (power == pw_infrared)
    {
 player->powers[power] = INFRATICS;
 return true;
    }
    if (power == pw_ironfeet)
    {
 player->powers[power] = IRONTICS;
 return true;
    }
    if (power == pw_strength)
    {
 P_GiveBody (player, 100);
 player->powers[power] = 1;
 return true;
    }
    if (player->powers[power])
 return false;
    player->powers[power] = 1;
    return true;
}
