void
P_KillMobj
( mobj_t* source,
  mobj_t* target )
{
    mobjtype_t item;
    mobj_t* mo;
    target->flags &= ~(MF_SHOOTABLE|MF_FLOAT|MF_SKULLFLY);
    if (target->type != MT_SKULL)
 target->flags &= ~MF_NOGRAVITY;
    target->flags |= MF_CORPSE|MF_DROPOFF;
    target->height >>= 2;
    if (source && source->player)
    {
 if (target->flags & MF_COUNTKILL)
     source->player->killcount++;
 if (target->player)
     source->player->frags[target->player-players]++;
    }
    else if (!netgame && (target->flags & MF_COUNTKILL) )
    {
 players[0].killcount++;
    }
    if (target->player)
    {
 if (!source)
     target->player->frags[target->player-players]++;
 target->flags &= ~MF_SOLID;
 target->player->playerstate = PST_DEAD;
 P_DropWeapon (target->player);
 if (target->player == &players[consoleplayer]
     && automapactive)
 {
     AM_Stop ();
 }
    }
    if (target->health < -target->info->spawnhealth
 && target->info->xdeathstate)
    {
 P_SetMobjState (target, target->info->xdeathstate);
    }
    else
 P_SetMobjState (target, target->info->deathstate);
    target->tics -= P_Random()&3;
    if (target->tics < 1)
 target->tics = 1;
    switch (target->type)
    {
      case MT_WOLFSS:
      case MT_POSSESSED:
 item = MT_CLIP;
 break;
      case MT_SHOTGUY:
 item = MT_SHOTGUN;
 break;
      case MT_CHAINGUY:
 item = MT_CHAINGUN;
 break;
      default:
 return;
    }
    mo = P_SpawnMobj (target->x,target->y,(-0x7fffffff - 1), item);
    mo->flags |= MF_DROPPED;
}
void
P_DamageMobj
( mobj_t* target,
  mobj_t* inflictor,
  mobj_t* source,
  int damage )
{
    unsigned ang;
    int saved;
    player_t* player;
    fixed_t thrust;
    int temp;
    if ( !(target->flags & MF_SHOOTABLE) )
 return;
    if (target->health <= 0)
 return;
    if ( target->flags & MF_SKULLFLY )
    {
 target->momx = target->momy = target->momz = 0;
    }
    player = target->player;
    if (player && gameskill == sk_baby)
 damage >>= 1;
    if (inflictor
 && !(target->flags & MF_NOCLIP)
 && (!source
     || !source->player
     || source->player->readyweapon != wp_chainsaw))
    {
 ang = R_PointToAngle2 ( inflictor->x,
    inflictor->y,
    target->x,
    target->y);
 thrust = damage*((1<<16)>>3)*100/target->info->mass;
 if ( damage < 40
      && damage > target->health
      && target->z - inflictor->z > 64*(1<<16)
      && (P_Random ()&1) )
 {
     ang += 0x80000000;
     thrust *= 4;
 }
 ang >>= 19;
 target->momx += FixedMul (thrust, finecosine[ang]);
 target->momy += FixedMul (thrust, finesine[ang]);
    }
    if (player)
    {
 if (target->subsector->sector->special == 11
     && damage >= target->health)
 {
     damage = target->health - 1;
 }
 if ( damage < 1000
      && ( (player->cheats&CF_GODMODE)
    || player->powers[pw_invulnerability] ) )
 {
     return;
 }
 if (player->armortype)
 {
     if (player->armortype == 1)
  saved = damage/3;
     else
  saved = damage/2;
     if (player->armorpoints <= saved)
     {
  saved = player->armorpoints;
  player->armortype = 0;
     }
     player->armorpoints -= saved;
     damage -= saved;
 }
 player->health -= damage;
 if (player->health < 0)
     player->health = 0;
 player->attacker = source;
 player->damagecount += damage;
 if (player->damagecount > 100)
     player->damagecount = 100;
 temp = damage < 100 ? damage : 100;
 if (player == &players[consoleplayer])
     I_Tactile (40,10,40+temp*2);
    }
    target->health -= damage;
    if (target->health <= 0)
    {
 P_KillMobj (source, target);
 return;
    }
    if ( (P_Random () < target->info->painchance)
  && !(target->flags&MF_SKULLFLY) )
    {
 target->flags |= MF_JUSTHIT;
 P_SetMobjState (target, target->info->painstate);
    }
    target->reactiontime = 0;
    if ( (!target->threshold || target->type == MT_VILE)
  && source && source != target
  && source->type != MT_VILE)
    {
 target->target = source;
 target->threshold = 100;
 if (target->state == &states[target->info->spawnstate]
     && target->info->seestate != S_NULL)
     P_SetMobjState (target, target->info->seestate);
    }
}
static const char
rcsid[] = "$Id: p_lights.c,v 1.5 1997/02/03 22:45:11 b1 Exp $";
void T_FireFlicker (fireflicker_t* flick)
{
    int amount;
    if (--flick->count)
 return;
    amount = (P_Random()&3)*16;
    if (flick->sector->lightlevel - amount < flick->minlight)
 flick->sector->lightlevel = flick->minlight;
    else
 flick->sector->lightlevel = flick->maxlight - amount;
    flick->count = 4;
}
void P_SpawnFireFlicker (sector_t* sector)
{
    fireflicker_t* flick;
    sector->special = 0;
    flick = Z_Malloc ( sizeof(*flick), 51, 0);
    P_AddThinker (&flick->thinker);
    flick->thinker.function.acp1 = (actionf_p1) T_FireFlicker;
    flick->sector = sector;
    flick->maxlight = sector->lightlevel;
    flick->minlight = P_FindMinSurroundingLight(sector,sector->lightlevel)+16;
    flick->count = 4;
}
void T_LightFlash (lightflash_t* flash)
{
    if (--flash->count)
 return;
    if (flash->sector->lightlevel == flash->maxlight)
    {
 flash-> sector->lightlevel = flash->minlight;
 flash->count = (P_Random()&flash->mintime)+1;
    }
    else
    {
 flash-> sector->lightlevel = flash->maxlight;
 flash->count = (P_Random()&flash->maxtime)+1;
    }
}
void P_SpawnLightFlash (sector_t* sector)
{
    lightflash_t* flash;
    sector->special = 0;
    flash = Z_Malloc ( sizeof(*flash), 51, 0);
    P_AddThinker (&flash->thinker);
    flash->thinker.function.acp1 = (actionf_p1) T_LightFlash;
    flash->sector = sector;
    flash->maxlight = sector->lightlevel;
    flash->minlight = P_FindMinSurroundingLight(sector,sector->lightlevel);
    flash->maxtime = 64;
    flash->mintime = 7;
    flash->count = (P_Random()&flash->maxtime)+1;
}
void T_StrobeFlash (strobe_t* flash)
{
    if (--flash->count)
 return;
    if (flash->sector->lightlevel == flash->minlight)
    {
 flash-> sector->lightlevel = flash->maxlight;
 flash->count = flash->brighttime;
    }
    else
    {
 flash-> sector->lightlevel = flash->minlight;
 flash->count =flash->darktime;
    }
}
void
P_SpawnStrobeFlash
( sector_t* sector,
  int fastOrSlow,
  int inSync )
{
    strobe_t* flash;
    flash = Z_Malloc ( sizeof(*flash), 51, 0);
    P_AddThinker (&flash->thinker);
    flash->sector = sector;
    flash->darktime = fastOrSlow;
    flash->brighttime = 5;
    flash->thinker.function.acp1 = (actionf_p1) T_StrobeFlash;
    flash->maxlight = sector->lightlevel;
    flash->minlight = P_FindMinSurroundingLight(sector, sector->lightlevel);
    if (flash->minlight == flash->maxlight)
 flash->minlight = 0;
    sector->special = 0;
    if (!inSync)
 flash->count = (P_Random()&7)+1;
    else
 flash->count = 1;
}
void EV_StartLightStrobing(line_t* line)
{
    int secnum;
    sector_t* sec;
    secnum = -1;
    while ((secnum = P_FindSectorFromLineTag(line,secnum)) >= 0)
    {
 sec = &sectors[secnum];
 if (sec->specialdata)
     continue;
 P_SpawnStrobeFlash (sec,35, 0);
    }
}
void EV_TurnTagLightsOff(line_t* line)
{
    int i;
    int j;
    int min;
    sector_t* sector;
    sector_t* tsec;
    line_t* templine;
    sector = sectors;
    for (j = 0;j < numsectors; j++, sector++)
    {
 if (sector->tag == line->tag)
 {
     min = sector->lightlevel;
     for (i = 0;i < sector->linecount; i++)
     {
  templine = sector->lines[i];
  tsec = getNextSector(templine,sector);
  if (!tsec)
      continue;
  if (tsec->lightlevel < min)
      min = tsec->lightlevel;
     }
     sector->lightlevel = min;
 }
    }
}
void
EV_LightTurnOn
( line_t* line,
  int bright )
{
    int i;
    int j;
    sector_t* sector;
    sector_t* temp;
    line_t* templine;
    sector = sectors;
    for (i=0;i<numsectors;i++, sector++)
    {
 if (sector->tag == line->tag)
 {
     if (!bright)
     {
  for (j = 0;j < sector->linecount; j++)
  {
      templine = sector->lines[j];
      temp = getNextSector(templine,sector);
      if (!temp)
   continue;
      if (temp->lightlevel > bright)
   bright = temp->lightlevel;
  }
     }
     sector-> lightlevel = bright;
 }
    }
}
void T_Glow(glow_t* g)
{
    switch(g->direction)
    {
      case -1:
 g->sector->lightlevel -= 8;
 if (g->sector->lightlevel <= g->minlight)
 {
     g->sector->lightlevel += 8;
     g->direction = 1;
 }
 break;
      case 1:
 g->sector->lightlevel += 8;
 if (g->sector->lightlevel >= g->maxlight)
 {
     g->sector->lightlevel -= 8;
     g->direction = -1;
 }
 break;
    }
}
void P_SpawnGlowingLight(sector_t* sector)
{
    glow_t* g;
    g = Z_Malloc( sizeof(*g), 51, 0);
    P_AddThinker(&g->thinker);
    g->sector = sector;
    g->minlight = P_FindMinSurroundingLight(sector,sector->lightlevel);
    g->maxlight = sector->lightlevel;
    g->thinker.function.acp1 = (actionf_p1) T_Glow;
    g->direction = -1;
    sector->special = 0;
}
static const char
rcsid[] = "$Id: p_map.c,v 1.5 1997/02/03 22:45:11 b1 Exp $";
fixed_t tmbbox[4];
mobj_t* tmthing;
int tmflags;
fixed_t tmx;
fixed_t tmy;
boolean floatok;
