fixed_t tmceilingz;
fixed_t tmdropoffz;
line_t* ceilingline;
line_t* spechit[8];
int numspechit;
boolean PIT_StompThing (mobj_t* thing)
{
    fixed_t blockdist;
    if (!(thing->flags & MF_SHOOTABLE) )
 return true;
    blockdist = thing->radius + tmthing->radius;
    if ( abs(thing->x - tmx) >= blockdist
  || abs(thing->y - tmy) >= blockdist )
    {
 return true;
    }
    if (thing == tmthing)
 return true;
    if ( !tmthing->player && gamemap != 30)
 return false;
    P_DamageMobj (thing, tmthing, tmthing, 10000);
    return true;
}
boolean
P_TeleportMove
( mobj_t* thing,
  fixed_t x,
  fixed_t y )
{
    int xl;
    int xh;
    int yl;
    int yh;
    int bx;
    int by;
    subsector_t* newsubsec;
    tmthing = thing;
    tmflags = thing->flags;
    tmx = x;
    tmy = y;
    tmbbox[BOXTOP] = y + tmthing->radius;
    tmbbox[BOXBOTTOM] = y - tmthing->radius;
    tmbbox[BOXRIGHT] = x + tmthing->radius;
    tmbbox[BOXLEFT] = x - tmthing->radius;
    newsubsec = R_PointInSubsector (x,y);
    ceilingline = ((void *)0);
    tmfloorz = tmdropoffz = newsubsec->sector->floorheight;
    tmceilingz = newsubsec->sector->ceilingheight;
    validcount++;
    numspechit = 0;
    xl = (tmbbox[BOXLEFT] - bmaporgx - 32*(1<<16))>>(16 +7);
    xh = (tmbbox[BOXRIGHT] - bmaporgx + 32*(1<<16))>>(16 +7);
    yl = (tmbbox[BOXBOTTOM] - bmaporgy - 32*(1<<16))>>(16 +7);
    yh = (tmbbox[BOXTOP] - bmaporgy + 32*(1<<16))>>(16 +7);
    for (bx=xl ; bx<=xh ; bx++)
 for (by=yl ; by<=yh ; by++)
     if (!P_BlockThingsIterator(bx,by,PIT_StompThing))
  return false;
    P_UnsetThingPosition (thing);
    thing->floorz = tmfloorz;
    thing->ceilingz = tmceilingz;
    thing->x = x;
    thing->y = y;
    P_SetThingPosition (thing);
    return true;
}
boolean PIT_CheckLine (line_t* ld)
{
    if (tmbbox[BOXRIGHT] <= ld->bbox[BOXLEFT]
 || tmbbox[BOXLEFT] >= ld->bbox[BOXRIGHT]
 || tmbbox[BOXTOP] <= ld->bbox[BOXBOTTOM]
 || tmbbox[BOXBOTTOM] >= ld->bbox[BOXTOP] )
 return true;
    if (P_BoxOnLineSide (tmbbox, ld) != -1)
 return true;
    if (!ld->backsector)
 return false;
    if (!(tmthing->flags & MF_MISSILE) )
    {
 if ( ld->flags & 1 )
     return false;
 if ( !tmthing->player && ld->flags & 2 )
     return false;
    }
    P_LineOpening (ld);
    if (opentop < tmceilingz)
    {
 tmceilingz = opentop;
 ceilingline = ld;
    }
    if (openbottom > tmfloorz)
 tmfloorz = openbottom;
    if (lowfloor < tmdropoffz)
 tmdropoffz = lowfloor;
    if (ld->special)
    {
 spechit[numspechit] = ld;
 numspechit++;
    }
    return true;
}
boolean PIT_CheckThing (mobj_t* thing)
{
    fixed_t blockdist;
    boolean solid;
    int damage;
    if (!(thing->flags & (MF_SOLID|MF_SPECIAL|MF_SHOOTABLE) ))
 return true;
    blockdist = thing->radius + tmthing->radius;
    if ( abs(thing->x - tmx) >= blockdist
  || abs(thing->y - tmy) >= blockdist )
    {
 return true;
    }
    if (thing == tmthing)
 return true;
    if (tmthing->flags & MF_SKULLFLY)
    {
 damage = ((P_Random()%8)+1)*tmthing->info->damage;
 P_DamageMobj (thing, tmthing, tmthing, damage);
 tmthing->flags &= ~MF_SKULLFLY;
 tmthing->momx = tmthing->momy = tmthing->momz = 0;
 P_SetMobjState (tmthing, tmthing->info->spawnstate);
 return false;
    }
    if (tmthing->flags & MF_MISSILE)
    {
 if (tmthing->z > thing->z + thing->height)
     return true;
 if (tmthing->z+tmthing->height < thing->z)
     return true;
 if (tmthing->target && (
     tmthing->target->type == thing->type ||
     (tmthing->target->type == MT_KNIGHT && thing->type == MT_BRUISER)||
     (tmthing->target->type == MT_BRUISER && thing->type == MT_KNIGHT) ) )
 {
     if (thing == tmthing->target)
  return true;
     if (thing->type != MT_PLAYER)
     {
  return false;
     }
 }
 if (! (thing->flags & MF_SHOOTABLE) )
 {
     return !(thing->flags & MF_SOLID);
 }
 damage = ((P_Random()%8)+1)*tmthing->info->damage;
 P_DamageMobj (thing, tmthing, tmthing->target, damage);
 return false;
    }
    if (thing->flags & MF_SPECIAL)
    {
 solid = thing->flags&MF_SOLID;
 if (tmflags&MF_PICKUP)
 {
     P_TouchSpecialThing (thing, tmthing);
 }
 return !solid;
    }
    return !(thing->flags & MF_SOLID);
}
boolean
P_CheckPosition
( mobj_t* thing,
  fixed_t x,
  fixed_t y )
{
    int xl;
    int xh;
    int yl;
    int yh;
    int bx;
    int by;
    subsector_t* newsubsec;
    tmthing = thing;
    tmflags = thing->flags;
    tmx = x;
    tmy = y;
    tmbbox[BOXTOP] = y + tmthing->radius;
    tmbbox[BOXBOTTOM] = y - tmthing->radius;
    tmbbox[BOXRIGHT] = x + tmthing->radius;
    tmbbox[BOXLEFT] = x - tmthing->radius;
    newsubsec = R_PointInSubsector (x,y);
    ceilingline = ((void *)0);
    tmfloorz = tmdropoffz = newsubsec->sector->floorheight;
    tmceilingz = newsubsec->sector->ceilingheight;
    validcount++;
    numspechit = 0;
    if ( tmflags & MF_NOCLIP )
 return true;
    xl = (tmbbox[BOXLEFT] - bmaporgx - 32*(1<<16))>>(16 +7);
    xh = (tmbbox[BOXRIGHT] - bmaporgx + 32*(1<<16))>>(16 +7);
    yl = (tmbbox[BOXBOTTOM] - bmaporgy - 32*(1<<16))>>(16 +7);
    yh = (tmbbox[BOXTOP] - bmaporgy + 32*(1<<16))>>(16 +7);
    for (bx=xl ; bx<=xh ; bx++)
 for (by=yl ; by<=yh ; by++)
     if (!P_BlockThingsIterator(bx,by,PIT_CheckThing))
  return false;
    xl = (tmbbox[BOXLEFT] - bmaporgx)>>(16 +7);
    xh = (tmbbox[BOXRIGHT] - bmaporgx)>>(16 +7);
    yl = (tmbbox[BOXBOTTOM] - bmaporgy)>>(16 +7);
    yh = (tmbbox[BOXTOP] - bmaporgy)>>(16 +7);
    for (bx=xl ; bx<=xh ; bx++)
 for (by=yl ; by<=yh ; by++)
     if (!P_BlockLinesIterator (bx,by,PIT_CheckLine))
  return false;
    return true;
}
boolean
P_TryMove
( mobj_t* thing,
  fixed_t x,
  fixed_t y )
{
    fixed_t oldx;
    fixed_t oldy;
    int side;
    int oldside;
    line_t* ld;
    floatok = false;
    if (!P_CheckPosition (thing, x, y))
 return false;
    if ( !(thing->flags & MF_NOCLIP) )
    {
 if (tmceilingz - tmfloorz < thing->height)
     return false;
 floatok = true;
 if ( !(thing->flags&MF_TELEPORT)
      &&tmceilingz - thing->z < thing->height)
     return false;
 if ( !(thing->flags&MF_TELEPORT)
      && tmfloorz - thing->z > 24*(1<<16) )
     return false;
 if ( !(thing->flags&(MF_DROPOFF|MF_FLOAT))
      && tmfloorz - tmdropoffz > 24*(1<<16) )
     return false;
    }
    P_UnsetThingPosition (thing);
    oldx = thing->x;
    oldy = thing->y;
    thing->floorz = tmfloorz;
    thing->ceilingz = tmceilingz;
    thing->x = x;
    thing->y = y;
    P_SetThingPosition (thing);
    if (! (thing->flags&(MF_TELEPORT|MF_NOCLIP)) )
    {
 while (numspechit--)
 {
     ld = spechit[numspechit];
     side = P_PointOnLineSide (thing->x, thing->y, ld);
     oldside = P_PointOnLineSide (oldx, oldy, ld);
     if (side != oldside)
     {
  if (ld->special)
      P_CrossSpecialLine (ld-lines, oldside, thing);
     }
 }
    }
    return true;
}
boolean P_ThingHeightClip (mobj_t* thing)
{
    boolean onfloor;
    onfloor = (thing->z == thing->floorz);
    P_CheckPosition (thing, thing->x, thing->y);
    thing->floorz = tmfloorz;
    thing->ceilingz = tmceilingz;
    if (onfloor)
    {
 thing->z = thing->floorz;
    }
    else
    {
 if (thing->z+thing->height > thing->ceilingz)
     thing->z = thing->ceilingz - thing->height;
    }
    if (thing->ceilingz - thing->floorz < thing->height)
 return false;
    return true;
}
fixed_t bestslidefrac;
fixed_t secondslidefrac;
line_t* bestslideline;
line_t* secondslideline;
mobj_t* slidemo;
fixed_t tmxmove;
fixed_t tmymove;
void P_HitSlideLine (line_t* ld)
{
    int side;
    angle_t lineangle;
    angle_t moveangle;
    angle_t deltaangle;
    fixed_t movelen;
    fixed_t newlen;
    if (ld->slopetype == ST_HORIZONTAL)
    {
 tmymove = 0;
 return;
    }
    if (ld->slopetype == ST_VERTICAL)
    {
 tmxmove = 0;
 return;
    }
    side = P_PointOnLineSide (slidemo->x, slidemo->y, ld);
    lineangle = R_PointToAngle2 (0,0, ld->dx, ld->dy);
    if (side == 1)
 lineangle += 0x80000000;
    moveangle = R_PointToAngle2 (0,0, tmxmove, tmymove);
    deltaangle = moveangle-lineangle;
    if (deltaangle > 0x80000000)
 deltaangle += 0x80000000;
    lineangle >>= 19;
    deltaangle >>= 19;
    movelen = P_AproxDistance (tmxmove, tmymove);
    newlen = FixedMul (movelen, finecosine[deltaangle]);
    tmxmove = FixedMul (newlen, finecosine[lineangle]);
    tmymove = FixedMul (newlen, finesine[lineangle]);
}
boolean PTR_SlideTraverse (intercept_t* in)
{
    line_t* li;
    if (!in->isaline)
 I_Error ("PTR_SlideTraverse: not a line?");
    li = in->d.line;
    if ( ! (li->flags & 4) )
    {
 if (P_PointOnLineSide (slidemo->x, slidemo->y, li))
 {
     return true;
 }
 goto isblocking;
    }
    P_LineOpening (li);
    if (openrange < slidemo->height)
 goto isblocking;
    if (opentop - slidemo->z < slidemo->height)
 goto isblocking;
    if (openbottom - slidemo->z > 24*(1<<16) )
 goto isblocking;
    return true;
  isblocking:
    if (in->frac < bestslidefrac)
    {
 secondslidefrac = bestslidefrac;
 secondslideline = bestslideline;
 bestslidefrac = in->frac;
 bestslideline = li;
    }
    return false;
}
void P_SlideMove (mobj_t* mo)
{
    fixed_t leadx;
    fixed_t leady;
    fixed_t trailx;
    fixed_t traily;
    fixed_t newx;
    fixed_t newy;
    int hitcount;
    slidemo = mo;
    hitcount = 0;
  retry:
    if (++hitcount == 3)
 goto stairstep;
    if (mo->momx > 0)
    {
 leadx = mo->x + mo->radius;
 trailx = mo->x - mo->radius;
    }
    else
    {
 leadx = mo->x - mo->radius;
 trailx = mo->x + mo->radius;
    }
    if (mo->momy > 0)
    {
 leady = mo->y + mo->radius;
 traily = mo->y - mo->radius;
    }
    else
    {
 leady = mo->y - mo->radius;
 traily = mo->y + mo->radius;
    }
    bestslidefrac = (1<<16)+1;
    P_PathTraverse ( leadx, leady, leadx+mo->momx, leady+mo->momy,
       1, PTR_SlideTraverse );
    P_PathTraverse ( trailx, leady, trailx+mo->momx, leady+mo->momy,
       1, PTR_SlideTraverse );
    P_PathTraverse ( leadx, traily, leadx+mo->momx, traily+mo->momy,
       1, PTR_SlideTraverse );
    if (bestslidefrac == (1<<16)+1)
    {
      stairstep:
 if (!P_TryMove (mo, mo->x, mo->y + mo->momy))
     P_TryMove (mo, mo->x + mo->momx, mo->y);
 return;
    }
    bestslidefrac -= 0x800;
    if (bestslidefrac > 0)
    {
 newx = FixedMul (mo->momx, bestslidefrac);
 newy = FixedMul (mo->momy, bestslidefrac);
 if (!P_TryMove (mo, mo->x+newx, mo->y+newy))
     goto stairstep;
    }
    bestslidefrac = (1<<16)-(bestslidefrac+0x800);
    if (bestslidefrac > (1<<16))
 bestslidefrac = (1<<16);
    if (bestslidefrac <= 0)
 return;
    tmxmove = FixedMul (mo->momx, bestslidefrac);
    tmymove = FixedMul (mo->momy, bestslidefrac);
    P_HitSlideLine (bestslideline);
    mo->momx = tmxmove;
    mo->momy = tmymove;
    if (!P_TryMove (mo, mo->x+tmxmove, mo->y+tmymove))
    {
 goto retry;
    }
}
mobj_t* linetarget;
mobj_t* shootthing;
fixed_t shootz;
int la_damage;
fixed_t attackrange;
fixed_t aimslope;
extern fixed_t topslope;
extern fixed_t bottomslope;
boolean
PTR_AimTraverse (intercept_t* in)
{
    line_t* li;
    mobj_t* th;
    fixed_t slope;
    fixed_t thingtopslope;
    fixed_t thingbottomslope;
    fixed_t dist;
    if (in->isaline)
    {
 li = in->d.line;
 if ( !(li->flags & 4) )
     return false;
 P_LineOpening (li);
 if (openbottom >= opentop)
     return false;
 dist = FixedMul (attackrange, in->frac);
 if (li->frontsector->floorheight != li->backsector->floorheight)
 {
     slope = FixedDiv (openbottom - shootz , dist);
     if (slope > bottomslope)
  bottomslope = slope;
 }
 if (li->frontsector->ceilingheight != li->backsector->ceilingheight)
 {
     slope = FixedDiv (opentop - shootz , dist);
     if (slope < topslope)
  topslope = slope;
 }
 if (topslope <= bottomslope)
     return false;
 return true;
    }
    th = in->d.thing;
    if (th == shootthing)
 return true;
    if (!(th->flags&MF_SHOOTABLE))
 return true;
    dist = FixedMul (attackrange, in->frac);
    thingtopslope = FixedDiv (th->z+th->height - shootz , dist);
    if (thingtopslope < bottomslope)
 return true;
    thingbottomslope = FixedDiv (th->z - shootz, dist);
    if (thingbottomslope > topslope)
 return true;
    if (thingtopslope > topslope)
 thingtopslope = topslope;
    if (thingbottomslope < bottomslope)
 thingbottomslope = bottomslope;
    aimslope = (thingtopslope+thingbottomslope)/2;
    linetarget = th;
    return false;
}
boolean PTR_ShootTraverse (intercept_t* in)
{
    fixed_t x;
    fixed_t y;
    fixed_t z;
    fixed_t frac;
    line_t* li;
    mobj_t* th;
    fixed_t slope;
    fixed_t dist;
    fixed_t thingtopslope;
    fixed_t thingbottomslope;
    if (in->isaline)
    {
 li = in->d.line;
 if (li->special)
     P_ShootSpecialLine (shootthing, li);
 if ( !(li->flags & 4) )
     goto hitline;
 P_LineOpening (li);
 dist = FixedMul (attackrange, in->frac);
 if (li->frontsector->floorheight != li->backsector->floorheight)
 {
     slope = FixedDiv (openbottom - shootz , dist);
     if (slope > aimslope)
  goto hitline;
 }
 if (li->frontsector->ceilingheight != li->backsector->ceilingheight)
 {
     slope = FixedDiv (opentop - shootz , dist);
     if (slope < aimslope)
  goto hitline;
 }
 return true;
      hitline:
 frac = in->frac - FixedDiv (4*(1<<16),attackrange);
 x = trace.x + FixedMul (trace.dx, frac);
 y = trace.y + FixedMul (trace.dy, frac);
 z = shootz + FixedMul (aimslope, FixedMul(frac, attackrange));
 if (li->frontsector->ceilingpic == skyflatnum)
 {
     if (z > li->frontsector->ceilingheight)
  return false;
     if (li->backsector && li->backsector->ceilingpic == skyflatnum)
  return false;
 }
 P_SpawnPuff (x,y,z);
 return false;
    }
    th = in->d.thing;
    if (th == shootthing)
 return true;
    if (!(th->flags&MF_SHOOTABLE))
 return true;
    dist = FixedMul (attackrange, in->frac);
    thingtopslope = FixedDiv (th->z+th->height - shootz , dist);
    if (thingtopslope < aimslope)
 return true;
    thingbottomslope = FixedDiv (th->z - shootz, dist);
    if (thingbottomslope > aimslope)
 return true;
    frac = in->frac - FixedDiv (10*(1<<16),attackrange);
    x = trace.x + FixedMul (trace.dx, frac);
    y = trace.y + FixedMul (trace.dy, frac);
    z = shootz + FixedMul (aimslope, FixedMul(frac, attackrange));
    if (in->d.thing->flags & MF_NOBLOOD)
 P_SpawnPuff (x,y,z);
    else
 P_SpawnBlood (x,y,z, la_damage);
    if (la_damage)
 P_DamageMobj (th, shootthing, shootthing, la_damage);
    return false;
}
fixed_t
P_AimLineAttack
( mobj_t* t1,
  angle_t angle,
  fixed_t distance )
{
    fixed_t x2;
    fixed_t y2;
    angle >>= 19;
    shootthing = t1;
    x2 = t1->x + (distance>>16)*finecosine[angle];
    y2 = t1->y + (distance>>16)*finesine[angle];
    shootz = t1->z + (t1->height>>1) + 8*(1<<16);
    topslope = 100*(1<<16)/160;
    bottomslope = -100*(1<<16)/160;
    attackrange = distance;
    linetarget = ((void *)0);
    P_PathTraverse ( t1->x, t1->y,
       x2, y2,
       1|2,
       PTR_AimTraverse );
    if (linetarget)
 return aimslope;
    return 0;
}
void
P_LineAttack
( mobj_t* t1,
  angle_t angle,
  fixed_t distance,
  fixed_t slope,
  int damage )
{
    fixed_t x2;
    fixed_t y2;
    angle >>= 19;
    shootthing = t1;
    la_damage = damage;
    x2 = t1->x + (distance>>16)*finecosine[angle];
    y2 = t1->y + (distance>>16)*finesine[angle];
    shootz = t1->z + (t1->height>>1) + 8*(1<<16);
    attackrange = distance;
    aimslope = slope;
    P_PathTraverse ( t1->x, t1->y,
       x2, y2,
       1|2,
       PTR_ShootTraverse );
}
mobj_t* usething;
boolean PTR_UseTraverse (intercept_t* in)
{
    int side;
    if (!in->d.line->special)
    {
 P_LineOpening (in->d.line);
 if (openrange <= 0)
 {
     S_StartSound (usething, sfx_noway);
     return false;
 }
 return true ;
    }
    side = 0;
    if (P_PointOnLineSide (usething->x, usething->y, in->d.line) == 1)
 side = 1;
    P_UseSpecialLine (usething, in->d.line, side);
    return false;
}
void P_UseLines (player_t* player)
{
    int angle;
    fixed_t x1;
    fixed_t y1;
    fixed_t x2;
    fixed_t y2;
    usething = player->mo;
    angle = player->mo->angle >> 19;
    x1 = player->mo->x;
    y1 = player->mo->y;
    x2 = x1 + ((64*(1<<16))>>16)*finecosine[angle];
    y2 = y1 + ((64*(1<<16))>>16)*finesine[angle];
    P_PathTraverse ( x1, y1, x2, y2, 1, PTR_UseTraverse );
}
mobj_t* bombsource;
mobj_t* bombspot;
int bombdamage;
boolean PIT_RadiusAttack (mobj_t* thing)
{
    fixed_t dx;
    fixed_t dy;
    fixed_t dist;
    if (!(thing->flags & MF_SHOOTABLE) )
 return true;
    if (thing->type == MT_CYBORG
 || thing->type == MT_SPIDER)
 return true;
    dx = abs(thing->x - bombspot->x);
    dy = abs(thing->y - bombspot->y);
    dist = dx>dy ? dx : dy;
    dist = (dist - thing->radius) >> 16;
    if (dist < 0)
 dist = 0;
    if (dist >= bombdamage)
 return true;
    if ( P_CheckSight (thing, bombspot) )
    {
 P_DamageMobj (thing, bombspot, bombsource, bombdamage - dist);
    }
    return true;
}
void
P_RadiusAttack
( mobj_t* spot,
  mobj_t* source,
  int damage )
{
    int x;
    int y;
    int xl;
    int xh;
    int yl;
    int yh;
    fixed_t dist;
    dist = (damage+32*(1<<16))<<16;
    yh = (spot->y + dist - bmaporgy)>>(16 +7);
    yl = (spot->y - dist - bmaporgy)>>(16 +7);
    xh = (spot->x + dist - bmaporgx)>>(16 +7);
    xl = (spot->x - dist - bmaporgx)>>(16 +7);
    bombspot = spot;
    bombsource = source;
    bombdamage = damage;
    for (y=yl ; y<=yh ; y++)
 for (x=xl ; x<=xh ; x++)
     P_BlockThingsIterator (x, y, PIT_RadiusAttack );
}
boolean crushchange;
boolean nofit;
boolean PIT_ChangeSector (mobj_t* thing)
{
    mobj_t* mo;
    if (P_ThingHeightClip (thing))
    {
 return true;
    }
    if (thing->health <= 0)
    {
 P_SetMobjState (thing, S_GIBS);
 thing->flags &= ~MF_SOLID;
 thing->height = 0;
 thing->radius = 0;
 return true;
    }
    if (thing->flags & MF_DROPPED)
    {
 P_RemoveMobj (thing);
 return true;
    }
    if (! (thing->flags & MF_SHOOTABLE) )
    {
 return true;
    }
    nofit = true;
    if (crushchange && !(leveltime&3) )
    {
 P_DamageMobj(thing,((void *)0),((void *)0),10);
 mo = P_SpawnMobj (thing->x,
     thing->y,
     thing->z + thing->height/2, MT_BLOOD);
 mo->momx = (P_Random() - P_Random ())<<12;
 mo->momy = (P_Random() - P_Random ())<<12;
    }
    return true;
}
boolean
P_ChangeSector
( sector_t* sector,
  boolean crunch )
{
    int x;
    int y;
    nofit = false;
    crushchange = crunch;
    for (x=sector->blockbox[BOXLEFT] ; x<= sector->blockbox[BOXRIGHT] ; x++)
 for (y=sector->blockbox[BOXBOTTOM];y<= sector->blockbox[BOXTOP] ; y++)
     P_BlockThingsIterator (x, y, PIT_ChangeSector);
    return nofit;
}
static const char
rcsid[] = "$Id: p_maputl.c,v 1.5 1997/02/03 22:45:11 b1 Exp $";
fixed_t
P_AproxDistance
( fixed_t dx,
  fixed_t dy )
{
    dx = abs(dx);
    dy = abs(dy);
    if (dx < dy)
 return dx+dy-(dx>>1);
    return dx+dy-(dy>>1);
}
int
P_PointOnLineSide
( fixed_t x,
  fixed_t y,
  line_t* line )
{
    fixed_t dx;
    fixed_t dy;
    fixed_t left;
    fixed_t right;
    if (!line->dx)
    {
 if (x <= line->v1->x)
     return line->dy > 0;
 return line->dy < 0;
    }
    if (!line->dy)
    {
 if (y <= line->v1->y)
     return line->dx < 0;
 return line->dx > 0;
    }
    dx = (x - line->v1->x);
    dy = (y - line->v1->y);
    left = FixedMul ( line->dy>>16 , dx );
    right = FixedMul ( dy , line->dx>>16 );
    if (right < left)
 return 0;
    return 1;
}
int
P_BoxOnLineSide
( fixed_t* tmbox,
  line_t* ld )
{
    int p1;
    int p2;
    switch (ld->slopetype)
    {
      case ST_HORIZONTAL:
 p1 = tmbox[BOXTOP] > ld->v1->y;
 p2 = tmbox[BOXBOTTOM] > ld->v1->y;
 if (ld->dx < 0)
 {
     p1 ^= 1;
     p2 ^= 1;
 }
 break;
      case ST_VERTICAL:
 p1 = tmbox[BOXRIGHT] < ld->v1->x;
 p2 = tmbox[BOXLEFT] < ld->v1->x;
 if (ld->dy < 0)
 {
     p1 ^= 1;
     p2 ^= 1;
 }
 break;
      case ST_POSITIVE:
 p1 = P_PointOnLineSide (tmbox[BOXLEFT], tmbox[BOXTOP], ld);
 p2 = P_PointOnLineSide (tmbox[BOXRIGHT], tmbox[BOXBOTTOM], ld);
 break;
      case ST_NEGATIVE:
 p1 = P_PointOnLineSide (tmbox[BOXRIGHT], tmbox[BOXTOP], ld);
 p2 = P_PointOnLineSide (tmbox[BOXLEFT], tmbox[BOXBOTTOM], ld);
 break;
    }
    if (p1 == p2)
 return p1;
    return -1;
}
int
P_PointOnDivlineSide
( fixed_t x,
  fixed_t y,
  divline_t* line )
{
    fixed_t dx;
    fixed_t dy;
    fixed_t left;
    fixed_t right;
    if (!line->dx)
    {
 if (x <= line->x)
     return line->dy > 0;
 return line->dy < 0;
    }
    if (!line->dy)
    {
 if (y <= line->y)
     return line->dx < 0;
 return line->dx > 0;
    }
    dx = (x - line->x);
    dy = (y - line->y);
    if ( (line->dy ^ line->dx ^ dx ^ dy)&0x80000000 )
    {
 if ( (line->dy ^ dx) & 0x80000000 )
     return 1;
 return 0;
    }
    left = FixedMul ( line->dy>>8, dx>>8 );
    right = FixedMul ( dy>>8 , line->dx>>8 );
    if (right < left)
 return 0;
    return 1;
}
void
P_MakeDivline
( line_t* li,
  divline_t* dl )
{
    dl->x = li->v1->x;
    dl->y = li->v1->y;
    dl->dx = li->dx;
    dl->dy = li->dy;
}
fixed_t
P_InterceptVector
( divline_t* v2,
  divline_t* v1 )
{
    fixed_t frac;
    fixed_t num;
    fixed_t den;
    den = FixedMul (v1->dy>>8,v2->dx) - FixedMul(v1->dx>>8,v2->dy);
    if (den == 0)
 return 0;
    num =
 FixedMul ( (v1->x - v2->x)>>8 ,v1->dy )
 +FixedMul ( (v2->y - v1->y)>>8, v1->dx );
    frac = FixedDiv (num , den);
    return frac;
}
fixed_t opentop;
fixed_t openbottom;
fixed_t openrange;
fixed_t lowfloor;
void P_LineOpening (line_t* linedef)
{
    sector_t* front;
    sector_t* back;
    if (linedef->sidenum[1] == -1)
    {
 openrange = 0;
 return;
    }
    front = linedef->frontsector;
    back = linedef->backsector;
    if (front->ceilingheight < back->ceilingheight)
 opentop = front->ceilingheight;
    else
 opentop = back->ceilingheight;
    if (front->floorheight > back->floorheight)
    {
 openbottom = front->floorheight;
 lowfloor = back->floorheight;
    }
    else
    {
 openbottom = back->floorheight;
 lowfloor = front->floorheight;
    }
    openrange = opentop - openbottom;
}
void P_UnsetThingPosition (mobj_t* thing)
{
    int blockx;
    int blocky;
    if ( ! (thing->flags & MF_NOSECTOR) )
    {
 if (thing->snext)
     thing->snext->sprev = thing->sprev;
 if (thing->sprev)
     thing->sprev->snext = thing->snext;
 else
     thing->subsector->sector->thinglist = thing->snext;
    }
    if ( ! (thing->flags & MF_NOBLOCKMAP) )
    {
 if (thing->bnext)
     thing->bnext->bprev = thing->bprev;
 if (thing->bprev)
     thing->bprev->bnext = thing->bnext;
 else
 {
     blockx = (thing->x - bmaporgx)>>(16 +7);
     blocky = (thing->y - bmaporgy)>>(16 +7);
     if (blockx>=0 && blockx < bmapwidth
  && blocky>=0 && blocky <bmapheight)
     {
  blocklinks[blocky*bmapwidth+blockx] = thing->bnext;
     }
 }
    }
}
void
P_SetThingPosition (mobj_t* thing)
{
    subsector_t* ss;
    sector_t* sec;
    int blockx;
    int blocky;
    mobj_t** link;
    ss = R_PointInSubsector (thing->x,thing->y);
    thing->subsector = ss;
    if ( ! (thing->flags & MF_NOSECTOR) )
    {
 sec = ss->sector;
 thing->sprev = ((void *)0);
 thing->snext = sec->thinglist;
 if (sec->thinglist)
     sec->thinglist->sprev = thing;
 sec->thinglist = thing;
    }
    if ( ! (thing->flags & MF_NOBLOCKMAP) )
    {
 blockx = (thing->x - bmaporgx)>>(16 +7);
 blocky = (thing->y - bmaporgy)>>(16 +7);
 if (blockx>=0
     && blockx < bmapwidth
     && blocky>=0
     && blocky < bmapheight)
 {
     link = &blocklinks[blocky*bmapwidth+blockx];
     thing->bprev = ((void *)0);
     thing->bnext = *link;
     if (*link)
  (*link)->bprev = thing;
     *link = thing;
 }
 else
 {
     thing->bnext = thing->bprev = ((void *)0);
 }
    }
}
boolean
P_BlockLinesIterator
( int x,
  int y,
  boolean(*func)(line_t*) )
{
    int offset;
    short* list;
    line_t* ld;
    if (x<0
 || y<0
 || x>=bmapwidth
 || y>=bmapheight)
    {
 return true;
    }
    offset = y*bmapwidth+x;
    offset = *(blockmap+offset);
    for ( list = blockmaplump+offset ; *list != -1 ; list++)
    {
 ld = &lines[*list];
 if (ld->validcount == validcount)
     continue;
 ld->validcount = validcount;
 if ( !func(ld) )
     return false;
    }
    return true;
}
boolean
P_BlockThingsIterator
( int x,
  int y,
  boolean(*func)(mobj_t*) )
{
    mobj_t* mobj;
    if ( x<0
  || y<0
  || x>=bmapwidth
  || y>=bmapheight)
    {
 return true;
    }
    for (mobj = blocklinks[y*bmapwidth+x] ;
  mobj ;
  mobj = mobj->bnext)
    {
 if (!func( mobj ) )
     return false;
    }
    return true;
}
intercept_t intercepts[128];
intercept_t* intercept_p;
divline_t trace;
boolean earlyout;
int ptflags;
boolean
PIT_AddLineIntercepts (line_t* ld)
{
    int s1;
    int s2;
    fixed_t frac;
    divline_t dl;
    if ( trace.dx > (1<<16)*16
  || trace.dy > (1<<16)*16
  || trace.dx < -(1<<16)*16
  || trace.dy < -(1<<16)*16)
    {
 s1 = P_PointOnDivlineSide (ld->v1->x, ld->v1->y, &trace);
 s2 = P_PointOnDivlineSide (ld->v2->x, ld->v2->y, &trace);
    }
    else
    {
 s1 = P_PointOnLineSide (trace.x, trace.y, ld);
 s2 = P_PointOnLineSide (trace.x+trace.dx, trace.y+trace.dy, ld);
    }
    if (s1 == s2)
 return true;
    P_MakeDivline (ld, &dl);
    frac = P_InterceptVector (&trace, &dl);
    if (frac < 0)
 return true;
    if (earlyout
 && frac < (1<<16)
 && !ld->backsector)
    {
 return false;
    }
    intercept_p->frac = frac;
    intercept_p->isaline = true;
    intercept_p->d.line = ld;
    intercept_p++;
    return true;
}
boolean PIT_AddThingIntercepts (mobj_t* thing)
{
    fixed_t x1;
    fixed_t y1;
    fixed_t x2;
    fixed_t y2;
    int s1;
    int s2;
    boolean tracepositive;
    divline_t dl;
    fixed_t frac;
    tracepositive = (trace.dx ^ trace.dy)>0;
    if (tracepositive)
    {
 x1 = thing->x - thing->radius;
 y1 = thing->y + thing->radius;
 x2 = thing->x + thing->radius;
 y2 = thing->y - thing->radius;
    }
    else
    {
 x1 = thing->x - thing->radius;
 y1 = thing->y - thing->radius;
 x2 = thing->x + thing->radius;
 y2 = thing->y + thing->radius;
    }
    s1 = P_PointOnDivlineSide (x1, y1, &trace);
    s2 = P_PointOnDivlineSide (x2, y2, &trace);
    if (s1 == s2)
 return true;
    dl.x = x1;
    dl.y = y1;
    dl.dx = x2-x1;
    dl.dy = y2-y1;
    frac = P_InterceptVector (&trace, &dl);
    if (frac < 0)
 return true;
    intercept_p->frac = frac;
    intercept_p->isaline = false;
    intercept_p->d.thing = thing;
    intercept_p++;
    return true;
}
boolean
P_TraverseIntercepts
( traverser_t func,
  fixed_t maxfrac )
{
    int count;
    fixed_t dist;
    intercept_t* scan;
    intercept_t* in;
    count = intercept_p - intercepts;
    in = 0;
    while (count--)
    {
 dist = 0x7fffffff;
 for (scan = intercepts ; scan<intercept_p ; scan++)
 {
     if (scan->frac < dist)
     {
  dist = scan->frac;
  in = scan;
     }
 }
 if (dist > maxfrac)
     return true;
        if ( !func (in) )
     return false;
 in->frac = 0x7fffffff;
    }
    return true;
}
boolean
P_PathTraverse
( fixed_t x1,
  fixed_t y1,
  fixed_t x2,
  fixed_t y2,
  int flags,
  boolean (*trav) (intercept_t *))
{
    fixed_t xt1;
    fixed_t yt1;
    fixed_t xt2;
    fixed_t yt2;
    fixed_t xstep;
    fixed_t ystep;
    fixed_t partial;
    fixed_t xintercept;
    fixed_t yintercept;
    int mapx;
    int mapy;
    int mapxstep;
    int mapystep;
    int count;
    earlyout = flags & 4;
    validcount++;
    intercept_p = intercepts;
    if ( ((x1-bmaporgx)&((128*(1<<16))-1)) == 0)
 x1 += (1<<16);
    if ( ((y1-bmaporgy)&((128*(1<<16))-1)) == 0)
 y1 += (1<<16);
    trace.x = x1;
    trace.y = y1;
    trace.dx = x2 - x1;
    trace.dy = y2 - y1;
    x1 -= bmaporgx;
    y1 -= bmaporgy;
    xt1 = x1>>(16 +7);
    yt1 = y1>>(16 +7);
    x2 -= bmaporgx;
    y2 -= bmaporgy;
    xt2 = x2>>(16 +7);
    yt2 = y2>>(16 +7);
    if (xt2 > xt1)
    {
 mapxstep = 1;
 partial = (1<<16) - ((x1>>((16 +7)-16))&((1<<16)-1));
 ystep = FixedDiv (y2-y1,abs(x2-x1));
    }
    else if (xt2 < xt1)
    {
 mapxstep = -1;
 partial = (x1>>((16 +7)-16))&((1<<16)-1);
 ystep = FixedDiv (y2-y1,abs(x2-x1));
    }
    else
    {
 mapxstep = 0;
 partial = (1<<16);
 ystep = 256*(1<<16);
    }
    yintercept = (y1>>((16 +7)-16)) + FixedMul (partial, ystep);
    if (yt2 > yt1)
    {
 mapystep = 1;
 partial = (1<<16) - ((y1>>((16 +7)-16))&((1<<16)-1));
 xstep = FixedDiv (x2-x1,abs(y2-y1));
    }
    else if (yt2 < yt1)
    {
 mapystep = -1;
 partial = (y1>>((16 +7)-16))&((1<<16)-1);
 xstep = FixedDiv (x2-x1,abs(y2-y1));
    }
    else
    {
 mapystep = 0;
 partial = (1<<16);
 xstep = 256*(1<<16);
    }
    xintercept = (x1>>((16 +7)-16)) + FixedMul (partial, xstep);
    mapx = xt1;
    mapy = yt1;
    for (count = 0 ; count < 64 ; count++)
    {
 if (flags & 1)
 {
     if (!P_BlockLinesIterator (mapx, mapy,PIT_AddLineIntercepts))
  return false;
 }
 if (flags & 2)
 {
     if (!P_BlockThingsIterator (mapx, mapy,PIT_AddThingIntercepts))
  return false;
 }
 if (mapx == xt2
     && mapy == yt2)
 {
     break;
 }
 if ( (yintercept >> 16) == mapy)
 {
     yintercept += ystep;
     mapx += mapxstep;
 }
 else if ( (xintercept >> 16) == mapx)
 {
     xintercept += xstep;
     mapy += mapystep;
 }
    }
    return P_TraverseIntercepts ( trav, (1<<16) );
}
static const char
rcsid[] = "$Id: p_mobj.c,v 1.5 1997/02/03 22:45:12 b1 Exp $";
void G_PlayerReborn (int player);
void P_SpawnMapThing (mapthing_t* mthing);
int test;
boolean
P_SetMobjState
( mobj_t* mobj,
  statenum_t state )
{
    state_t* st;
    do
    {
 if (state == S_NULL)
 {
     mobj->state = (state_t *) S_NULL;
     P_RemoveMobj (mobj);
     return false;
 }
 st = &states[state];
 mobj->state = st;
 mobj->tics = st->tics;
 mobj->sprite = st->sprite;
 mobj->frame = st->frame;
 if (st->action.acp1)
     st->action.acp1(mobj);
 state = st->nextstate;
    } while (!mobj->tics);
    return true;
}
void P_ExplodeMissile (mobj_t* mo)
{
    mo->momx = mo->momy = mo->momz = 0;
    P_SetMobjState (mo, mobjinfo[mo->type].deathstate);
    mo->tics -= P_Random()&3;
    if (mo->tics < 1)
 mo->tics = 1;
    mo->flags &= ~MF_MISSILE;
    if (mo->info->deathsound)
 S_StartSound (mo, mo->info->deathsound);
}
void P_XYMovement (mobj_t* mo)
{
    fixed_t ptryx;
    fixed_t ptryy;
    player_t* player;
    fixed_t xmove;
    fixed_t ymove;
    if (!mo->momx && !mo->momy)
    {
 if (mo->flags & MF_SKULLFLY)
 {
     mo->flags &= ~MF_SKULLFLY;
     mo->momx = mo->momy = mo->momz = 0;
     P_SetMobjState (mo, mo->info->spawnstate);
 }
 return;
    }
    player = mo->player;
    if (mo->momx > (30*(1<<16)))
 mo->momx = (30*(1<<16));
    else if (mo->momx < -(30*(1<<16)))
 mo->momx = -(30*(1<<16));
    if (mo->momy > (30*(1<<16)))
 mo->momy = (30*(1<<16));
    else if (mo->momy < -(30*(1<<16)))
 mo->momy = -(30*(1<<16));
    xmove = mo->momx;
    ymove = mo->momy;
    do
    {
 if (xmove > (30*(1<<16))/2 || ymove > (30*(1<<16))/2)
 {
     ptryx = mo->x + xmove/2;
     ptryy = mo->y + ymove/2;
     xmove >>= 1;
     ymove >>= 1;
 }
 else
 {
     ptryx = mo->x + xmove;
     ptryy = mo->y + ymove;
     xmove = ymove = 0;
 }
 if (!P_TryMove (mo, ptryx, ptryy))
 {
     if (mo->player)
     {
  P_SlideMove (mo);
     }
     else if (mo->flags & MF_MISSILE)
     {
  if (ceilingline &&
      ceilingline->backsector &&
      ceilingline->backsector->ceilingpic == skyflatnum)
  {
      P_RemoveMobj (mo);
      return;
  }
  P_ExplodeMissile (mo);
     }
     else
  mo->momx = mo->momy = 0;
 }
    } while (xmove || ymove);
    if (player && player->cheats & CF_NOMOMENTUM)
    {
 mo->momx = mo->momy = 0;
 return;
    }
    if (mo->flags & (MF_MISSILE | MF_SKULLFLY) )
 return;
    if (mo->z > mo->floorz)
 return;
    if (mo->flags & MF_CORPSE)
    {
 if (mo->momx > (1<<16)/4
     || mo->momx < -(1<<16)/4
     || mo->momy > (1<<16)/4
     || mo->momy < -(1<<16)/4)
 {
     if (mo->floorz != mo->subsector->sector->floorheight)
  return;
 }
    }
    if (mo->momx > -0x1000
 && mo->momx < 0x1000
 && mo->momy > -0x1000
 && mo->momy < 0x1000
 && (!player
     || (player->cmd.forwardmove== 0
  && player->cmd.sidemove == 0 ) ) )
    {
 if ( player&&(unsigned)((player->mo->state - states)- S_PLAY_RUN1) < 4)
     P_SetMobjState (player->mo, S_PLAY);
 mo->momx = 0;
 mo->momy = 0;
    }
    else
    {
 mo->momx = FixedMul (mo->momx, 0xe800);
 mo->momy = FixedMul (mo->momy, 0xe800);
    }
}
void P_ZMovement (mobj_t* mo)
{
    fixed_t dist;
    fixed_t delta;
    if (mo->player && mo->z < mo->floorz)
    {
 mo->player->viewheight -= mo->floorz-mo->z;
 mo->player->deltaviewheight
     = ((41*(1<<16)) - mo->player->viewheight)>>3;
    }
    mo->z += mo->momz;
    if ( mo->flags & MF_FLOAT
  && mo->target)
    {
 if ( !(mo->flags & MF_SKULLFLY)
      && !(mo->flags & MF_INFLOAT) )
 {
     dist = P_AproxDistance (mo->x - mo->target->x,
        mo->y - mo->target->y);
     delta =(mo->target->z + (mo->height>>1)) - mo->z;
     if (delta<0 && dist < -(delta*3) )
  mo->z -= ((1<<16)*4);
     else if (delta>0 && dist < (delta*3) )
  mo->z += ((1<<16)*4);
 }
    }
    if (mo->z <= mo->floorz)
    {
 if (mo->flags & MF_SKULLFLY)
 {
     mo->momz = -mo->momz;
 }
 if (mo->momz < 0)
 {
     if (mo->player
  && mo->momz < -(1<<16)*8)
     {
  mo->player->deltaviewheight = mo->momz>>3;
  S_StartSound (mo, sfx_oof);
     }
     mo->momz = 0;
 }
 mo->z = mo->floorz;
 if ( (mo->flags & MF_MISSILE)
      && !(mo->flags & MF_NOCLIP) )
 {
     P_ExplodeMissile (mo);
     return;
 }
    }
    else if (! (mo->flags & MF_NOGRAVITY) )
    {
 if (mo->momz == 0)
     mo->momz = -(1<<16)*2;
 else
     mo->momz -= (1<<16);
    }
    if (mo->z + mo->height > mo->ceilingz)
    {
 if (mo->momz > 0)
     mo->momz = 0;
 {
     mo->z = mo->ceilingz - mo->height;
 }
 if (mo->flags & MF_SKULLFLY)
 {
     mo->momz = -mo->momz;
 }
 if ( (mo->flags & MF_MISSILE)
      && !(mo->flags & MF_NOCLIP) )
 {
     P_ExplodeMissile (mo);
     return;
 }
    }
}
void
P_NightmareRespawn (mobj_t* mobj)
{
    fixed_t x;
    fixed_t y;
    fixed_t z;
    subsector_t* ss;
    mobj_t* mo;
    mapthing_t* mthing;
    x = mobj->spawnpoint.x << 16;
    y = mobj->spawnpoint.y << 16;
    if (!P_CheckPosition (mobj, x, y) )
 return;
    mo = P_SpawnMobj (mobj->x,
        mobj->y,
        mobj->subsector->sector->floorheight , MT_TFOG);
    S_StartSound (mo, sfx_telept);
    ss = R_PointInSubsector (x,y);
    mo = P_SpawnMobj (x, y, ss->sector->floorheight , MT_TFOG);
    S_StartSound (mo, sfx_telept);
    mthing = &mobj->spawnpoint;
    if (mobj->info->flags & MF_SPAWNCEILING)
 z = 0x7fffffff;
    else
 z = (-0x7fffffff - 1);
    mo = P_SpawnMobj (x,y,z, mobj->type);
    mo->spawnpoint = mobj->spawnpoint;
    mo->angle = 0x20000000 * (mthing->angle/45);
    if (mthing->options & 8)
 mo->flags |= MF_AMBUSH;
    mo->reactiontime = 18;
    P_RemoveMobj (mobj);
}
void P_MobjThinker (mobj_t* mobj)
{
    if (mobj->momx
 || mobj->momy
 || (mobj->flags&MF_SKULLFLY) )
    {
 P_XYMovement (mobj);
 if (mobj->thinker.function.acv == (actionf_v) (-1))
     return;
    }
    if ( (mobj->z != mobj->floorz)
  || mobj->momz )
    {
 P_ZMovement (mobj);
 if (mobj->thinker.function.acv == (actionf_v) (-1))
     return;
    }
    if (mobj->tics != -1)
    {
 mobj->tics--;
 if (!mobj->tics)
     if (!P_SetMobjState (mobj, mobj->state->nextstate) )
  return;
    }
    else
    {
 if (! (mobj->flags & MF_COUNTKILL) )
     return;
 if (!respawnmonsters)
     return;
 mobj->movecount++;
 if (mobj->movecount < 12*35)
     return;
 if ( leveltime&31 )
     return;
 if (P_Random () > 4)
     return;
 P_NightmareRespawn (mobj);
    }
}
mobj_t*
P_SpawnMobj
( fixed_t x,
  fixed_t y,
  fixed_t z,
  mobjtype_t type )
{
    mobj_t* mobj;
    state_t* st;
    mobjinfo_t* info;
    mobj = Z_Malloc (sizeof(*mobj), 50, ((void *)0));
    memset (mobj, 0, sizeof (*mobj));
    info = &mobjinfo[type];
    mobj->type = type;
    mobj->info = info;
    mobj->x = x;
    mobj->y = y;
    mobj->radius = info->radius;
    mobj->height = info->height;
    mobj->flags = info->flags;
    mobj->health = info->spawnhealth;
    if (gameskill != sk_nightmare)
 mobj->reactiontime = info->reactiontime;
    mobj->lastlook = P_Random () % 4;
    st = &states[info->spawnstate];
    mobj->state = st;
    mobj->tics = st->tics;
    mobj->sprite = st->sprite;
    mobj->frame = st->frame;
    P_SetThingPosition (mobj);
    mobj->floorz = mobj->subsector->sector->floorheight;
    mobj->ceilingz = mobj->subsector->sector->ceilingheight;
    if (z == (-0x7fffffff - 1))
 mobj->z = mobj->floorz;
    else if (z == 0x7fffffff)
 mobj->z = mobj->ceilingz - mobj->info->height;
    else
 mobj->z = z;
    mobj->thinker.function.acp1 = (actionf_p1)P_MobjThinker;
    P_AddThinker (&mobj->thinker);
    return mobj;
}
mapthing_t itemrespawnque[128];
int itemrespawntime[128];
int iquehead;
int iquetail;
void P_RemoveMobj (mobj_t* mobj)
{
    if ((mobj->flags & MF_SPECIAL)
 && !(mobj->flags & MF_DROPPED)
 && (mobj->type != MT_INV)
 && (mobj->type != MT_INS))
    {
 itemrespawnque[iquehead] = mobj->spawnpoint;
 itemrespawntime[iquehead] = leveltime;
 iquehead = (iquehead+1)&(128 -1);
 if (iquehead == iquetail)
     iquetail = (iquetail+1)&(128 -1);
    }
    P_UnsetThingPosition (mobj);
    S_StopSound (mobj);
    P_RemoveThinker ((thinker_t*)mobj);
}
void P_RespawnSpecials (void)
{
    fixed_t x;
    fixed_t y;
    fixed_t z;
    subsector_t* ss;
    mobj_t* mo;
    mapthing_t* mthing;
    int i;
    if (deathmatch != 2)
 return;
    if (iquehead == iquetail)
 return;
    if (leveltime - itemrespawntime[iquetail] < 30*35)
 return;
    mthing = &itemrespawnque[iquetail];
    x = mthing->x << 16;
    y = mthing->y << 16;
    ss = R_PointInSubsector (x,y);
    mo = P_SpawnMobj (x, y, ss->sector->floorheight , MT_IFOG);
    S_StartSound (mo, sfx_itmbk);
    for (i=0 ; i< NUMMOBJTYPES ; i++)
    {
 if (mthing->type == mobjinfo[i].doomednum)
     break;
    }
    if (mobjinfo[i].flags & MF_SPAWNCEILING)
 z = 0x7fffffff;
    else
 z = (-0x7fffffff - 1);
    mo = P_SpawnMobj (x,y,z, i);
    mo->spawnpoint = *mthing;
    mo->angle = 0x20000000 * (mthing->angle/45);
    iquetail = (iquetail+1)&(128 -1);
}
void P_SpawnPlayer (mapthing_t* mthing)
{
    player_t* p;
    fixed_t x;
    fixed_t y;
    fixed_t z;
    mobj_t* mobj;
    int i;
    if (!playeringame[mthing->type-1])
 return;
    p = &players[mthing->type-1];
    if (p->playerstate == PST_REBORN)
 G_PlayerReborn (mthing->type-1);
    x = mthing->x << 16;
    y = mthing->y << 16;
    z = (-0x7fffffff - 1);
    mobj = P_SpawnMobj (x,y,z, MT_PLAYER);
    if (mthing->type > 1)
 mobj->flags |= (mthing->type-1)<<MF_TRANSSHIFT;
    mobj->angle = 0x20000000 * (mthing->angle/45);
    mobj->player = p;
    mobj->health = p->health;
    p->mo = mobj;
    p->playerstate = PST_LIVE;
    p->refire = 0;
    p->message = ((void *)0);
    p->damagecount = 0;
    p->bonuscount = 0;
    p->extralight = 0;
    p->fixedcolormap = 0;
    p->viewheight = (41*(1<<16));
    P_SetupPsprites (p);
    if (deathmatch)
 for (i=0 ; i<NUMCARDS ; i++)
     p->cards[i] = true;
    if (mthing->type-1 == consoleplayer)
    {
 ST_Start ();
 HU_Start ();
    }
}
void P_SpawnMapThing (mapthing_t* mthing)
{
    int i;
    int bit;
    mobj_t* mobj;
    fixed_t x;
    fixed_t y;
    fixed_t z;
    if (mthing->type == 11)
    {
 if (deathmatch_p < &deathmatchstarts[10])
 {
     memcpy (deathmatch_p, mthing, sizeof(*mthing));
     deathmatch_p++;
 }
 return;
    }
    if (mthing->type <= 4)
    {
 playerstarts[mthing->type-1] = *mthing;
 if (!deathmatch)
     P_SpawnPlayer (mthing);
 return;
    }
    if (!netgame && (mthing->options & 16) )
 return;
    if (gameskill == sk_baby)
 bit = 1;
    else if (gameskill == sk_nightmare)
 bit = 4;
    else
 bit = 1<<(gameskill-1);
    if (!(mthing->options & bit) )
 return;
    for (i=0 ; i< NUMMOBJTYPES ; i++)
 if (mthing->type == mobjinfo[i].doomednum)
     break;
    if (i==NUMMOBJTYPES)
 I_Error ("P_SpawnMapThing: Unknown type %i at (%i, %i)",
   mthing->type,
   mthing->x, mthing->y);
    if (deathmatch && mobjinfo[i].flags & MF_NOTDMATCH)
 return;
    if (nomonsters
 && ( i == MT_SKULL
      || (mobjinfo[i].flags & MF_COUNTKILL)) )
    {
 return;
    }
    x = mthing->x << 16;
    y = mthing->y << 16;
    if (mobjinfo[i].flags & MF_SPAWNCEILING)
 z = 0x7fffffff;
    else
 z = (-0x7fffffff - 1);
    mobj = P_SpawnMobj (x,y,z, i);
    mobj->spawnpoint = *mthing;
    if (mobj->tics > 0)
 mobj->tics = 1 + (P_Random () % mobj->tics);
    if (mobj->flags & MF_COUNTKILL)
 totalkills++;
    if (mobj->flags & MF_COUNTITEM)
 totalitems++;
    mobj->angle = 0x20000000 * (mthing->angle/45);
    if (mthing->options & 8)
 mobj->flags |= MF_AMBUSH;
}
extern fixed_t attackrange;
void
P_SpawnPuff
( fixed_t x,
  fixed_t y,
  fixed_t z )
{
    mobj_t* th;
    z += ((P_Random()-P_Random())<<10);
    th = P_SpawnMobj (x,y,z, MT_PUFF);
    th->momz = (1<<16);
    th->tics -= P_Random()&3;
    if (th->tics < 1)
 th->tics = 1;
    if (attackrange == (64*(1<<16)))
 P_SetMobjState (th, S_PUFF3);
}
void
P_SpawnBlood
( fixed_t x,
  fixed_t y,
  fixed_t z,
  int damage )
{
    mobj_t* th;
    z += ((P_Random()-P_Random())<<10);
    th = P_SpawnMobj (x,y,z, MT_BLOOD);
    th->momz = (1<<16)*2;
    th->tics -= P_Random()&3;
    if (th->tics < 1)
 th->tics = 1;
    if (damage <= 12 && damage >= 9)
 P_SetMobjState (th,S_BLOOD2);
    else if (damage < 9)
 P_SetMobjState (th,S_BLOOD3);
}
void P_CheckMissileSpawn (mobj_t* th)
{
    th->tics -= P_Random()&3;
    if (th->tics < 1)
 th->tics = 1;
    th->x += (th->momx>>1);
    th->y += (th->momy>>1);
    th->z += (th->momz>>1);
    if (!P_TryMove (th, th->x, th->y))
 P_ExplodeMissile (th);
}
mobj_t*
P_SpawnMissile
( mobj_t* source,
  mobj_t* dest,
  mobjtype_t type )
{
    mobj_t* th;
    angle_t an;
    int dist;
    th = P_SpawnMobj (source->x,
        source->y,
        source->z + 4*8*(1<<16), type);
    if (th->info->seesound)
 S_StartSound (th, th->info->seesound);
    th->target = source;
    an = R_PointToAngle2 (source->x, source->y, dest->x, dest->y);
    if (dest->flags & MF_SHADOW)
 an += (P_Random()-P_Random())<<20;
    th->angle = an;
    an >>= 19;
    th->momx = FixedMul (th->info->speed, finecosine[an]);
    th->momy = FixedMul (th->info->speed, finesine[an]);
    dist = P_AproxDistance (dest->x - source->x, dest->y - source->y);
    dist = dist / th->info->speed;
    if (dist < 1)
 dist = 1;
    th->momz = (dest->z - source->z) / dist;
    P_CheckMissileSpawn (th);
    return th;
}
void
P_SpawnPlayerMissile
( mobj_t* source,
  mobjtype_t type )
{
    mobj_t* th;
    angle_t an;
    fixed_t x;
    fixed_t y;
    fixed_t z;
    fixed_t slope;
    an = source->angle;
    slope = P_AimLineAttack (source, an, 16*64*(1<<16));
    if (!linetarget)
    {
 an += 1<<26;
 slope = P_AimLineAttack (source, an, 16*64*(1<<16));
 if (!linetarget)
 {
     an -= 2<<26;
     slope = P_AimLineAttack (source, an, 16*64*(1<<16));
 }
 if (!linetarget)
 {
     an = source->angle;
     slope = 0;
 }
    }
    x = source->x;
    y = source->y;
    z = source->z + 4*8*(1<<16);
    th = P_SpawnMobj (x,y,z, type);
    if (th->info->seesound)
 S_StartSound (th, th->info->seesound);
    th->target = source;
    th->angle = an;
    th->momx = FixedMul( th->info->speed,
    finecosine[an>>19]);
    th->momy = FixedMul( th->info->speed,
    finesine[an>>19]);
    th->momz = FixedMul( th->info->speed, slope);
    P_CheckMissileSpawn (th);
}
static const char
rcsid[] = "$Id: p_plats.c,v 1.5 1997/02/03 22:45:12 b1 Exp $";
plat_t* activeplats[30];
void T_PlatRaise(plat_t* plat)
{
    result_e res;
    switch(plat->status)
    {
      case up:
 res = T_MovePlane(plat->sector,
     plat->speed,
     plat->high,
     plat->crush,0,1);
 if (plat->type == raiseAndChange
     || plat->type == raiseToNearestAndChange)
 {
     if (!(leveltime&7))
  S_StartSound((mobj_t *)&plat->sector->soundorg,
        sfx_stnmov);
 }
 if (res == crushed && (!plat->crush))
 {
     plat->count = plat->wait;
     plat->status = down;
     S_StartSound((mobj_t *)&plat->sector->soundorg,
    sfx_pstart);
 }
 else
 {
     if (res == pastdest)
     {
  plat->count = plat->wait;
  plat->status = waiting;
  S_StartSound((mobj_t *)&plat->sector->soundorg,
        sfx_pstop);
  switch(plat->type)
  {
    case blazeDWUS:
    case downWaitUpStay:
      P_RemoveActivePlat(plat);
      break;
    case raiseAndChange:
    case raiseToNearestAndChange:
      P_RemoveActivePlat(plat);
      break;
    default:
      break;
  }
     }
 }
 break;
      case down:
 res = T_MovePlane(plat->sector,plat->speed,plat->low,false,0,-1);
 if (res == pastdest)
 {
     plat->count = plat->wait;
     plat->status = waiting;
     S_StartSound((mobj_t *)&plat->sector->soundorg,sfx_pstop);
 }
 break;
      case waiting:
 if (!--plat->count)
 {
     if (plat->sector->floorheight == plat->low)
  plat->status = up;
     else
  plat->status = down;
     S_StartSound((mobj_t *)&plat->sector->soundorg,sfx_pstart);
 }
      case in_stasis:
 break;
    }
}
int
EV_DoPlat
( line_t* line,
  plattype_e type,
  int amount )
{
    plat_t* plat;
    int secnum;
    int rtn;
    sector_t* sec;
    secnum = -1;
    rtn = 0;
    switch(type)
    {
      case perpetualRaise:
 P_ActivateInStasis(line->tag);
 break;
      default:
 break;
    }
    while ((secnum = P_FindSectorFromLineTag(line,secnum)) >= 0)
    {
 sec = &sectors[secnum];
 if (sec->specialdata)
     continue;
 rtn = 1;
 plat = Z_Malloc( sizeof(*plat), 51, 0);
 P_AddThinker(&plat->thinker);
 plat->type = type;
 plat->sector = sec;
 plat->sector->specialdata = plat;
 plat->thinker.function.acp1 = (actionf_p1) T_PlatRaise;
 plat->crush = false;
 plat->tag = line->tag;
 switch(type)
 {
   case raiseToNearestAndChange:
     plat->speed = (1<<16)/2;
     sec->floorpic = sides[line->sidenum[0]].sector->floorpic;
     plat->high = P_FindNextHighestFloor(sec,sec->floorheight);
     plat->wait = 0;
     plat->status = up;
     sec->special = 0;
     S_StartSound((mobj_t *)&sec->soundorg,sfx_stnmov);
     break;
   case raiseAndChange:
     plat->speed = (1<<16)/2;
     sec->floorpic = sides[line->sidenum[0]].sector->floorpic;
     plat->high = sec->floorheight + amount*(1<<16);
     plat->wait = 0;
     plat->status = up;
     S_StartSound((mobj_t *)&sec->soundorg,sfx_stnmov);
     break;
   case downWaitUpStay:
     plat->speed = (1<<16) * 4;
     plat->low = P_FindLowestFloorSurrounding(sec);
     if (plat->low > sec->floorheight)
  plat->low = sec->floorheight;
     plat->high = sec->floorheight;
     plat->wait = 35*3;
     plat->status = down;
     S_StartSound((mobj_t *)&sec->soundorg,sfx_pstart);
     break;
   case blazeDWUS:
     plat->speed = (1<<16) * 8;
     plat->low = P_FindLowestFloorSurrounding(sec);
     if (plat->low > sec->floorheight)
  plat->low = sec->floorheight;
     plat->high = sec->floorheight;
     plat->wait = 35*3;
     plat->status = down;
     S_StartSound((mobj_t *)&sec->soundorg,sfx_pstart);
     break;
   case perpetualRaise:
     plat->speed = (1<<16);
     plat->low = P_FindLowestFloorSurrounding(sec);
     if (plat->low > sec->floorheight)
  plat->low = sec->floorheight;
     plat->high = P_FindHighestFloorSurrounding(sec);
     if (plat->high < sec->floorheight)
  plat->high = sec->floorheight;
     plat->wait = 35*3;
     plat->status = P_Random()&1;
     S_StartSound((mobj_t *)&sec->soundorg,sfx_pstart);
     break;
 }
 P_AddActivePlat(plat);
    }
    return rtn;
}
void P_ActivateInStasis(int tag)
{
    int i;
    for (i = 0;i < 30;i++)
 if (activeplats[i]
     && (activeplats[i])->tag == tag
     && (activeplats[i])->status == in_stasis)
 {
     (activeplats[i])->status = (activeplats[i])->oldstatus;
     (activeplats[i])->thinker.function.acp1
       = (actionf_p1) T_PlatRaise;
 }
}
void EV_StopPlat(line_t* line)
{
    int j;
    for (j = 0;j < 30;j++)
 if (activeplats[j]
     && ((activeplats[j])->status != in_stasis)
     && ((activeplats[j])->tag == line->tag))
 {
     (activeplats[j])->oldstatus = (activeplats[j])->status;
     (activeplats[j])->status = in_stasis;
     (activeplats[j])->thinker.function.acv = (actionf_v)((void *)0);
 }
}
void P_AddActivePlat(plat_t* plat)
{
    int i;
    for (i = 0;i < 30;i++)
 if (activeplats[i] == ((void *)0))
 {
     activeplats[i] = plat;
     return;
 }
    I_Error ("P_AddActivePlat: no more plats!");
}
void P_RemoveActivePlat(plat_t* plat)
{
    int i;
    for (i = 0;i < 30;i++)
 if (plat == activeplats[i])
 {
     (activeplats[i])->sector->specialdata = ((void *)0);
     P_RemoveThinker(&(activeplats[i])->thinker);
     activeplats[i] = ((void *)0);
     return;
 }
    I_Error ("P_RemoveActivePlat: can't find plat!");
}
static const char
rcsid[] = "$Id: p_pspr.c,v 1.5 1997/02/03 22:45:12 b1 Exp $";
void
P_SetPsprite
( player_t* player,
  int position,
  statenum_t stnum )
{
    pspdef_t* psp;
    state_t* state;
    psp = &player->psprites[position];
    do
    {
 if (!stnum)
 {
     psp->state = ((void *)0);
     break;
 }
 state = &states[stnum];
 psp->state = state;
 psp->tics = state->tics;
 if (state->misc1)
 {
     psp->sx = state->misc1 << 16;
     psp->sy = state->misc2 << 16;
 }
 if (state->action.acp2)
 {
     state->action.acp2(player, psp);
     if (!psp->state)
  break;
 }
 stnum = psp->state->nextstate;
    } while (!psp->tics);
}
fixed_t swingx;
fixed_t swingy;
void P_CalcSwing (player_t* player)
{
    fixed_t swing;
    int angle;
    swing = player->bob;
    angle = (8192/70*leveltime)&(8192 -1);
    swingx = FixedMul ( swing, finesine[angle]);
    angle = (8192/70*leveltime+8192/2)&(8192 -1);
    swingy = -FixedMul ( swingx, finesine[angle]);
}
void P_BringUpWeapon (player_t* player)
{
    statenum_t newstate;
    if (player->pendingweapon == wp_nochange)
 player->pendingweapon = player->readyweapon;
    if (player->pendingweapon == wp_chainsaw)
 S_StartSound (player->mo, sfx_sawup);
    newstate = weaponinfo[player->pendingweapon].upstate;
    player->pendingweapon = wp_nochange;
    player->psprites[ps_weapon].sy = 128*(1<<16);
    P_SetPsprite (player, ps_weapon, newstate);
}
boolean P_CheckAmmo (player_t* player)
{
    ammotype_t ammo;
    int count;
    ammo = weaponinfo[player->readyweapon].ammo;
    if (player->readyweapon == wp_bfg)
 count = 40;
    else if (player->readyweapon == wp_supershotgun)
 count = 2;
    else
 count = 1;
    if (ammo == am_noammo || player->ammo[ammo] >= count)
 return true;
    do
    {
 if (player->weaponowned[wp_plasma]
     && player->ammo[am_cell]
     && (gamemode != shareware) )
 {
     player->pendingweapon = wp_plasma;
 }
 else if (player->weaponowned[wp_supershotgun]
   && player->ammo[am_shell]>2
   && (gamemode == commercial) )
 {
     player->pendingweapon = wp_supershotgun;
 }
 else if (player->weaponowned[wp_chaingun]
   && player->ammo[am_clip])
 {
     player->pendingweapon = wp_chaingun;
 }
 else if (player->weaponowned[wp_shotgun]
   && player->ammo[am_shell])
 {
     player->pendingweapon = wp_shotgun;
 }
 else if (player->ammo[am_clip])
 {
     player->pendingweapon = wp_pistol;
 }
 else if (player->weaponowned[wp_chainsaw])
 {
     player->pendingweapon = wp_chainsaw;
 }
 else if (player->weaponowned[wp_missile]
   && player->ammo[am_misl])
 {
     player->pendingweapon = wp_missile;
 }
 else if (player->weaponowned[wp_bfg]
   && player->ammo[am_cell]>40
   && (gamemode != shareware) )
 {
     player->pendingweapon = wp_bfg;
 }
 else
 {
     player->pendingweapon = wp_fist;
 }
    } while (player->pendingweapon == wp_nochange);
    P_SetPsprite (player,
    ps_weapon,
    weaponinfo[player->readyweapon].downstate);
    return false;
}
void P_FireWeapon (player_t* player)
{
    statenum_t newstate;
    if (!P_CheckAmmo (player))
 return;
    P_SetMobjState (player->mo, S_PLAY_ATK1);
    newstate = weaponinfo[player->readyweapon].atkstate;
    P_SetPsprite (player, ps_weapon, newstate);
    P_NoiseAlert (player->mo, player->mo);
}
void P_DropWeapon (player_t* player)
{
    P_SetPsprite (player,
    ps_weapon,
    weaponinfo[player->readyweapon].downstate);
}
void
A_WeaponReady
( player_t* player,
  pspdef_t* psp )
{
    statenum_t newstate;
    int angle;
    if (player->mo->state == &states[S_PLAY_ATK1]
 || player->mo->state == &states[S_PLAY_ATK2] )
    {
 P_SetMobjState (player->mo, S_PLAY);
    }
    if (player->readyweapon == wp_chainsaw
 && psp->state == &states[S_SAW])
    {
 S_StartSound (player->mo, sfx_sawidl);
    }
    if (player->pendingweapon != wp_nochange || !player->health)
    {
 newstate = weaponinfo[player->readyweapon].downstate;
 P_SetPsprite (player, ps_weapon, newstate);
 return;
    }
    if (player->cmd.buttons & BT_ATTACK)
    {
 if ( !player->attackdown
      || (player->readyweapon != wp_missile
   && player->readyweapon != wp_bfg) )
 {
     player->attackdown = true;
     P_FireWeapon (player);
     return;
 }
    }
    else
 player->attackdown = false;
    angle = (128*leveltime)&(8192 -1);
    psp->sx = (1<<16) + FixedMul (player->bob, finecosine[angle]);
    angle &= 8192/2-1;
    psp->sy = 32*(1<<16) + FixedMul (player->bob, finesine[angle]);
}
void A_ReFire
( player_t* player,
  pspdef_t* psp )
{
    if ( (player->cmd.buttons & BT_ATTACK)
  && player->pendingweapon == wp_nochange
  && player->health)
    {
 player->refire++;
 P_FireWeapon (player);
    }
    else
    {
 player->refire = 0;
 P_CheckAmmo (player);
    }
}
void
A_CheckReload
( player_t* player,
  pspdef_t* psp )
{
    P_CheckAmmo (player);
}
void
A_Lower
( player_t* player,
  pspdef_t* psp )
{
    psp->sy += (1<<16)*6;
    if (psp->sy < 128*(1<<16) )
 return;
    if (player->playerstate == PST_DEAD)
    {
 psp->sy = 128*(1<<16);
 return;
    }
    if (!player->health)
    {
 P_SetPsprite (player, ps_weapon, S_NULL);
 return;
    }
    player->readyweapon = player->pendingweapon;
    P_BringUpWeapon (player);
}
void
A_Raise
( player_t* player,
  pspdef_t* psp )
{
    statenum_t newstate;
    psp->sy -= (1<<16)*6;
    if (psp->sy > 32*(1<<16) )
 return;
    psp->sy = 32*(1<<16);
    newstate = weaponinfo[player->readyweapon].readystate;
    P_SetPsprite (player, ps_weapon, newstate);
}
void
A_GunFlash
( player_t* player,
  pspdef_t* psp )
{
    P_SetMobjState (player->mo, S_PLAY_ATK2);
    P_SetPsprite (player,ps_flash,weaponinfo[player->readyweapon].flashstate);
}
void
A_Punch
( player_t* player,
  pspdef_t* psp )
{
    angle_t angle;
    int damage;
    int slope;
    damage = (P_Random ()%10+1)<<1;
    if (player->powers[pw_strength])
 damage *= 10;
    angle = player->mo->angle;
    angle += (P_Random()-P_Random())<<18;
    slope = P_AimLineAttack (player->mo, angle, (64*(1<<16)));
    P_LineAttack (player->mo, angle, (64*(1<<16)), slope, damage);
    if (linetarget)
    {
 S_StartSound (player->mo, sfx_punch);
 player->mo->angle = R_PointToAngle2 (player->mo->x,
          player->mo->y,
          linetarget->x,
          linetarget->y);
    }
}
void
A_Saw
( player_t* player,
  pspdef_t* psp )
{
    angle_t angle;
    int damage;
    int slope;
    damage = 2*(P_Random ()%10+1);
    angle = player->mo->angle;
    angle += (P_Random()-P_Random())<<18;
    slope = P_AimLineAttack (player->mo, angle, (64*(1<<16))+1);
    P_LineAttack (player->mo, angle, (64*(1<<16))+1, slope, damage);
    if (!linetarget)
    {
 S_StartSound (player->mo, sfx_sawful);
 return;
    }
    S_StartSound (player->mo, sfx_sawhit);
    angle = R_PointToAngle2 (player->mo->x, player->mo->y,
        linetarget->x, linetarget->y);
    if (angle - player->mo->angle > 0x80000000)
    {
 if (angle - player->mo->angle < -0x40000000/20)
     player->mo->angle = angle + 0x40000000/21;
 else
     player->mo->angle -= 0x40000000/20;
    }
    else
    {
 if (angle - player->mo->angle > 0x40000000/20)
     player->mo->angle = angle - 0x40000000/21;
 else
     player->mo->angle += 0x40000000/20;
    }
    player->mo->flags |= MF_JUSTATTACKED;
}
void
A_FireMissile
( player_t* player,
  pspdef_t* psp )
{
    player->ammo[weaponinfo[player->readyweapon].ammo]--;
    P_SpawnPlayerMissile (player->mo, MT_ROCKET);
}
void
A_FireBFG
( player_t* player,
  pspdef_t* psp )
{
    player->ammo[weaponinfo[player->readyweapon].ammo] -= 40;
    P_SpawnPlayerMissile (player->mo, MT_BFG);
}
void
A_FirePlasma
( player_t* player,
  pspdef_t* psp )
{
    player->ammo[weaponinfo[player->readyweapon].ammo]--;
    P_SetPsprite (player,
    ps_flash,
    weaponinfo[player->readyweapon].flashstate+(P_Random ()&1) );
    P_SpawnPlayerMissile (player->mo, MT_PLASMA);
}
fixed_t bulletslope;
void P_BulletSlope (mobj_t* mo)
{
    angle_t an;
    an = mo->angle;
    bulletslope = P_AimLineAttack (mo, an, 16*64*(1<<16));
    if (!linetarget)
    {
 an += 1<<26;
 bulletslope = P_AimLineAttack (mo, an, 16*64*(1<<16));
 if (!linetarget)
 {
     an -= 2<<26;
     bulletslope = P_AimLineAttack (mo, an, 16*64*(1<<16));
 }
    }
}
void
P_GunShot
( mobj_t* mo,
  boolean accurate )
{
    angle_t angle;
    int damage;
    damage = 5*(P_Random ()%3+1);
    angle = mo->angle;
    if (!accurate)
 angle += (P_Random()-P_Random())<<18;
    P_LineAttack (mo, angle, (32*64*(1<<16)), bulletslope, damage);
}
void
A_FirePistol
( player_t* player,
  pspdef_t* psp )
{
    S_StartSound (player->mo, sfx_pistol);
    P_SetMobjState (player->mo, S_PLAY_ATK2);
    player->ammo[weaponinfo[player->readyweapon].ammo]--;
    P_SetPsprite (player,
    ps_flash,
    weaponinfo[player->readyweapon].flashstate);
    P_BulletSlope (player->mo);
    P_GunShot (player->mo, !player->refire);
}
void
A_FireShotgun
( player_t* player,
  pspdef_t* psp )
{
    int i;
    S_StartSound (player->mo, sfx_shotgn);
    P_SetMobjState (player->mo, S_PLAY_ATK2);
    player->ammo[weaponinfo[player->readyweapon].ammo]--;
    P_SetPsprite (player,
    ps_flash,
    weaponinfo[player->readyweapon].flashstate);
    P_BulletSlope (player->mo);
    for (i=0 ; i<7 ; i++)
 P_GunShot (player->mo, false);
}
void
A_FireShotgun2
( player_t* player,
  pspdef_t* psp )
{
    int i;
    angle_t angle;
    int damage;
    S_StartSound (player->mo, sfx_dshtgn);
    P_SetMobjState (player->mo, S_PLAY_ATK2);
    player->ammo[weaponinfo[player->readyweapon].ammo]-=2;
    P_SetPsprite (player,
    ps_flash,
    weaponinfo[player->readyweapon].flashstate);
    P_BulletSlope (player->mo);
    for (i=0 ; i<20 ; i++)
    {
 damage = 5*(P_Random ()%3+1);
 angle = player->mo->angle;
 angle += (P_Random()-P_Random())<<19;
 P_LineAttack (player->mo,
        angle,
        (32*64*(1<<16)),
        bulletslope + ((P_Random()-P_Random())<<5), damage);
    }
}
void
A_FireCGun
( player_t* player,
  pspdef_t* psp )
{
    S_StartSound (player->mo, sfx_pistol);
    if (!player->ammo[weaponinfo[player->readyweapon].ammo])
 return;
    P_SetMobjState (player->mo, S_PLAY_ATK2);
    player->ammo[weaponinfo[player->readyweapon].ammo]--;
    P_SetPsprite (player,
    ps_flash,
    weaponinfo[player->readyweapon].flashstate
    + psp->state
    - &states[S_CHAIN1] );
    P_BulletSlope (player->mo);
    P_GunShot (player->mo, !player->refire);
}
