{
    player->extralight = 2;
}
void A_BFGSpray (mobj_t* mo)
{
    int i;
    int j;
    int damage;
    angle_t an;
    for (i=0 ; i<40 ; i++)
    {
 an = mo->angle - 0x40000000/2 + 0x40000000/40*i;
 P_AimLineAttack (mo->target, an, 16*64*(1<<16));
 if (!linetarget)
     continue;
 P_SpawnMobj (linetarget->x,
       linetarget->y,
       linetarget->z + (linetarget->height>>2),
       MT_EXTRABFG);
 damage = 0;
 for (j=0;j<15;j++)
     damage += (P_Random()&7) + 1;
 P_DamageMobj (linetarget, mo->target,mo->target, damage);
    }
}
void
A_BFGsound
( player_t* player,
  pspdef_t* psp )
{
    S_StartSound (player->mo, sfx_bfg);
}
void P_SetupPsprites (player_t* player)
{
    int i;
    for (i=0 ; i<NUMPSPRITES ; i++)
 player->psprites[i].state = ((void *)0);
    player->pendingweapon = player->readyweapon;
    P_BringUpWeapon (player);
}
void P_MovePsprites (player_t* player)
{
    int i;
    pspdef_t* psp;
    state_t* state;
    psp = &player->psprites[0];
    for (i=0 ; i<NUMPSPRITES ; i++, psp++)
    {
 if ( (state = psp->state) )
 {
     if (psp->tics != -1)
     {
  psp->tics--;
  if (!psp->tics)
      P_SetPsprite (player, i, psp->state->nextstate);
     }
 }
    }
    player->psprites[ps_flash].sx = player->psprites[ps_weapon].sx;
    player->psprites[ps_flash].sy = player->psprites[ps_weapon].sy;
}
static const char
rcsid[] = "$Id: p_tick.c,v 1.4 1997/02/03 16:47:55 b1 Exp $";
byte* save_p;
void P_ArchivePlayers (void)
{
    int i;
    int j;
    player_t* dest;
    for (i=0 ; i<4 ; i++)
    {
 if (!playeringame[i])
     continue;
 save_p += (4 - ((int) save_p & 3)) & 3;
 dest = (player_t *)save_p;
 memcpy (dest,&players[i],sizeof(player_t));
 save_p += sizeof(player_t);
 for (j=0 ; j<NUMPSPRITES ; j++)
 {
     if (dest->psprites[j].state)
     {
  dest->psprites[j].state
      = (state_t *)(dest->psprites[j].state-states);
     }
 }
    }
}
void P_UnArchivePlayers (void)
{
    int i;
    int j;
    for (i=0 ; i<4 ; i++)
    {
 if (!playeringame[i])
     continue;
 save_p += (4 - ((int) save_p & 3)) & 3;
 memcpy (&players[i],save_p, sizeof(player_t));
 save_p += sizeof(player_t);
 players[i].mo = ((void *)0);
 players[i].message = ((void *)0);
 players[i].attacker = ((void *)0);
 for (j=0 ; j<NUMPSPRITES ; j++)
 {
     if (players[i]. psprites[j].state)
     {
  players[i]. psprites[j].state
      = &states[ (int)players[i].psprites[j].state ];
     }
 }
    }
}
void P_ArchiveWorld (void)
{
    int i;
    int j;
    sector_t* sec;
    line_t* li;
    side_t* si;
    short* put;
    put = (short *)save_p;
    for (i=0, sec = sectors ; i<numsectors ; i++,sec++)
    {
 *put++ = sec->floorheight >> 16;
 *put++ = sec->ceilingheight >> 16;
 *put++ = sec->floorpic;
 *put++ = sec->ceilingpic;
 *put++ = sec->lightlevel;
 *put++ = sec->special;
 *put++ = sec->tag;
    }
    for (i=0, li = lines ; i<numlines ; i++,li++)
    {
 *put++ = li->flags;
 *put++ = li->special;
 *put++ = li->tag;
 for (j=0 ; j<2 ; j++)
 {
     if (li->sidenum[j] == -1)
  continue;
     si = &sides[li->sidenum[j]];
     *put++ = si->textureoffset >> 16;
     *put++ = si->rowoffset >> 16;
     *put++ = si->toptexture;
     *put++ = si->bottomtexture;
     *put++ = si->midtexture;
 }
    }
    save_p = (byte *)put;
}
void P_UnArchiveWorld (void)
{
    int i;
    int j;
    sector_t* sec;
    line_t* li;
    side_t* si;
    short* get;
    get = (short *)save_p;
    for (i=0, sec = sectors ; i<numsectors ; i++,sec++)
    {
 sec->floorheight = *get++ << 16;
 sec->ceilingheight = *get++ << 16;
 sec->floorpic = *get++;
 sec->ceilingpic = *get++;
 sec->lightlevel = *get++;
 sec->special = *get++;
 sec->tag = *get++;
 sec->specialdata = 0;
 sec->soundtarget = 0;
    }
    for (i=0, li = lines ; i<numlines ; i++,li++)
    {
 li->flags = *get++;
 li->special = *get++;
 li->tag = *get++;
 for (j=0 ; j<2 ; j++)
 {
     if (li->sidenum[j] == -1)
  continue;
     si = &sides[li->sidenum[j]];
     si->textureoffset = *get++ << 16;
     si->rowoffset = *get++ << 16;
     si->toptexture = *get++;
     si->bottomtexture = *get++;
     si->midtexture = *get++;
 }
    }
    save_p = (byte *)get;
}
typedef enum
{
    tc_end,
    tc_mobj
} thinkerclass_t;
void P_ArchiveThinkers (void)
{
    thinker_t* th;
    mobj_t* mobj;
    for (th = thinkercap.next ; th != &thinkercap ; th=th->next)
    {
 if (th->function.acp1 == (actionf_p1)P_MobjThinker)
 {
     *save_p++ = tc_mobj;
     save_p += (4 - ((int) save_p & 3)) & 3;
     mobj = (mobj_t *)save_p;
     memcpy (mobj, th, sizeof(*mobj));
     save_p += sizeof(*mobj);
     mobj->state = (state_t *)(mobj->state - states);
     if (mobj->player)
  mobj->player = (player_t *)((mobj->player-players) + 1);
     continue;
 }
    }
    *save_p++ = tc_end;
}
void P_UnArchiveThinkers (void)
{
    byte tclass;
    thinker_t* currentthinker;
    thinker_t* next;
    mobj_t* mobj;
    currentthinker = thinkercap.next;
    while (currentthinker != &thinkercap)
    {
 next = currentthinker->next;
 if (currentthinker->function.acp1 == (actionf_p1)P_MobjThinker)
     P_RemoveMobj ((mobj_t *)currentthinker);
 else
     Z_Free (currentthinker);
 currentthinker = next;
    }
    P_InitThinkers ();
    while (1)
    {
 tclass = *save_p++;
 switch (tclass)
 {
   case tc_end:
     return;
   case tc_mobj:
     save_p += (4 - ((int) save_p & 3)) & 3;
     mobj = Z_Malloc (sizeof(*mobj), 50, ((void *)0));
     memcpy (mobj, save_p, sizeof(*mobj));
     save_p += sizeof(*mobj);
     mobj->state = &states[(int)mobj->state];
     mobj->target = ((void *)0);
     if (mobj->player)
     {
  mobj->player = &players[(int)mobj->player-1];
  mobj->player->mo = mobj;
     }
     P_SetThingPosition (mobj);
     mobj->info = &mobjinfo[mobj->type];
     mobj->floorz = mobj->subsector->sector->floorheight;
     mobj->ceilingz = mobj->subsector->sector->ceilingheight;
     mobj->thinker.function.acp1 = (actionf_p1)P_MobjThinker;
     P_AddThinker (&mobj->thinker);
     break;
   default:
     I_Error ("Unknown tclass %i in savegame",tclass);
 }
    }
}
