void P_ArchiveSpecials (void)
{
    thinker_t* th;
    ceiling_t* ceiling;
    vldoor_t* door;
    floormove_t* floor;
    plat_t* plat;
    lightflash_t* flash;
    strobe_t* strobe;
    glow_t* glow;
    int i;
    for (th = thinkercap.next ; th != &thinkercap ; th=th->next)
    {
 if (th->function.acv == (actionf_v)((void *)0))
 {
     for (i = 0; i < 30;i++)
  if (activeceilings[i] == (ceiling_t *)th)
      break;
     if (i<30)
     {
  *save_p++ = tc_ceiling;
  save_p += (4 - ((int) save_p & 3)) & 3;
  ceiling = (ceiling_t *)save_p;
  memcpy (ceiling, th, sizeof(*ceiling));
  save_p += sizeof(*ceiling);
  ceiling->sector = (sector_t *)(ceiling->sector - sectors);
     }
     continue;
 }
 if (th->function.acp1 == (actionf_p1)T_MoveCeiling)
 {
     *save_p++ = tc_ceiling;
     save_p += (4 - ((int) save_p & 3)) & 3;
     ceiling = (ceiling_t *)save_p;
     memcpy (ceiling, th, sizeof(*ceiling));
     save_p += sizeof(*ceiling);
     ceiling->sector = (sector_t *)(ceiling->sector - sectors);
     continue;
 }
 if (th->function.acp1 == (actionf_p1)T_VerticalDoor)
 {
     *save_p++ = tc_door;
     save_p += (4 - ((int) save_p & 3)) & 3;
     door = (vldoor_t *)save_p;
     memcpy (door, th, sizeof(*door));
     save_p += sizeof(*door);
     door->sector = (sector_t *)(door->sector - sectors);
     continue;
 }
 if (th->function.acp1 == (actionf_p1)T_MoveFloor)
 {
     *save_p++ = tc_floor;
     save_p += (4 - ((int) save_p & 3)) & 3;
     floor = (floormove_t *)save_p;
     memcpy (floor, th, sizeof(*floor));
     save_p += sizeof(*floor);
     floor->sector = (sector_t *)(floor->sector - sectors);
     continue;
 }
 if (th->function.acp1 == (actionf_p1)T_PlatRaise)
 {
     *save_p++ = tc_plat;
     save_p += (4 - ((int) save_p & 3)) & 3;
     plat = (plat_t *)save_p;
     memcpy (plat, th, sizeof(*plat));
     save_p += sizeof(*plat);
     plat->sector = (sector_t *)(plat->sector - sectors);
     continue;
 }
 if (th->function.acp1 == (actionf_p1)T_LightFlash)
 {
     *save_p++ = tc_flash;
     save_p += (4 - ((int) save_p & 3)) & 3;
     flash = (lightflash_t *)save_p;
     memcpy (flash, th, sizeof(*flash));
     save_p += sizeof(*flash);
     flash->sector = (sector_t *)(flash->sector - sectors);
     continue;
 }
 if (th->function.acp1 == (actionf_p1)T_StrobeFlash)
 {
     *save_p++ = tc_strobe;
     save_p += (4 - ((int) save_p & 3)) & 3;
     strobe = (strobe_t *)save_p;
     memcpy (strobe, th, sizeof(*strobe));
     save_p += sizeof(*strobe);
     strobe->sector = (sector_t *)(strobe->sector - sectors);
     continue;
 }
 if (th->function.acp1 == (actionf_p1)T_Glow)
 {
     *save_p++ = tc_glow;
     save_p += (4 - ((int) save_p & 3)) & 3;
     glow = (glow_t *)save_p;
     memcpy (glow, th, sizeof(*glow));
     save_p += sizeof(*glow);
     glow->sector = (sector_t *)(glow->sector - sectors);
     continue;
 }
    }
    *save_p++ = tc_endspecials;
}
void P_UnArchiveSpecials (void)
{
    byte tclass;
    ceiling_t* ceiling;
    vldoor_t* door;
    floormove_t* floor;
    plat_t* plat;
    lightflash_t* flash;
    strobe_t* strobe;
    glow_t* glow;
    while (1)
    {
 tclass = *save_p++;
 switch (tclass)
 {
   case tc_endspecials:
     return;
   case tc_ceiling:
     save_p += (4 - ((int) save_p & 3)) & 3;
     ceiling = Z_Malloc (sizeof(*ceiling), 50, ((void *)0));
     memcpy (ceiling, save_p, sizeof(*ceiling));
     save_p += sizeof(*ceiling);
     ceiling->sector = &sectors[(int)ceiling->sector];
     ceiling->sector->specialdata = ceiling;
     if (ceiling->thinker.function.acp1)
  ceiling->thinker.function.acp1 = (actionf_p1)T_MoveCeiling;
     P_AddThinker (&ceiling->thinker);
     P_AddActiveCeiling(ceiling);
     break;
   case tc_door:
     save_p += (4 - ((int) save_p & 3)) & 3;
     door = Z_Malloc (sizeof(*door), 50, ((void *)0));
     memcpy (door, save_p, sizeof(*door));
     save_p += sizeof(*door);
     door->sector = &sectors[(int)door->sector];
     door->sector->specialdata = door;
     door->thinker.function.acp1 = (actionf_p1)T_VerticalDoor;
     P_AddThinker (&door->thinker);
     break;
   case tc_floor:
     save_p += (4 - ((int) save_p & 3)) & 3;
     floor = Z_Malloc (sizeof(*floor), 50, ((void *)0));
     memcpy (floor, save_p, sizeof(*floor));
     save_p += sizeof(*floor);
     floor->sector = &sectors[(int)floor->sector];
     floor->sector->specialdata = floor;
     floor->thinker.function.acp1 = (actionf_p1)T_MoveFloor;
     P_AddThinker (&floor->thinker);
     break;
   case tc_plat:
     save_p += (4 - ((int) save_p & 3)) & 3;
     plat = Z_Malloc (sizeof(*plat), 50, ((void *)0));
     memcpy (plat, save_p, sizeof(*plat));
     save_p += sizeof(*plat);
     plat->sector = &sectors[(int)plat->sector];
     plat->sector->specialdata = plat;
     if (plat->thinker.function.acp1)
  plat->thinker.function.acp1 = (actionf_p1)T_PlatRaise;
     P_AddThinker (&plat->thinker);
     P_AddActivePlat(plat);
     break;
   case tc_flash:
     save_p += (4 - ((int) save_p & 3)) & 3;
     flash = Z_Malloc (sizeof(*flash), 50, ((void *)0));
     memcpy (flash, save_p, sizeof(*flash));
     save_p += sizeof(*flash);
     flash->sector = &sectors[(int)flash->sector];
     flash->thinker.function.acp1 = (actionf_p1)T_LightFlash;
     P_AddThinker (&flash->thinker);
     break;
   case tc_strobe:
     save_p += (4 - ((int) save_p & 3)) & 3;
     strobe = Z_Malloc (sizeof(*strobe), 50, ((void *)0));
     memcpy (strobe, save_p, sizeof(*strobe));
     save_p += sizeof(*strobe);
     strobe->sector = &sectors[(int)strobe->sector];
     strobe->thinker.function.acp1 = (actionf_p1)T_StrobeFlash;
     P_AddThinker (&strobe->thinker);
     break;
   case tc_glow:
     save_p += (4 - ((int) save_p & 3)) & 3;
     glow = Z_Malloc (sizeof(*glow), 50, ((void *)0));
     memcpy (glow, save_p, sizeof(*glow));
     save_p += sizeof(*glow);
     glow->sector = &sectors[(int)glow->sector];
     glow->thinker.function.acp1 = (actionf_p1)T_Glow;
     P_AddThinker (&glow->thinker);
     break;
   default:
     I_Error ("P_UnarchiveSpecials:Unknown tclass %i "
       "in savegame",tclass);
 }
    }
}
