void P_LoadBlockMap (int lump)
{
    int i;
    int count;
    blockmaplump = W_CacheLumpNum (lump,50);
    blockmap = blockmaplump+4;
    count = W_LumpLength (lump)/2;
    for (i=0 ; i<count ; i++)
 blockmaplump[i] = (blockmaplump[i]);
    bmaporgx = blockmaplump[0]<<16;
    bmaporgy = blockmaplump[1]<<16;
    bmapwidth = blockmaplump[2];
    bmapheight = blockmaplump[3];
    count = sizeof(*blocklinks)* bmapwidth*bmapheight;
    blocklinks = Z_Malloc (count,50, 0);
    memset (blocklinks, 0, count);
}
void P_GroupLines (void)
{
    line_t** linebuffer;
    int i;
    int j;
    int total;
    line_t* li;
    sector_t* sector;
    subsector_t* ss;
    seg_t* seg;
    fixed_t bbox[4];
    int block;
    ss = subsectors;
    for (i=0 ; i<numsubsectors ; i++, ss++)
    {
 seg = &segs[ss->firstline];
 ss->sector = seg->sidedef->sector;
    }
    li = lines;
    total = 0;
    for (i=0 ; i<numlines ; i++, li++)
    {
 total++;
 li->frontsector->linecount++;
 if (li->backsector && li->backsector != li->frontsector)
 {
     li->backsector->linecount++;
     total++;
 }
    }
    linebuffer = Z_Malloc (total*4, 50, 0);
    sector = sectors;
    for (i=0 ; i<numsectors ; i++, sector++)
    {
 M_ClearBox (bbox);
 sector->lines = linebuffer;
 li = lines;
 for (j=0 ; j<numlines ; j++, li++)
 {
     if (li->frontsector == sector || li->backsector == sector)
     {
  *linebuffer++ = li;
  M_AddToBox (bbox, li->v1->x, li->v1->y);
  M_AddToBox (bbox, li->v2->x, li->v2->y);
     }
 }
 if (linebuffer - sector->lines != sector->linecount)
     I_Error ("P_GroupLines: miscounted");
 sector->soundorg.x = (bbox[BOXRIGHT]+bbox[BOXLEFT])/2;
 sector->soundorg.y = (bbox[BOXTOP]+bbox[BOXBOTTOM])/2;
 block = (bbox[BOXTOP]-bmaporgy+32*(1<<16))>>(16 +7);
 block = block >= bmapheight ? bmapheight-1 : block;
 sector->blockbox[BOXTOP]=block;
 block = (bbox[BOXBOTTOM]-bmaporgy-32*(1<<16))>>(16 +7);
 block = block < 0 ? 0 : block;
 sector->blockbox[BOXBOTTOM]=block;
 block = (bbox[BOXRIGHT]-bmaporgx+32*(1<<16))>>(16 +7);
 block = block >= bmapwidth ? bmapwidth-1 : block;
 sector->blockbox[BOXRIGHT]=block;
 block = (bbox[BOXLEFT]-bmaporgx-32*(1<<16))>>(16 +7);
 block = block < 0 ? 0 : block;
 sector->blockbox[BOXLEFT]=block;
    }
}
void
P_SetupLevel
( int episode,
  int map,
  int playermask,
  skill_t skill)
{
    int i;
    char lumpname[9];
    int lumpnum;
    totalkills = totalitems = totalsecret = wminfo.maxfrags = 0;
    wminfo.partime = 180;
    for (i=0 ; i<4 ; i++)
    {
 players[i].killcount = players[i].secretcount
     = players[i].itemcount = 0;
    }
    players[consoleplayer].viewz = 1;
    S_Start ();
 Z_FreeTags (50, 100 -1);
    P_InitThinkers ();
    W_Reload ();
    if ( gamemode == commercial)
    {
 if (map<10)
     sprintf (lumpname,"map0%i", map);
 else
     sprintf (lumpname,"map%i", map);
    }
    else
    {
 lumpname[0] = 'E';
 lumpname[1] = '0' + episode;
 lumpname[2] = 'M';
 lumpname[3] = '0' + map;
 lumpname[4] = 0;
    }
    lumpnum = W_GetNumForName (lumpname);
    leveltime = 0;
    P_LoadBlockMap (lumpnum+ML_BLOCKMAP);
    P_LoadVertexes (lumpnum+ML_VERTEXES);
    P_LoadSectors (lumpnum+ML_SECTORS);
    P_LoadSideDefs (lumpnum+ML_SIDEDEFS);
    P_LoadLineDefs (lumpnum+ML_LINEDEFS);
    P_LoadSubsectors (lumpnum+ML_SSECTORS);
    P_LoadNodes (lumpnum+ML_NODES);
    P_LoadSegs (lumpnum+ML_SEGS);
    rejectmatrix = W_CacheLumpNum (lumpnum+ML_REJECT,50);
    P_GroupLines ();
    bodyqueslot = 0;
    deathmatch_p = deathmatchstarts;
    P_LoadThings (lumpnum+ML_THINGS);
    if (deathmatch)
    {
 for (i=0 ; i<4 ; i++)
     if (playeringame[i])
     {
  players[i].mo = ((void *)0);
  G_DeathMatchSpawnPlayer (i);
     }
    }
    iquehead = iquetail = 0;
    P_SpawnSpecials ();
    if (precache)
 R_PrecacheLevel ();
}
