void
P_ShootSpecialLine
( mobj_t* thing,
  line_t* line )
{
    int ok;
    if (!thing->player)
    {
 ok = 0;
 switch(line->special)
 {
   case 46:
     ok = 1;
     break;
 }
 if (!ok)
     return;
    }
    switch(line->special)
    {
      case 24:
 EV_DoFloor(line,raiseFloor);
 P_ChangeSwitchTexture(line,0);
 break;
      case 46:
 EV_DoDoor(line,open);
 P_ChangeSwitchTexture(line,1);
 break;
      case 47:
 EV_DoPlat(line,raiseToNearestAndChange,0);
 P_ChangeSwitchTexture(line,0);
 break;
    }
}
void P_PlayerInSpecialSector (player_t* player)
{
    sector_t* sector;
    sector = player->mo->subsector->sector;
    if (player->mo->z != sector->floorheight)
 return;
    switch (sector->special)
    {
      case 5:
 if (!player->powers[pw_ironfeet])
     if (!(leveltime&0x1f))
  P_DamageMobj (player->mo, ((void *)0), ((void *)0), 10);
 break;
      case 7:
 if (!player->powers[pw_ironfeet])
     if (!(leveltime&0x1f))
  P_DamageMobj (player->mo, ((void *)0), ((void *)0), 5);
 break;
      case 16:
      case 4:
 if (!player->powers[pw_ironfeet]
     || (P_Random()<5) )
 {
     if (!(leveltime&0x1f))
  P_DamageMobj (player->mo, ((void *)0), ((void *)0), 20);
 }
 break;
      case 9:
 player->secretcount++;
 sector->special = 0;
 break;
      case 11:
 player->cheats &= ~CF_GODMODE;
 if (!(leveltime&0x1f))
     P_DamageMobj (player->mo, ((void *)0), ((void *)0), 20);
 if (player->health <= 10)
     G_ExitLevel();
 break;
      default:
 I_Error ("P_PlayerInSpecialSector: "
   "unknown special %i",
   sector->special);
 break;
    };
}
boolean levelTimer;
int levelTimeCount;
void P_UpdateSpecials (void)
{
    anim_t* anim;
    int pic;
    int i;
    line_t* line;
    if (levelTimer == true)
    {
 levelTimeCount--;
 if (!levelTimeCount)
     G_ExitLevel();
    }
    for (anim = anims ; anim < lastanim ; anim++)
    {
 for (i=anim->basepic ; i<anim->basepic+anim->numpics ; i++)
 {
     pic = anim->basepic + ( (leveltime/anim->speed + i)%anim->numpics );
     if (anim->istexture)
  texturetranslation[i] = pic;
     else
  flattranslation[i] = pic;
 }
    }
    for (i = 0; i < numlinespecials; i++)
    {
 line = linespeciallist[i];
 switch(line->special)
 {
   case 48:
     sides[line->sidenum[0]].textureoffset += (1<<16);
     break;
 }
    }
    for (i = 0; i < 16; i++)
 if (buttonlist[i].btimer)
 {
     buttonlist[i].btimer--;
     if (!buttonlist[i].btimer)
     {
  switch(buttonlist[i].where)
  {
    case top:
      sides[buttonlist[i].line->sidenum[0]].toptexture =
   buttonlist[i].btexture;
      break;
    case middle:
      sides[buttonlist[i].line->sidenum[0]].midtexture =
   buttonlist[i].btexture;
      break;
    case bottom:
      sides[buttonlist[i].line->sidenum[0]].bottomtexture =
   buttonlist[i].btexture;
      break;
  }
  S_StartSound((mobj_t *)&buttonlist[i].soundorg,sfx_swtchn);
  memset(&buttonlist[i],0,sizeof(button_t));
     }
 }
}
int EV_DoDonut(line_t* line)
{
    sector_t* s1;
    sector_t* s2;
    sector_t* s3;
    int secnum;
    int rtn;
    int i;
    floormove_t* floor;
    secnum = -1;
    rtn = 0;
    while ((secnum = P_FindSectorFromLineTag(line,secnum)) >= 0)
    {
 s1 = &sectors[secnum];
 if (s1->specialdata)
     continue;
 rtn = 1;
 s2 = getNextSector(s1->lines[0],s1);
 for (i = 0;i < s2->linecount;i++)
 {
     if ((!s2->lines[i]->flags & 4) ||
  (s2->lines[i]->backsector == s1))
  continue;
     s3 = s2->lines[i]->backsector;
     floor = Z_Malloc (sizeof(*floor), 51, 0);
     P_AddThinker (&floor->thinker);
     s2->specialdata = floor;
     floor->thinker.function.acp1 = (actionf_p1) T_MoveFloor;
     floor->type = donutRaise;
     floor->crush = false;
     floor->direction = 1;
     floor->sector = s2;
     floor->speed = (1<<16) / 2;
     floor->texture = s3->floorpic;
     floor->newspecial = 0;
     floor->floordestheight = s3->floorheight;
     floor = Z_Malloc (sizeof(*floor), 51, 0);
     P_AddThinker (&floor->thinker);
     s1->specialdata = floor;
     floor->thinker.function.acp1 = (actionf_p1) T_MoveFloor;
     floor->type = lowerFloor;
     floor->crush = false;
     floor->direction = -1;
     floor->sector = s1;
     floor->speed = (1<<16) / 2;
     floor->floordestheight = s3->floorheight;
     break;
 }
    }
    return rtn;
}
short numlinespecials;
line_t* linespeciallist[64];
void P_SpawnSpecials (void)
{
    sector_t* sector;
    int i;
    int episode;
    episode = 1;
    if (W_CheckNumForName("texture2") >= 0)
 episode = 2;
    levelTimer = false;
    i = M_CheckParm("-avg");
    if (i && deathmatch)
    {
 levelTimer = true;
 levelTimeCount = 20 * 60 * 35;
    }
    i = M_CheckParm("-timer");
    if (i && deathmatch)
    {
 int time;
 time = atoi(myargv[i+1]) * 60 * 35;
 levelTimer = true;
 levelTimeCount = time;
    }
    sector = sectors;
    for (i=0 ; i<numsectors ; i++, sector++)
    {
 if (!sector->special)
     continue;
 switch (sector->special)
 {
   case 1:
     P_SpawnLightFlash (sector);
     break;
   case 2:
     P_SpawnStrobeFlash(sector,15,0);
     break;
   case 3:
     P_SpawnStrobeFlash(sector,35,0);
     break;
   case 4:
     P_SpawnStrobeFlash(sector,15,0);
     sector->special = 4;
     break;
   case 8:
     P_SpawnGlowingLight(sector);
     break;
   case 9:
     totalsecret++;
     break;
   case 10:
     P_SpawnDoorCloseIn30 (sector);
     break;
   case 12:
     P_SpawnStrobeFlash (sector, 35, 1);
     break;
   case 13:
     P_SpawnStrobeFlash (sector, 15, 1);
     break;
   case 14:
     P_SpawnDoorRaiseIn5Mins (sector, i);
     break;
   case 17:
     P_SpawnFireFlicker(sector);
     break;
 }
    }
    numlinespecials = 0;
    for (i = 0;i < numlines; i++)
    {
 switch(lines[i].special)
 {
   case 48:
     linespeciallist[numlinespecials] = &lines[i];
     numlinespecials++;
     break;
 }
    }
    for (i = 0;i < 30;i++)
 activeceilings[i] = ((void *)0);
    for (i = 0;i < 30;i++)
 activeplats[i] = ((void *)0);
    for (i = 0;i < 16;i++)
 memset(&buttonlist[i],0,sizeof(button_t));
}
