static const char
rcsid[] = "$Id: p_telept.c,v 1.3 1997/01/28 22:08:29 b1 Exp $";
int
EV_Teleport
( line_t* line,
  int side,
  mobj_t* thing )
{
    int i;
    int tag;
    mobj_t* m;
    mobj_t* fog;
    unsigned an;
    thinker_t* thinker;
    sector_t* sector;
    fixed_t oldx;
    fixed_t oldy;
    fixed_t oldz;
    if (thing->flags & MF_MISSILE)
 return 0;
    if (side == 1)
 return 0;
    tag = line->tag;
    for (i = 0; i < numsectors; i++)
    {
 if (sectors[ i ].tag == tag )
 {
     thinker = thinkercap.next;
     for (thinker = thinkercap.next;
   thinker != &thinkercap;
   thinker = thinker->next)
     {
  if (thinker->function.acp1 != (actionf_p1)P_MobjThinker)
      continue;
  m = (mobj_t *)thinker;
  if (m->type != MT_TELEPORTMAN )
      continue;
  sector = m->subsector->sector;
  if (sector-sectors != i )
      continue;
  oldx = thing->x;
  oldy = thing->y;
  oldz = thing->z;
  if (!P_TeleportMove (thing, m->x, m->y))
      return 0;
  thing->z = thing->floorz;
  if (thing->player)
      thing->player->viewz = thing->z+thing->player->viewheight;
  fog = P_SpawnMobj (oldx, oldy, oldz, MT_TFOG);
  S_StartSound (fog, sfx_telept);
  an = m->angle >> 19;
  fog = P_SpawnMobj (m->x+20*finecosine[an], m->y+20*finesine[an]
       , thing->z, MT_TFOG);
  S_StartSound (fog, sfx_telept);
  if (thing->player)
      thing->reactiontime = 18;
  thing->angle = m->angle;
  thing->momx = thing->momy = thing->momz = 0;
  return 1;
     }
 }
    }
    return 0;
}
static const char
rcsid[] = "$Id: p_tick.c,v 1.4 1997/02/03 16:47:55 b1 Exp $";
int leveltime;
thinker_t thinkercap;
void P_InitThinkers (void)
{
    thinkercap.prev = thinkercap.next = &thinkercap;
}
void P_AddThinker (thinker_t* thinker)
{
    thinkercap.prev->next = thinker;
    thinker->next = &thinkercap;
    thinker->prev = thinkercap.prev;
    thinkercap.prev = thinker;
}
void P_RemoveThinker (thinker_t* thinker)
{
  thinker->function.acv = (actionf_v)(-1);
}
void P_AllocateThinker (thinker_t* thinker)
{
}
void P_RunThinkers (void)
{
    thinker_t* currentthinker;
    currentthinker = thinkercap.next;
    while (currentthinker != &thinkercap)
    {
 if ( currentthinker->function.acv == (actionf_v)(-1) )
 {
     currentthinker->next->prev = currentthinker->prev;
     currentthinker->prev->next = currentthinker->next;
     Z_Free (currentthinker);
 }
 else
 {
     if (currentthinker->function.acp1)
  currentthinker->function.acp1 (currentthinker);
 }
 currentthinker = currentthinker->next;
    }
}
void P_Ticker (void)
{
    int i;
    if (paused)
 return;
    if ( !netgame
  && menuactive
  && !demoplayback
  && players[consoleplayer].viewz != 1)
    {
 return;
    }
    for (i=0 ; i<4 ; i++)
 if (playeringame[i])
     P_PlayerThink (&players[i]);
    P_RunThinkers ();
    P_UpdateSpecials ();
    P_RespawnSpecials ();
    leveltime++;
}
static const char
rcsid[] = "$Id: p_user.c,v 1.3 1997/01/28 22:08:29 b1 Exp $";
boolean onground;
void
P_Thrust
( player_t* player,
  angle_t angle,
  fixed_t move )
{
    angle >>= 19;
    player->mo->momx += FixedMul(move,finecosine[angle]);
    player->mo->momy += FixedMul(move,finesine[angle]);
}
void P_CalcHeight (player_t* player)
{
    int angle;
    fixed_t bob;
    player->bob =
 FixedMul (player->mo->momx, player->mo->momx)
 + FixedMul (player->mo->momy,player->mo->momy);
    player->bob >>= 2;
    if (player->bob>0x100000)
 player->bob = 0x100000;
    if ((player->cheats & CF_NOMOMENTUM) || !onground)
    {
 player->viewz = player->mo->z + (41*(1<<16));
 if (player->viewz > player->mo->ceilingz-4*(1<<16))
     player->viewz = player->mo->ceilingz-4*(1<<16);
 player->viewz = player->mo->z + player->viewheight;
 return;
    }
    angle = (8192/20*leveltime)&(8192 -1);
    bob = FixedMul ( player->bob/2, finesine[angle]);
    if (player->playerstate == PST_LIVE)
    {
 player->viewheight += player->deltaviewheight;
 if (player->viewheight > (41*(1<<16)))
 {
     player->viewheight = (41*(1<<16));
     player->deltaviewheight = 0;
 }
 if (player->viewheight < (41*(1<<16))/2)
 {
     player->viewheight = (41*(1<<16))/2;
     if (player->deltaviewheight <= 0)
  player->deltaviewheight = 1;
 }
 if (player->deltaviewheight)
 {
     player->deltaviewheight += (1<<16)/4;
     if (!player->deltaviewheight)
  player->deltaviewheight = 1;
 }
    }
    player->viewz = player->mo->z + player->viewheight + bob;
    if (player->viewz > player->mo->ceilingz-4*(1<<16))
 player->viewz = player->mo->ceilingz-4*(1<<16);
}
void P_MovePlayer (player_t* player)
{
    ticcmd_t* cmd;
    cmd = &player->cmd;
    player->mo->angle += (cmd->angleturn<<16);
    onground = (player->mo->z <= player->mo->floorz);
    if (cmd->forwardmove && onground)
 P_Thrust (player, player->mo->angle, cmd->forwardmove*2048);
    if (cmd->sidemove && onground)
 P_Thrust (player, player->mo->angle-0x40000000, cmd->sidemove*2048);
    if ( (cmd->forwardmove || cmd->sidemove)
  && player->mo->state == &states[S_PLAY] )
    {
 P_SetMobjState (player->mo, S_PLAY_RUN1);
    }
}
void P_DeathThink (player_t* player)
{
    angle_t angle;
    angle_t delta;
    P_MovePsprites (player);
    if (player->viewheight > 6*(1<<16))
 player->viewheight -= (1<<16);
    if (player->viewheight < 6*(1<<16))
 player->viewheight = 6*(1<<16);
    player->deltaviewheight = 0;
    onground = (player->mo->z <= player->mo->floorz);
    P_CalcHeight (player);
    if (player->attacker && player->attacker != player->mo)
    {
 angle = R_PointToAngle2 (player->mo->x,
     player->mo->y,
     player->attacker->x,
     player->attacker->y);
 delta = angle - player->mo->angle;
 if (delta < (0x40000000/18) || delta > (unsigned)-(0x40000000/18))
 {
     player->mo->angle = angle;
     if (player->damagecount)
  player->damagecount--;
 }
 else if (delta < 0x80000000)
     player->mo->angle += (0x40000000/18);
 else
     player->mo->angle -= (0x40000000/18);
    }
    else if (player->damagecount)
 player->damagecount--;
    if (player->cmd.buttons & BT_USE)
 player->playerstate = PST_REBORN;
}
void P_PlayerThink (player_t* player)
{
    ticcmd_t* cmd;
    weapontype_t newweapon;
    if (player->cheats & CF_NOCLIP)
 player->mo->flags |= MF_NOCLIP;
    else
 player->mo->flags &= ~MF_NOCLIP;
    cmd = &player->cmd;
    if (player->mo->flags & MF_JUSTATTACKED)
    {
 cmd->angleturn = 0;
 cmd->forwardmove = 0xc800/512;
 cmd->sidemove = 0;
 player->mo->flags &= ~MF_JUSTATTACKED;
    }
    if (player->playerstate == PST_DEAD)
    {
 P_DeathThink (player);
 return;
    }
    if (player->mo->reactiontime)
 player->mo->reactiontime--;
    else
 P_MovePlayer (player);
    P_CalcHeight (player);
    if (player->mo->subsector->sector->special)
 P_PlayerInSpecialSector (player);
    if (cmd->buttons & BT_SPECIAL)
 cmd->buttons = 0;
    if (cmd->buttons & BT_CHANGE)
    {
 newweapon = (cmd->buttons&BT_WEAPONMASK)>>BT_WEAPONSHIFT;
 if (newweapon == wp_fist
     && player->weaponowned[wp_chainsaw]
     && !(player->readyweapon == wp_chainsaw
   && player->powers[pw_strength]))
 {
     newweapon = wp_chainsaw;
 }
 if ( (gamemode == commercial)
     && newweapon == wp_shotgun
     && player->weaponowned[wp_supershotgun]
     && player->readyweapon != wp_supershotgun)
 {
     newweapon = wp_supershotgun;
 }
 if (player->weaponowned[newweapon]
     && newweapon != player->readyweapon)
 {
     if ((newweapon != wp_plasma
   && newweapon != wp_bfg)
  || (gamemode != shareware) )
     {
  player->pendingweapon = newweapon;
     }
 }
    }
    if (cmd->buttons & BT_USE)
    {
 if (!player->usedown)
 {
     P_UseLines (player);
     player->usedown = true;
 }
    }
    else
 player->usedown = false;
    P_MovePsprites (player);
    if (player->powers[pw_strength])
 player->powers[pw_strength]++;
    if (player->powers[pw_invulnerability])
 player->powers[pw_invulnerability]--;
    if (player->powers[pw_invisibility])
 if (! --player->powers[pw_invisibility] )
     player->mo->flags &= ~MF_SHADOW;
    if (player->powers[pw_infrared])
 player->powers[pw_infrared]--;
    if (player->powers[pw_ironfeet])
 player->powers[pw_ironfeet]--;
    if (player->damagecount)
 player->damagecount--;
    if (player->bonuscount)
 player->bonuscount--;
    if (player->powers[pw_invulnerability])
    {
 if (player->powers[pw_invulnerability] > 4*32
     || (player->powers[pw_invulnerability]&8) )
     player->fixedcolormap = 32;
 else
     player->fixedcolormap = 0;
    }
    else if (player->powers[pw_infrared])
    {
 if (player->powers[pw_infrared] > 4*32
     || (player->powers[pw_infrared]&8) )
 {
     player->fixedcolormap = 1;
 }
 else
     player->fixedcolormap = 0;
    }
    else
 player->fixedcolormap = 0;
}
