void R_FillBackScreen (void)
{
    byte* src;
    byte* dest;
    int x;
    int y;
    patch_t* patch;
    char name1[] = "FLOOR7_2";
    char name2[] = "GRNROCK";
    char* name;
    if (scaledviewwidth == 320)
 return;
    if ( gamemode == commercial)
 name = name2;
    else
 name = name1;
    src = W_CacheLumpName (name, 101);
    dest = screens[1];
    for (y=0 ; y<200 -32 ; y++)
    {
 for (x=0 ; x<320/64 ; x++)
 {
     memcpy (dest, src+((y&63)<<6), 64);
     dest += 64;
 }
 if (320&63)
 {
     memcpy (dest, src+((y&63)<<6), 320&63);
     dest += (320&63);
 }
    }
    patch = W_CacheLumpName ("brdr_t",101);
    for (x=0 ; x<scaledviewwidth ; x+=8)
 V_DrawPatch (viewwindowx+x,viewwindowy-8,1,patch);
    patch = W_CacheLumpName ("brdr_b",101);
    for (x=0 ; x<scaledviewwidth ; x+=8)
 V_DrawPatch (viewwindowx+x,viewwindowy+viewheight,1,patch);
    patch = W_CacheLumpName ("brdr_l",101);
    for (y=0 ; y<viewheight ; y+=8)
 V_DrawPatch (viewwindowx-8,viewwindowy+y,1,patch);
    patch = W_CacheLumpName ("brdr_r",101);
    for (y=0 ; y<viewheight ; y+=8)
 V_DrawPatch (viewwindowx+scaledviewwidth,viewwindowy+y,1,patch);
    V_DrawPatch (viewwindowx-8,
   viewwindowy-8,
   1,
   W_CacheLumpName ("brdr_tl",101));
    V_DrawPatch (viewwindowx+scaledviewwidth,
   viewwindowy-8,
   1,
   W_CacheLumpName ("brdr_tr",101));
    V_DrawPatch (viewwindowx-8,
   viewwindowy+viewheight,
   1,
   W_CacheLumpName ("brdr_bl",101));
    V_DrawPatch (viewwindowx+scaledviewwidth,
   viewwindowy+viewheight,
   1,
   W_CacheLumpName ("brdr_br",101));
}
