    if (scaledviewwidth == 320)
 return;
    top = ((200 -32)-viewheight)/2;
    side = (320 -scaledviewwidth)/2;
    R_VideoErase (0, top*320 +side);
    ofs = (viewheight+top)*320 -side;
    R_VideoErase (ofs, top*320 +side);
    ofs = top*320 + 320 -side;
