void
R_AddPointToBox
( int x,
  int y,
  fixed_t* box )
{
    if (x< box[BOXLEFT])
 box[BOXLEFT] = x;
    if (x> box[BOXRIGHT])
 box[BOXRIGHT] = x;
    if (y< box[BOXBOTTOM])
 box[BOXBOTTOM] = y;
    if (y> box[BOXTOP])
 box[BOXTOP] = y;
}
int
R_PointOnSide
( fixed_t x,
  fixed_t y,
  node_t* node )
{
    fixed_t dx;
    fixed_t dy;
    fixed_t left;
    fixed_t right;
    if (!node->dx)
    {
 if (x <= node->x)
     return node->dy > 0;
 return node->dy < 0;
    }
    if (!node->dy)
    {
 if (y <= node->y)
     return node->dx < 0;
 return node->dx > 0;
    }
    dx = (x - node->x);
    dy = (y - node->y);
    if ( (node->dy ^ node->dx ^ dx ^ dy)&0x80000000 )
    {
 if ( (node->dy ^ dx) & 0x80000000 )
 {
     return 1;
 }
 return 0;
    }
    left = FixedMul ( node->dy>>16 , dx );
    right = FixedMul ( dy , node->dx>>16 );
    if (right < left)
    {
 return 0;
    }
    return 1;
}
int
R_PointOnSegSide
( fixed_t x,
  fixed_t y,
  seg_t* line )
{
    fixed_t lx;
    fixed_t ly;
    fixed_t ldx;
    fixed_t ldy;
    fixed_t dx;
    fixed_t dy;
    fixed_t left;
    fixed_t right;
    lx = line->v1->x;
    ly = line->v1->y;
    ldx = line->v2->x - lx;
    ldy = line->v2->y - ly;
    if (!ldx)
    {
 if (x <= lx)
     return ldy > 0;
 return ldy < 0;
    }
    if (!ldy)
    {
 if (y <= ly)
     return ldx < 0;
 return ldx > 0;
    }
    dx = (x - lx);
    dy = (y - ly);
    if ( (ldy ^ ldx ^ dx ^ dy)&0x80000000 )
    {
 if ( (ldy ^ dx) & 0x80000000 )
 {
     return 1;
 }
 return 0;
    }
    left = FixedMul ( ldy>>16 , dx );
    right = FixedMul ( dy , ldx>>16 );
    if (right < left)
    {
 return 0;
    }
    return 1;
}
angle_t
R_PointToAngle
( fixed_t x,
  fixed_t y )
{
    x -= viewx;
    y -= viewy;
    if ( (!x) && (!y) )
 return 0;
    if (x>= 0)
    {
 if (y>= 0)
 {
     if (x>y)
     {
  return tantoangle[ SlopeDiv(y,x)];
     }
     else
     {
  return 0x40000000 -1-tantoangle[ SlopeDiv(x,y)];
     }
 }
 else
 {
     y = -y;
     if (x>y)
     {
  return -tantoangle[SlopeDiv(y,x)];
     }
     else
     {
  return 0xc0000000 +tantoangle[ SlopeDiv(x,y)];
     }
 }
    }
    else
    {
 x = -x;
 if (y>= 0)
 {
     if (x>y)
     {
  return 0x80000000 -1-tantoangle[ SlopeDiv(y,x)];
     }
     else
     {
  return 0x40000000 + tantoangle[ SlopeDiv(x,y)];
     }
 }
 else
 {
     y = -y;
     if (x>y)
     {
  return 0x80000000 +tantoangle[ SlopeDiv(y,x)];
     }
     else
     {
  return 0xc0000000 -1-tantoangle[ SlopeDiv(x,y)];
     }
 }
    }
    return 0;
}
angle_t
R_PointToAngle2
( fixed_t x1,
  fixed_t y1,
  fixed_t x2,
  fixed_t y2 )
{
    viewx = x1;
    viewy = y1;
    return R_PointToAngle (x2, y2);
}
fixed_t
R_PointToDist
( fixed_t x,
  fixed_t y )
{
    int angle;
    fixed_t dx;
    fixed_t dy;
    fixed_t temp;
    fixed_t dist;
    dx = abs(x - viewx);
    dy = abs(y - viewy);
    if (dy>dx)
    {
 temp = dx;
 dx = dy;
 dy = temp;
    }
    angle = (tantoangle[ FixedDiv(dy,dx)>>(16 -11) ]+0x40000000) >> 19;
    dist = FixedDiv (dx, finesine[angle] );
    return dist;
}
void R_InitPointToAngle (void)
{
}
fixed_t R_ScaleFromGlobalAngle (angle_t visangle)
{
    fixed_t scale;
    int anglea;
    int angleb;
    int sinea;
    int sineb;
    fixed_t num;
    int den;
    anglea = 0x40000000 + (visangle-viewangle);
    angleb = 0x40000000 + (visangle-rw_normalangle);
    sinea = finesine[anglea>>19];
    sineb = finesine[angleb>>19];
    num = FixedMul(projection,sineb)<<detailshift;
    den = FixedMul(rw_distance,sinea);
    if (den > num>>16)
    {
 scale = FixedDiv (num, den);
 if (scale > 64*(1<<16))
     scale = 64*(1<<16);
 else if (scale < 256)
     scale = 256;
    }
    else
 scale = 64*(1<<16);
    return scale;
}
void R_InitTables (void)
{
}
void R_InitTextureMapping (void)
{
    int i;
    int x;
    int t;
    fixed_t focallength;
    focallength = FixedDiv (centerxfrac,
       finetangent[8192/4+2048/2] );
    for (i=0 ; i<8192/2 ; i++)
    {
 if (finetangent[i] > (1<<16)*2)
     t = -1;
 else if (finetangent[i] < -(1<<16)*2)
     t = viewwidth+1;
 else
 {
     t = FixedMul (finetangent[i], focallength);
     t = (centerxfrac - t+(1<<16)-1)>>16;
     if (t < -1)
  t = -1;
     else if (t>viewwidth+1)
  t = viewwidth+1;
 }
 viewangletox[i] = t;
    }
    for (x=0;x<=viewwidth;x++)
    {
 i = 0;
 while (viewangletox[i]>x)
     i++;
 xtoviewangle[x] = (i<<19)-0x40000000;
    }
    for (i=0 ; i<8192/2 ; i++)
    {
 t = FixedMul (finetangent[i], focallength);
 t = centerx - t;
 if (viewangletox[i] == -1)
     viewangletox[i] = 0;
 else if (viewangletox[i] == viewwidth+1)
     viewangletox[i] = viewwidth;
    }
    clipangle = xtoviewangle[0];
}
void R_InitLightTables (void)
{
    int i;
    int j;
    int level;
    int startmap;
    int scale;
    for (i=0 ; i< 16 ; i++)
    {
 startmap = ((16 -1-i)*2)*32/16;
 for (j=0 ; j<128 ; j++)
 {
     scale = FixedDiv ((320/2*(1<<16)), (j+1)<<20);
     scale >>= 12;
     level = startmap - scale/2;
     if (level < 0)
  level = 0;
     if (level >= 32)
  level = 32 -1;
     zlight[i][j] = colormaps + level*256;
 }
    }
}
boolean setsizeneeded;
int setblocks;
int setdetail;
void
R_SetViewSize
( int blocks,
  int detail )
{
    setsizeneeded = true;
    setblocks = blocks;
    setdetail = detail;
}
void R_ExecuteSetViewSize (void)
{
    fixed_t cosadj;
    fixed_t dy;
    int i;
    int j;
    int level;
    int startmap;
    setsizeneeded = false;
    if (setblocks == 11)
    {
 scaledviewwidth = 320;
 viewheight = 200;
    }
    else
    {
 scaledviewwidth = setblocks*32;
 viewheight = (setblocks*168/10)&~7;
    }
    detailshift = setdetail;
    viewwidth = scaledviewwidth>>detailshift;
    centery = viewheight/2;
    centerx = viewwidth/2;
    centerxfrac = centerx<<16;
    centeryfrac = centery<<16;
    projection = centerxfrac;
    if (!detailshift)
    {
 colfunc = basecolfunc = R_DrawColumn;
 fuzzcolfunc = R_DrawFuzzColumn;
 transcolfunc = R_DrawTranslatedColumn;
 spanfunc = R_DrawSpan;
    }
    else
    {
 colfunc = basecolfunc = R_DrawColumnLow;
 fuzzcolfunc = R_DrawFuzzColumn;
 transcolfunc = R_DrawTranslatedColumn;
 spanfunc = R_DrawSpanLow;
    }
    R_InitBuffer (scaledviewwidth, viewheight);
    R_InitTextureMapping ();
    pspritescale = (1<<16)*viewwidth/320;
    pspriteiscale = (1<<16)*320/viewwidth;
    for (i=0 ; i<viewwidth ; i++)
 screenheightarray[i] = viewheight;
    for (i=0 ; i<viewheight ; i++)
    {
 dy = ((i-viewheight/2)<<16)+(1<<16)/2;
 dy = abs(dy);
 yslope[i] = FixedDiv ( (viewwidth<<detailshift)/2*(1<<16), dy);
    }
    for (i=0 ; i<viewwidth ; i++)
    {
 cosadj = abs(finecosine[xtoviewangle[i]>>19]);
 distscale[i] = FixedDiv ((1<<16),cosadj);
    }
    for (i=0 ; i< 16 ; i++)
    {
 startmap = ((16 -1-i)*2)*32/16;
 for (j=0 ; j<48 ; j++)
 {
     level = startmap - j*320/(viewwidth<<detailshift)/2;
     if (level < 0)
  level = 0;
     if (level >= 32)
  level = 32 -1;
     scalelight[i][j] = colormaps + level*256;
 }
    }
}
