void R_RenderPlayerView (player_t* player)
{
    R_SetupFrame (player);
    R_ClearClipSegs ();
    R_ClearDrawSegs ();
    R_ClearPlanes ();
    R_ClearSprites ();
    NetUpdate ();
    R_RenderBSPNode (numnodes-1);
    NetUpdate ();
    R_DrawPlanes ();
    NetUpdate ();
    R_DrawMasked ();
    NetUpdate ();
}
static const char
rcsid[] = "$Id: r_plane.c,v 1.4 1997/02/03 16:47:55 b1 Exp $";
