fixed_t cachedystep[200];
void R_InitPlanes (void)
{
}
void
R_MapPlane
( int y,
  int x1,
  int x2 )
{
    angle_t angle;
    fixed_t distance;
    fixed_t length;
    unsigned index;
    if (x2 < x1
 || x1<0
 || x2>=viewwidth
 || (unsigned)y>viewheight)
    {
 I_Error ("R_MapPlane: %i, %i at %i",x1,x2,y);
    }
    if (planeheight != cachedheight[y])
    {
 cachedheight[y] = planeheight;
 distance = cacheddistance[y] = FixedMul (planeheight, yslope[y]);
 ds_xstep = cachedxstep[y] = FixedMul (distance,basexscale);
 ds_ystep = cachedystep[y] = FixedMul (distance,baseyscale);
    }
    else
    {
 distance = cacheddistance[y];
 ds_xstep = cachedxstep[y];
 ds_ystep = cachedystep[y];
    }
    length = FixedMul (distance,distscale[x1]);
    angle = (viewangle + xtoviewangle[x1])>>19;
    ds_xfrac = viewx + FixedMul(finecosine[angle], length);
    ds_yfrac = -viewy - FixedMul(finesine[angle], length);
    if (fixedcolormap)
 ds_colormap = fixedcolormap;
    else
    {
 index = distance >> 20;
 if (index >= 128 )
     index = 128 -1;
 ds_colormap = planezlight[index];
    }
    ds_y = y;
    ds_x1 = x1;
    ds_x2 = x2;
    spanfunc ();
}
void R_ClearPlanes (void)
{
    int i;
    angle_t angle;
    for (i=0 ; i<viewwidth ; i++)
    {
 floorclip[i] = viewheight;
 ceilingclip[i] = -1;
    }
    lastvisplane = visplanes;
    lastopening = openings;
    memset (cachedheight, 0, sizeof(cachedheight));
    angle = (viewangle-0x40000000)>>19;
    basexscale = FixedDiv (finecosine[angle],centerxfrac);
    baseyscale = -FixedDiv (finesine[angle],centerxfrac);
}
visplane_t*
R_FindPlane
( fixed_t height,
  int picnum,
  int lightlevel )
{
    visplane_t* check;
    if (picnum == skyflatnum)
    {
 height = 0;
 lightlevel = 0;
    }
    for (check=visplanes; check<lastvisplane; check++)
    {
 if (height == check->height
     && picnum == check->picnum
     && lightlevel == check->lightlevel)
 {
     break;
 }
    }
    if (check < lastvisplane)
 return check;
    if (lastvisplane - visplanes == 128)
 I_Error ("R_FindPlane: no more visplanes");
    lastvisplane++;
    check->height = height;
    check->picnum = picnum;
    check->lightlevel = lightlevel;
    check->minx = 320;
    check->maxx = -1;
    memset (check->top,0xff,sizeof(check->top));
    return check;
}
visplane_t*
R_CheckPlane
( visplane_t* pl,
  int start,
  int stop )
{
    int intrl;
    int intrh;
    int unionl;
    int unionh;
    int x;
    if (start < pl->minx)
    {
 intrl = pl->minx;
 unionl = start;
    }
    else
    {
 unionl = pl->minx;
 intrl = start;
    }
    if (stop > pl->maxx)
    {
 intrh = pl->maxx;
 unionh = stop;
    }
    else
    {
 unionh = pl->maxx;
 intrh = stop;
    }
    for (x=intrl ; x<= intrh ; x++)
 if (pl->top[x] != 0xff)
     break;
    if (x > intrh)
    {
 pl->minx = unionl;
 pl->maxx = unionh;
 return pl;
    }
    lastvisplane->height = pl->height;
    lastvisplane->picnum = pl->picnum;
    lastvisplane->lightlevel = pl->lightlevel;
    pl = lastvisplane++;
    pl->minx = start;
    pl->maxx = stop;
    memset (pl->top,0xff,sizeof(pl->top));
    return pl;
}
void
R_MakeSpans
( int x,
  int t1,
  int b1,
  int t2,
  int b2 )
{
    while (t1 < t2 && t1<=b1)
    {
 R_MapPlane (t1,spanstart[t1],x-1);
 t1++;
    }
    while (b1 > b2 && b1>=t1)
    {
 R_MapPlane (b1,spanstart[b1],x-1);
 b1--;
    }
    while (t2 < t1 && t2<=b2)
    {
 spanstart[t2] = x;
 t2++;
    }
    while (b2 > b1 && b2>=t2)
    {
 spanstart[b2] = x;
 b2--;
    }
}
void R_DrawPlanes (void)
{
    visplane_t* pl;
    int light;
    int x;
    int stop;
    int angle;
    if (ds_p - drawsegs > 256)
 I_Error ("R_DrawPlanes: drawsegs overflow (%i)",
   ds_p - drawsegs);
    if (lastvisplane - visplanes > 128)
 I_Error ("R_DrawPlanes: visplane overflow (%i)",
   lastvisplane - visplanes);
    if (lastopening - openings > 320*64)
 I_Error ("R_DrawPlanes: opening overflow (%i)",
   lastopening - openings);
    for (pl = visplanes ; pl < lastvisplane ; pl++)
    {
 if (pl->minx > pl->maxx)
     continue;
 if (pl->picnum == skyflatnum)
 {
     dc_iscale = pspriteiscale>>detailshift;
     dc_colormap = colormaps;
     dc_texturemid = skytexturemid;
     for (x=pl->minx ; x <= pl->maxx ; x++)
     {
  dc_yl = pl->top[x];
  dc_yh = pl->bottom[x];
  if (dc_yl <= dc_yh)
  {
      angle = (viewangle + xtoviewangle[x])>>22;
      dc_x = x;
      dc_source = R_GetColumn(skytexture, angle);
      colfunc ();
  }
     }
     continue;
 }
 ds_source = W_CacheLumpNum(firstflat +
       flattranslation[pl->picnum],
       1);
 planeheight = abs(pl->height-viewz);
 light = (pl->lightlevel >> 4)+extralight;
 if (light >= 16)
     light = 16 -1;
 if (light < 0)
     light = 0;
 planezlight = zlight[light];
 pl->top[pl->maxx+1] = 0xff;
 pl->top[pl->minx-1] = 0xff;
 stop = pl->maxx + 1;
 for (x=pl->minx ; x<= stop ; x++)
 {
     R_MakeSpans(x,pl->top[x-1],
   pl->bottom[x-1],
   pl->top[x],
   pl->bottom[x]);
 }
 { if (( (memblock_t *)( (byte *)(ds_source) - sizeof(memblock_t)))->id!=0x1d4a11) I_Error("Z_CT at ""doom_amalg.c"":%i",34903); Z_ChangeTag2(ds_source,101); };;
    }
}
