{
    int r;
    if (frame >= 29 || rotation > 8)
 I_Error("R_InstallSpriteLump: "
  "Bad frame characters in lump %i", lump);
    if ((int)frame > maxframe)
 maxframe = frame;
    if (rotation == 0)
    {
 if (sprtemp[frame].rotate == false)
     I_Error ("R_InitSprites: Sprite %s frame %c has "
       "multip rot=0 lump", spritename, 'A'+frame);
 if (sprtemp[frame].rotate == true)
     I_Error ("R_InitSprites: Sprite %s frame %c has rotations "
       "and a rot=0 lump", spritename, 'A'+frame);
 sprtemp[frame].rotate = false;
 for (r=0 ; r<8 ; r++)
 {
     sprtemp[frame].lump[r] = lump - firstspritelump;
     sprtemp[frame].flip[r] = (byte)flipped;
 }
 return;
    }
    if (sprtemp[frame].rotate == false)
 I_Error ("R_InitSprites: Sprite %s frame %c has rotations "
   "and a rot=0 lump", spritename, 'A'+frame);
    sprtemp[frame].rotate = true;
    rotation--;
    if (sprtemp[frame].lump[rotation] != -1)
 I_Error ("R_InitSprites: Sprite %s : %c : %c "
   "has two lumps mapped to it",
   spritename, 'A'+frame, '1'+rotation);
    sprtemp[frame].lump[rotation] = lump - firstspritelump;
    sprtemp[frame].flip[rotation] = (byte)flipped;
}
void R_InitSpriteDefs (char** namelist)
{
    char** check;
    int i;
    int l;
    int intname;
    int frame;
    int rotation;
    int start;
    int end;
    int patched;
    check = namelist;
    while (*check != ((void *)0))
 check++;
    numsprites = check-namelist;
    if (!numsprites)
 return;
    sprites = Z_Malloc(numsprites *sizeof(*sprites), 1, ((void *)0));
    start = firstspritelump-1;
    end = lastspritelump+1;
    for (i=0 ; i<numsprites ; i++)
    {
 spritename = namelist[i];
 memset (sprtemp,-1, sizeof(sprtemp));
 maxframe = -1;
 intname = *(int *)namelist[i];
 for (l=start+1 ; l<end ; l++)
 {
     if (*(int *)lumpinfo[l].name == intname)
     {
  frame = lumpinfo[l].name[4] - 'A';
  rotation = lumpinfo[l].name[5] - '0';
  if (modifiedgame)
      patched = W_GetNumForName (lumpinfo[l].name);
  else
      patched = l;
  R_InstallSpriteLump (patched, frame, rotation, false);
  if (lumpinfo[l].name[6])
  {
      frame = lumpinfo[l].name[6] - 'A';
      rotation = lumpinfo[l].name[7] - '0';
      R_InstallSpriteLump (l, frame, rotation, true);
  }
     }
 }
 if (maxframe == -1)
 {
     sprites[i].numframes = 0;
     continue;
 }
 maxframe++;
 for (frame = 0 ; frame < maxframe ; frame++)
 {
     switch ((int)sprtemp[frame].rotate)
     {
       case -1:
  I_Error ("R_InitSprites: No patches found "
    "for %s frame %c", namelist[i], frame+'A');
  break;
       case 0:
  break;
       case 1:
  for (rotation=0 ; rotation<8 ; rotation++)
      if (sprtemp[frame].lump[rotation] == -1)
   I_Error ("R_InitSprites: Sprite %s frame %c "
     "is missing rotations",
     namelist[i], frame+'A');
  break;
     }
 }
 sprites[i].numframes = maxframe;
 sprites[i].spriteframes =
     Z_Malloc (maxframe * sizeof(spriteframe_t), 1, ((void *)0));
 memcpy (sprites[i].spriteframes, sprtemp, maxframe*sizeof(spriteframe_t));
    }
}
vissprite_t vissprites[128];
vissprite_t* vissprite_p;
int newvissprite;
void R_InitSprites (char** namelist)
{
    int i;
    for (i=0 ; i<320 ; i++)
    {
 negonearray[i] = -1;
    }
    R_InitSpriteDefs (namelist);
}
void R_ClearSprites (void)
{
    vissprite_p = vissprites;
}
vissprite_t overflowsprite;
vissprite_t* R_NewVisSprite (void)
{
    if (vissprite_p == &vissprites[128])
 return &overflowsprite;
    vissprite_p++;
    return vissprite_p-1;
}
short* mfloorclip;
short* mceilingclip;
fixed_t spryscale;
fixed_t sprtopscreen;
void R_DrawMaskedColumn (column_t* column)
{
    int topscreen;
    int bottomscreen;
    fixed_t basetexturemid;
    basetexturemid = dc_texturemid;
    for ( ; column->topdelta != 0xff ; )
    {
 topscreen = sprtopscreen + spryscale*column->topdelta;
 bottomscreen = topscreen + spryscale*column->length;
 dc_yl = (topscreen+(1<<16)-1)>>16;
 dc_yh = (bottomscreen-1)>>16;
 if (dc_yh >= mfloorclip[dc_x])
     dc_yh = mfloorclip[dc_x]-1;
 if (dc_yl <= mceilingclip[dc_x])
     dc_yl = mceilingclip[dc_x]+1;
 if (dc_yl <= dc_yh)
 {
     dc_source = (byte *)column + 3;
     dc_texturemid = basetexturemid - (column->topdelta<<16);
     colfunc ();
 }
 column = (column_t *)( (byte *)column + column->length + 4);
    }
    dc_texturemid = basetexturemid;
}
void
R_DrawVisSprite
( vissprite_t* vis,
  int x1,
  int x2 )
{
    column_t* column;
    int texturecolumn;
    fixed_t frac;
    patch_t* patch;
    patch = W_CacheLumpNum (vis->patch+firstspritelump, 101);
    dc_colormap = vis->colormap;
    if (!dc_colormap)
    {
 colfunc = fuzzcolfunc;
    }
    else if (vis->mobjflags & MF_TRANSLATION)
    {
 colfunc = R_DrawTranslatedColumn;
 dc_translation = translationtables - 256 +
     ( (vis->mobjflags & MF_TRANSLATION) >> (MF_TRANSSHIFT-8) );
    }
    dc_iscale = abs(vis->xiscale)>>detailshift;
    dc_texturemid = vis->texturemid;
    frac = vis->startfrac;
    spryscale = vis->scale;
    sprtopscreen = centeryfrac - FixedMul(dc_texturemid,spryscale);
    for (dc_x=vis->x1 ; dc_x<=vis->x2 ; dc_x++, frac += vis->xiscale)
    {
 texturecolumn = frac>>16;
 if (texturecolumn < 0 || texturecolumn >= (patch->width))
     I_Error ("R_DrawSpriteRange: bad texturecolumn");
 column = (column_t *) ((byte *)patch +
          (patch->columnofs[texturecolumn]));
 R_DrawMaskedColumn (column);
    }
    colfunc = basecolfunc;
}
void R_ProjectSprite (mobj_t* thing)
{
    fixed_t tr_x;
    fixed_t tr_y;
    fixed_t gxt;
    fixed_t gyt;
    fixed_t tx;
    fixed_t tz;
    fixed_t xscale;
    int x1;
    int x2;
    spritedef_t* sprdef;
    spriteframe_t* sprframe;
    int lump;
    unsigned rot;
    boolean flip;
    int index;
    vissprite_t* vis;
    angle_t ang;
    fixed_t iscale;
    tr_x = thing->x - viewx;
    tr_y = thing->y - viewy;
    gxt = FixedMul(tr_x,viewcos);
    gyt = -FixedMul(tr_y,viewsin);
    tz = gxt-gyt;
    if (tz < ((1<<16)*4))
 return;
    xscale = FixedDiv(projection, tz);
    gxt = -FixedMul(tr_x,viewsin);
    gyt = FixedMul(tr_y,viewcos);
    tx = -(gyt+gxt);
    if (abs(tx)>(tz<<2))
 return;
    if ((unsigned)thing->sprite >= numsprites)
 I_Error ("R_ProjectSprite: invalid sprite number %i ",
   thing->sprite);
    sprdef = &sprites[thing->sprite];
    if ( (thing->frame&0x7fff) >= sprdef->numframes )
 I_Error ("R_ProjectSprite: invalid sprite frame %i : %i ",
   thing->sprite, thing->frame);
    sprframe = &sprdef->spriteframes[ thing->frame & 0x7fff];
    if (sprframe->rotate)
    {
 ang = R_PointToAngle (thing->x, thing->y);
 rot = (ang-thing->angle+(unsigned)(0x20000000/2)*9)>>29;
 lump = sprframe->lump[rot];
 flip = (boolean)sprframe->flip[rot];
    }
    else
    {
 lump = sprframe->lump[0];
 flip = (boolean)sprframe->flip[0];
    }
    tx -= spriteoffset[lump];
    x1 = (centerxfrac + FixedMul (tx,xscale) ) >>16;
    if (x1 > viewwidth)
 return;
    tx += spritewidth[lump];
    x2 = ((centerxfrac + FixedMul (tx,xscale) ) >>16) - 1;
    if (x2 < 0)
 return;
    vis = R_NewVisSprite ();
    vis->mobjflags = thing->flags;
    vis->scale = xscale<<detailshift;
    vis->gx = thing->x;
    vis->gy = thing->y;
    vis->gz = thing->z;
    vis->gzt = thing->z + spritetopoffset[lump];
    vis->texturemid = vis->gzt - viewz;
    vis->x1 = x1 < 0 ? 0 : x1;
    vis->x2 = x2 >= viewwidth ? viewwidth-1 : x2;
    iscale = FixedDiv ((1<<16), xscale);
    if (flip)
    {
 vis->startfrac = spritewidth[lump]-1;
 vis->xiscale = -iscale;
    }
    else
    {
 vis->startfrac = 0;
 vis->xiscale = iscale;
    }
    if (vis->x1 > x1)
 vis->startfrac += vis->xiscale*(vis->x1-x1);
    vis->patch = lump;
    if (thing->flags & MF_SHADOW)
    {
 vis->colormap = ((void *)0);
    }
    else if (fixedcolormap)
    {
 vis->colormap = fixedcolormap;
    }
    else if (thing->frame & 0x8000)
    {
 vis->colormap = colormaps;
    }
    else
    {
 index = xscale>>(12 -detailshift);
 if (index >= 48)
     index = 48 -1;
 vis->colormap = spritelights[index];
    }
}
void R_AddSprites (sector_t* sec)
{
    mobj_t* thing;
    int lightnum;
    if (sec->validcount == validcount)
 return;
    sec->validcount = validcount;
    lightnum = (sec->lightlevel >> 4)+extralight;
    if (lightnum < 0)
 spritelights = scalelight[0];
    else if (lightnum >= 16)
 spritelights = scalelight[16 -1];
    else
 spritelights = scalelight[lightnum];
    for (thing = sec->thinglist ; thing ; thing = thing->snext)
 R_ProjectSprite (thing);
}
void R_DrawPSprite (pspdef_t* psp)
{
    fixed_t tx;
    int x1;
    int x2;
    spritedef_t* sprdef;
    spriteframe_t* sprframe;
    int lump;
    boolean flip;
    vissprite_t* vis;
    vissprite_t avis;
    if ( (unsigned)psp->state->sprite >= numsprites)
 I_Error ("R_ProjectSprite: invalid sprite number %i ",
   psp->state->sprite);
    sprdef = &sprites[psp->state->sprite];
    if ( (psp->state->frame & 0x7fff) >= sprdef->numframes)
 I_Error ("R_ProjectSprite: invalid sprite frame %i : %i ",
   psp->state->sprite, psp->state->frame);
    sprframe = &sprdef->spriteframes[ psp->state->frame & 0x7fff ];
    lump = sprframe->lump[0];
    flip = (boolean)sprframe->flip[0];
    tx = psp->sx-160*(1<<16);
    tx -= spriteoffset[lump];
    x1 = (centerxfrac + FixedMul (tx,pspritescale) ) >>16;
    if (x1 > viewwidth)
 return;
    tx += spritewidth[lump];
    x2 = ((centerxfrac + FixedMul (tx, pspritescale) ) >>16) - 1;
    if (x2 < 0)
 return;
    vis = &avis;
    vis->mobjflags = 0;
    vis->texturemid = (100<<16)+(1<<16)/2-(psp->sy-spritetopoffset[lump]);
    vis->x1 = x1 < 0 ? 0 : x1;
    vis->x2 = x2 >= viewwidth ? viewwidth-1 : x2;
    vis->scale = pspritescale<<detailshift;
    if (flip)
    {
 vis->xiscale = -pspriteiscale;
 vis->startfrac = spritewidth[lump]-1;
    }
    else
    {
 vis->xiscale = pspriteiscale;
 vis->startfrac = 0;
    }
    if (vis->x1 > x1)
 vis->startfrac += vis->xiscale*(vis->x1-x1);
    vis->patch = lump;
    if (viewplayer->powers[pw_invisibility] > 4*32
 || viewplayer->powers[pw_invisibility] & 8)
    {
 vis->colormap = ((void *)0);
    }
    else if (fixedcolormap)
    {
 vis->colormap = fixedcolormap;
    }
    else if (psp->state->frame & 0x8000)
    {
 vis->colormap = colormaps;
    }
    else
    {
 vis->colormap = spritelights[48 -1];
    }
    R_DrawVisSprite (vis, vis->x1, vis->x2);
}
void R_DrawPlayerSprites (void)
{
    int i;
    int lightnum;
    pspdef_t* psp;
    lightnum =
 (viewplayer->mo->subsector->sector->lightlevel >> 4)
 +extralight;
    if (lightnum < 0)
 spritelights = scalelight[0];
    else if (lightnum >= 16)
 spritelights = scalelight[16 -1];
    else
 spritelights = scalelight[lightnum];
    mfloorclip = screenheightarray;
    mceilingclip = negonearray;
    for (i=0, psp=viewplayer->psprites;
  i<NUMPSPRITES;
  i++,psp++)
    {
 if (psp->state)
     R_DrawPSprite (psp);
    }
}
vissprite_t vsprsortedhead;
void R_SortVisSprites (void)
{
    int i;
    int count;
    vissprite_t* ds;
    vissprite_t* best;
    vissprite_t unsorted;
    fixed_t bestscale;
    count = vissprite_p - vissprites;
    unsorted.next = unsorted.prev = &unsorted;
    if (!count)
 return;
    for (ds=vissprites ; ds<vissprite_p ; ds++)
    {
 ds->next = ds+1;
 ds->prev = ds-1;
    }
    vissprites[0].prev = &unsorted;
    unsorted.next = &vissprites[0];
    (vissprite_p-1)->next = &unsorted;
    unsorted.prev = vissprite_p-1;
    vsprsortedhead.next = vsprsortedhead.prev = &vsprsortedhead;
    for (i=0 ; i<count ; i++)
    {
 bestscale = 0x7fffffff;
 for (ds=unsorted.next ; ds!= &unsorted ; ds=ds->next)
 {
     if (ds->scale < bestscale)
     {
  bestscale = ds->scale;
  best = ds;
     }
 }
 best->next->prev = best->prev;
 best->prev->next = best->next;
 best->next = &vsprsortedhead;
 best->prev = vsprsortedhead.prev;
 vsprsortedhead.prev->next = best;
 vsprsortedhead.prev = best;
    }
}
void R_DrawSprite (vissprite_t* spr)
{
    drawseg_t* ds;
    short clipbot[320];
    short cliptop[320];
    int x;
    int r1;
    int r2;
    fixed_t scale;
    fixed_t lowscale;
    int silhouette;
    for (x = spr->x1 ; x<=spr->x2 ; x++)
 clipbot[x] = cliptop[x] = -2;
    for (ds=ds_p-1 ; ds >= drawsegs ; ds--)
    {
 if (ds->x1 > spr->x2
     || ds->x2 < spr->x1
     || (!ds->silhouette
  && !ds->maskedtexturecol) )
 {
     continue;
 }
 r1 = ds->x1 < spr->x1 ? spr->x1 : ds->x1;
 r2 = ds->x2 > spr->x2 ? spr->x2 : ds->x2;
 if (ds->scale1 > ds->scale2)
 {
     lowscale = ds->scale2;
     scale = ds->scale1;
 }
 else
 {
     lowscale = ds->scale1;
     scale = ds->scale2;
 }
 if (scale < spr->scale
     || ( lowscale < spr->scale
   && !R_PointOnSegSide (spr->gx, spr->gy, ds->curline) ) )
 {
     if (ds->maskedtexturecol)
  R_RenderMaskedSegRange (ds, r1, r2);
     continue;
 }
 silhouette = ds->silhouette;
 if (spr->gz >= ds->bsilheight)
     silhouette &= ~1;
 if (spr->gzt <= ds->tsilheight)
     silhouette &= ~2;
 if (silhouette == 1)
 {
     for (x=r1 ; x<=r2 ; x++)
  if (clipbot[x] == -2)
      clipbot[x] = ds->sprbottomclip[x];
 }
 else if (silhouette == 2)
 {
     for (x=r1 ; x<=r2 ; x++)
  if (cliptop[x] == -2)
      cliptop[x] = ds->sprtopclip[x];
 }
 else if (silhouette == 3)
 {
     for (x=r1 ; x<=r2 ; x++)
     {
  if (clipbot[x] == -2)
      clipbot[x] = ds->sprbottomclip[x];
  if (cliptop[x] == -2)
      cliptop[x] = ds->sprtopclip[x];
     }
 }
    }
    for (x = spr->x1 ; x<=spr->x2 ; x++)
    {
 if (clipbot[x] == -2)
     clipbot[x] = viewheight;
 if (cliptop[x] == -2)
     cliptop[x] = -1;
    }
    mfloorclip = clipbot;
    mceilingclip = cliptop;
    R_DrawVisSprite (spr, spr->x1, spr->x2);
}
void R_DrawMasked (void)
{
    vissprite_t* spr;
    drawseg_t* ds;
    R_SortVisSprites ();
    if (vissprite_p > vissprites)
    {
 for (spr = vsprsortedhead.next ;
      spr != &vsprsortedhead ;
      spr=spr->next)
 {
     R_DrawSprite (spr);
 }
    }
    for (ds=ds_p-1 ; ds >= drawsegs ; ds--)
 if (ds->maskedtexturecol)
     R_RenderMaskedSegRange (ds, ds->x1, ds->x2);
    if (!viewangleoffset)
 R_DrawPlayerSprites ();
}
static const char
rcsid[] = "$Id: s_sound.c,v 1.6 1997/02/03 22:45:12 b1 Exp $";
const char snd_prefixen[]
= { 'P', 'P', 'A', 'S', 'S', 'S', 'M', 'M', 'M', 'S', 'S', 'S' };
extern int snd_MusicDevice;
extern int snd_SfxDevice;
extern int snd_DesiredMusicDevice;
extern int snd_DesiredSfxDevice;
typedef struct
{
    sfxinfo_t* sfxinfo;
    void* origin;
    int handle;
} channel_t;
static channel_t* channels;
int snd_SfxVolume = 15;
int snd_MusicVolume = 15;
static boolean mus_paused;
static musicinfo_t* mus_playing=0;
int numChannels;
static int nextcleanup;
int
S_getChannel
( void* origin,
  sfxinfo_t* sfxinfo );
int
S_AdjustSoundParams
( mobj_t* listener,
  mobj_t* source,
  int* vol,
  int* sep,
  int* pitch );
void S_StopChannel(int cnum);
void S_Init
( int sfxVolume,
  int musicVolume )
{
  int i;
  fprintf( stderr, "S_Init: default sfx volume %d\n", sfxVolume);
  I_SetChannels();
  S_SetSfxVolume(sfxVolume);
  S_SetMusicVolume(musicVolume);
  channels =
    (channel_t *) Z_Malloc(numChannels*sizeof(channel_t), 1, 0);
  for (i=0 ; i<numChannels ; i++)
    channels[i].sfxinfo = 0;
  mus_paused = 0;
  for (i=1 ; i<NUMSFX ; i++)
    S_sfx[i].lumpnum = S_sfx[i].usefulness = -1;
}
void S_Start(void)
{
  int cnum;
  int mnum;
  for (cnum=0 ; cnum<numChannels ; cnum++)
    if (channels[cnum].sfxinfo)
      S_StopChannel(cnum);
  mus_paused = 0;
  if (gamemode == commercial)
    mnum = mus_runnin + gamemap - 1;
  else
  {
    int spmus[]=
    {
      mus_e3m4,
      mus_e3m2,
      mus_e3m3,
      mus_e1m5,
      mus_e2m7,
      mus_e2m4,
      mus_e2m6,
      mus_e2m5,
      mus_e1m9
    };
    if (gameepisode < 4)
      mnum = mus_e1m1 + (gameepisode-1)*9 + gamemap-1;
    else
      mnum = spmus[gamemap-1];
    }
  S_ChangeMusic(mnum, true);
  nextcleanup = 15;
}
void
S_StartSoundAtVolume
( void* origin_p,
  int sfx_id,
  int volume )
{
  int rc;
  int sep;
  int pitch;
  int priority;
  sfxinfo_t* sfx;
  int cnum;
  mobj_t* origin = (mobj_t *) origin_p;
  if (sfx_id < 1 || sfx_id > NUMSFX)
    I_Error("Bad sfx #: %d", sfx_id);
  sfx = &S_sfx[sfx_id];
  if (sfx->link)
  {
    pitch = sfx->pitch;
    priority = sfx->priority;
    volume += sfx->volume;
    if (volume < 1)
      return;
    if (volume > snd_SfxVolume)
      volume = snd_SfxVolume;
  }
  else
  {
    pitch = 128;
    priority = 64;
  }
  if (origin && origin != players[consoleplayer].mo)
  {
    rc = S_AdjustSoundParams(players[consoleplayer].mo,
        origin,
        &volume,
        &sep,
        &pitch);
    if ( origin->x == players[consoleplayer].mo->x
  && origin->y == players[consoleplayer].mo->y)
    {
      sep = 128;
    }
    if (!rc)
      return;
  }
  else
  {
    sep = 128;
  }
  if (sfx_id >= sfx_sawup
      && sfx_id <= sfx_sawhit)
  {
    pitch += 8 - (M_Random()&15);
    if (pitch<0)
      pitch = 0;
    else if (pitch>255)
      pitch = 255;
  }
  else if (sfx_id != sfx_itemup
    && sfx_id != sfx_tink)
  {
    pitch += 16 - (M_Random()&31);
    if (pitch<0)
      pitch = 0;
    else if (pitch>255)
      pitch = 255;
  }
  S_StopSound(origin);
  cnum = S_getChannel(origin, sfx);
  if (cnum<0)
    return;
  if (sfx->lumpnum < 0)
    sfx->lumpnum = I_GetSfxLumpNum(sfx);
  if (!sfx->data)
  {
    fprintf( stderr,
      "S_StartSoundAtVolume: 16bit and not pre-cached - wtf?\n");
  }
  if (sfx->usefulness++ < 0)
    sfx->usefulness = 1;
  channels[cnum].handle = I_StartSound(sfx_id,
           volume,
           sep,
           pitch,
           priority);
}
void
S_StartSound
( void* origin,
  int sfx_id )
{
    S_StartSoundAtVolume(origin, sfx_id, snd_SfxVolume);
}
void S_StopSound(void *origin)
{
    int cnum;
    for (cnum=0 ; cnum<numChannels ; cnum++)
    {
 if (channels[cnum].sfxinfo && channels[cnum].origin == origin)
 {
     S_StopChannel(cnum);
     break;
 }
    }
}
void S_PauseSound(void)
{
    if (mus_playing && !mus_paused)
    {
 I_PauseSong(mus_playing->handle);
 mus_paused = true;
    }
}
void S_ResumeSound(void)
{
    if (mus_playing && mus_paused)
    {
 I_ResumeSong(mus_playing->handle);
 mus_paused = false;
    }
}
void S_UpdateSounds(void* listener_p)
{
    int audible;
    int cnum;
    int volume;
    int sep;
    int pitch;
    sfxinfo_t* sfx;
    channel_t* c;
    mobj_t* listener = (mobj_t*)listener_p;
    for (cnum=0 ; cnum<numChannels ; cnum++)
    {
 c = &channels[cnum];
 sfx = c->sfxinfo;
 if (c->sfxinfo)
 {
     if (I_SoundIsPlaying(c->handle))
     {
  volume = snd_SfxVolume;
  pitch = 128;
  sep = 128;
  if (sfx->link)
  {
      pitch = sfx->pitch;
      volume += sfx->volume;
      if (volume < 1)
      {
   S_StopChannel(cnum);
   continue;
      }
      else if (volume > snd_SfxVolume)
      {
   volume = snd_SfxVolume;
      }
  }
  if (c->origin && listener_p != c->origin)
  {
      audible = S_AdjustSoundParams(listener,
        c->origin,
        &volume,
        &sep,
        &pitch);
      if (!audible)
      {
   S_StopChannel(cnum);
      }
      else
   I_UpdateSoundParams(c->handle, volume, sep, pitch);
  }
     }
     else
     {
  S_StopChannel(cnum);
     }
 }
    }
}
void S_SetMusicVolume(int volume)
{
    if (volume < 0 || volume > 127)
    {
 I_Error("Attempt to set music volume at %d",
  volume);
    }
    I_SetMusicVolume(127);
    I_SetMusicVolume(volume);
    snd_MusicVolume = volume;
}
void S_SetSfxVolume(int volume)
{
    if (volume < 0 || volume > 127)
 I_Error("Attempt to set sfx volume at %d", volume);
    snd_SfxVolume = volume;
}
void S_StartMusic(int m_id)
{
    S_ChangeMusic(m_id, false);
}
void
S_ChangeMusic
( int musicnum,
  int looping )
{
    musicinfo_t* music;
    char namebuf[9];
    if ( (musicnum <= mus_None)
  || (musicnum >= NUMMUSIC) )
    {
 I_Error("Bad music number %d", musicnum);
    }
    else
 music = &S_music[musicnum];
    if (mus_playing == music)
 return;
    S_StopMusic();
    if (!music->lumpnum)
    {
 sprintf(namebuf, "d_%s", music->name);
 music->lumpnum = W_GetNumForName(namebuf);
    }
    music->data = (void *) W_CacheLumpNum(music->lumpnum, 3);
    music->handle = I_RegisterSong(music->data);
    I_PlaySong(music->handle, looping);
    mus_playing = music;
}
void S_StopMusic(void)
{
    if (mus_playing)
    {
 if (mus_paused)
     I_ResumeSong(mus_playing->handle);
 I_StopSong(mus_playing->handle);
 I_UnRegisterSong(mus_playing->handle);
 { if (( (memblock_t *)( (byte *)(mus_playing->data) - sizeof(memblock_t)))->id!=0x1d4a11) I_Error("Z_CT at ""doom_amalg.c"":%i",37400); Z_ChangeTag2(mus_playing->data,101); };;
 mus_playing->data = 0;
 mus_playing = 0;
    }
}
void S_StopChannel(int cnum)
{
    int i;
    channel_t* c = &channels[cnum];
    if (c->sfxinfo)
    {
 if (I_SoundIsPlaying(c->handle))
 {
     I_StopSound(c->handle);
 }
 for (i=0 ; i<numChannels ; i++)
 {
     if (cnum != i
  && c->sfxinfo == channels[i].sfxinfo)
     {
  break;
     }
 }
 c->sfxinfo->usefulness--;
 c->sfxinfo = 0;
    }
}
int
S_AdjustSoundParams
( mobj_t* listener,
  mobj_t* source,
  int* vol,
  int* sep,
  int* pitch )
{
    fixed_t approx_dist;
    fixed_t adx;
    fixed_t ady;
    angle_t angle;
    adx = abs(listener->x - source->x);
    ady = abs(listener->y - source->y);
    approx_dist = adx + ady - ((adx < ady ? adx : ady)>>1);
    if (gamemap != 8
 && approx_dist > (1200*0x10000))
    {
 return 0;
    }
    angle = R_PointToAngle2(listener->x,
       listener->y,
       source->x,
       source->y);
    if (angle > listener->angle)
 angle = angle - listener->angle;
    else
 angle = angle + (0xffffffff - listener->angle);
    angle >>= 19;
    *sep = 128 - (FixedMul((96*0x10000),finesine[angle])>>16);
    if (approx_dist < (160*0x10000))
    {
 *vol = snd_SfxVolume;
    }
    else if (gamemap == 8)
    {
 if (approx_dist > (1200*0x10000))
     approx_dist = (1200*0x10000);
 *vol = 15+ ((snd_SfxVolume-15)
      *(((1200*0x10000) - approx_dist)>>16))
     / (((1200*0x10000)-(160*0x10000))>>16);
    }
    else
    {
 *vol = (snd_SfxVolume
  * (((1200*0x10000) - approx_dist)>>16))
     / (((1200*0x10000)-(160*0x10000))>>16);
    }
    return (*vol > 0);
}
int
S_getChannel
( void* origin,
  sfxinfo_t* sfxinfo )
{
    int cnum;
    channel_t* c;
    for (cnum=0 ; cnum<numChannels ; cnum++)
    {
 if (!channels[cnum].sfxinfo)
     break;
 else if (origin && channels[cnum].origin == origin)
 {
     S_StopChannel(cnum);
     break;
 }
    }
    if (cnum == numChannels)
    {
 for (cnum=0 ; cnum<numChannels ; cnum++)
     if (channels[cnum].sfxinfo->priority >= sfxinfo->priority) break;
 if (cnum == numChannels)
 {
     return -1;
 }
 else
 {
     S_StopChannel(cnum);
 }
    }
    c = &channels[cnum];
    c->sfxinfo = sfxinfo;
    c->origin = origin;
    return cnum;
}
