extern boolean automapactive;
patch_t* sttminus;
void STlib_init(void)
{
    sttminus = (patch_t *) W_CacheLumpName("STTMINUS", 1);
}
void
STlib_initNum
( st_number_t* n,
  int x,
  int y,
  patch_t** pl,
  int* num,
  boolean* on,
  int width )
{
    n->x = x;
    n->y = y;
    n->oldnum = 0;
    n->width = width;
    n->num = num;
    n->on = on;
    n->p = pl;
}
void
STlib_drawNum
( st_number_t* n,
  boolean refresh )
{
    int numdigits = n->width;
    int num = *n->num;
    int w = (n->p[0]->width);
    int h = (n->p[0]->height);
    int x = n->x;
    int neg;
    n->oldnum = *n->num;
    neg = num < 0;
    if (neg)
    {
 if (numdigits == 2 && num < -9)
     num = -9;
 else if (numdigits == 3 && num < -99)
     num = -99;
 num = -num;
    }
    x = n->x - numdigits*w;
    if (n->y - (200 - 32*1) < 0)
 I_Error("drawNum: n->y - ST_Y < 0");
    V_CopyRect(x, n->y - (200 - 32*1), 4, w*numdigits, h, x, n->y, 0);
    if (num == 1994)
 return;
    x = n->x;
    if (!num)
 V_DrawPatch(x - w, n->y, 0, n->p[ 0 ]);
    while (num && numdigits--)
    {
 x -= w;
 V_DrawPatch(x, n->y, 0, n->p[ num % 10 ]);
 num /= 10;
    }
    if (neg)
 V_DrawPatch(x - 8, n->y, 0, sttminus);
}
void
STlib_updateNum
( st_number_t* n,
  boolean refresh )
{
    if (*n->on) STlib_drawNum(n, refresh);
}
void
STlib_initPercent
( st_percent_t* p,
  int x,
  int y,
  patch_t** pl,
  int* num,
  boolean* on,
  patch_t* percent )
{
    STlib_initNum(&p->n, x, y, pl, num, on, 3);
    p->p = percent;
}
void
STlib_updatePercent
( st_percent_t* per,
  int refresh )
{
    if (refresh && *per->n.on)
 V_DrawPatch(per->n.x, per->n.y, 0, per->p);
    STlib_updateNum(&per->n, refresh);
}
void
STlib_initMultIcon
( st_multicon_t* i,
  int x,
  int y,
  patch_t** il,
  int* inum,
  boolean* on )
{
    i->x = x;
    i->y = y;
    i->oldinum = -1;
    i->inum = inum;
    i->on = on;
    i->p = il;
}
void
STlib_updateMultIcon
( st_multicon_t* mi,
  boolean refresh )
{
    int w;
    int h;
    int x;
    int y;
    if (*mi->on
 && (mi->oldinum != *mi->inum || refresh)
 && (*mi->inum!=-1))
    {
 if (mi->oldinum != -1)
 {
     x = mi->x - (mi->p[mi->oldinum]->leftoffset);
     y = mi->y - (mi->p[mi->oldinum]->topoffset);
     w = (mi->p[mi->oldinum]->width);
     h = (mi->p[mi->oldinum]->height);
     if (y - (200 - 32*1) < 0)
  I_Error("updateMultIcon: y - ST_Y < 0");
     V_CopyRect(x, y-(200 - 32*1), 4, w, h, x, y, 0);
 }
 V_DrawPatch(mi->x, mi->y, 0, mi->p[*mi->inum]);
 mi->oldinum = *mi->inum;
    }
}
void
STlib_initBinIcon
( st_binicon_t* b,
  int x,
  int y,
  patch_t* i,
  boolean* val,
  boolean* on )
{
    b->x = x;
    b->y = y;
    b->oldval = 0;
    b->val = val;
    b->on = on;
    b->p = i;
}
void
STlib_updateBinIcon
( st_binicon_t* bi,
  boolean refresh )
{
    int x;
    int y;
    int w;
    int h;
    if (*bi->on
 && (bi->oldval != *bi->val || refresh))
    {
 x = bi->x - (bi->p->leftoffset);
 y = bi->y - (bi->p->topoffset);
 w = (bi->p->width);
 h = (bi->p->height);
 if (y - (200 - 32*1) < 0)
     I_Error("updateBinIcon: y - ST_Y < 0");
 if (*bi->val)
     V_DrawPatch(bi->x, bi->y, 0, bi->p);
 else
     V_CopyRect(x, y-(200 - 32*1), 4, w, h, x, y, 0);
 bi->oldval = *bi->val;
    }
}
