static boolean st_stopped = true;
void ST_Start (void)
{
    if (!st_stopped)
 ST_Stop();
    ST_initData();
    ST_createWidgets();
    st_stopped = false;
}
void ST_Stop (void)
{
    if (st_stopped)
 return;
    I_SetPalette (W_CacheLumpNum (lu_palette, 101));
    st_stopped = true;
}
void ST_Init (void)
{
    veryfirsttime = 0;
    ST_loadData();
    screens[4] = (byte *) Z_Malloc(320*32*1, 1, 0);
}
static const char
rcsid[] = "$Id: tables.c,v 1.4 1997/02/03 16:47:57 b1 Exp $";
int
SlopeDiv
( unsigned num,
  unsigned den)
{
    unsigned ans;
    if (den < 512)
 return 2048;
    ans = (num<<3)/(den>>8);
    return ans <= 2048 ? ans : 2048;
}
