{
    byte* src;
    if (x<0
 ||x+width >320
 || y<0
 || y+height>200
 || (unsigned)scrn>4 )
    {
 I_Error ("Bad V_DrawBlock");
    }
    src = screens[scrn] + y*320 +x;
    while (height--)
    {
 memcpy (dest, src, width);
 src += 320;
 dest += width;
    }
}
