static const char
rcsid[] = "$Id: w_wad.c,v 1.5 1997/02/03 16:47:57 b1 Exp $";
lumpinfo_t* lumpinfo;
int numlumps;
void** lumpcache;
void strupr (char* s)
{
    while (*s) { *s = toupper(*s); s++; }
}
int filelength (int handle)
{
    struct stat fileinfo;
    if (fstat (handle,&fileinfo) == -1)
 I_Error ("Error fstating");
    return fileinfo.st_size;
}
void
ExtractFileBase
( char* path,
  char* dest )
{
    char* src;
    int length;
    src = path + strlen(path) - 1;
    while (src != path
    && *(src-1) != '\\'
    && *(src-1) != '/')
    {
 src--;
    }
    memset (dest,0,8);
    length = 0;
    while (*src && *src != '.')
    {
 if (++length == 9)
     I_Error ("Filename base of %s >8 chars",path);
 *dest++ = toupper((int)*src++);
    }
}
int reloadlump;
char* reloadname;
void W_AddFile (char *filename)
{
    wadinfo_t header;
    lumpinfo_t* lump_p;
    unsigned i;
    int handle;
    int length;
    int startlump;
    filelump_t* fileinfo;
    filelump_t singleinfo;
    int storehandle;
    if (filename[0] == '~')
    {
 filename++;
 reloadname = filename;
 reloadlump = numlumps;
    }
    if ( (handle = open (filename,00 | 0)) == -1)
    {
 printf (" couldn't open %s\n",filename);
 return;
    }
    printf (" adding %s\n",filename);
    startlump = numlumps;
    if (strcasecmp (filename+strlen(filename)-3 , "wad" ) )
    {
 fileinfo = &singleinfo;
 singleinfo.filepos = 0;
 singleinfo.size = (filelength(handle));
 ExtractFileBase (filename, singleinfo.name);
 numlumps++;
    }
    else
    {
 read (handle, &header, sizeof(header));
 if (strncmp(header.identification,"IWAD",4))
 {
     if (strncmp(header.identification,"PWAD",4))
     {
  I_Error ("Wad file %s doesn't have IWAD "
    "or PWAD id\n", filename);
     }
 }
 header.numlumps = (header.numlumps);
 header.infotableofs = (header.infotableofs);
 length = header.numlumps*sizeof(filelump_t);
 fileinfo = __builtin_alloca (length);
 lseek (handle, header.infotableofs, 0);
 read (handle, fileinfo, length);
 numlumps += header.numlumps;
    }
    lumpinfo = realloc (lumpinfo, numlumps*sizeof(lumpinfo_t));
    if (!lumpinfo)
 I_Error ("Couldn't realloc lumpinfo");
    lump_p = &lumpinfo[startlump];
    storehandle = reloadname ? -1 : handle;
    for (i=startlump ; i<numlumps ; i++,lump_p++, fileinfo++)
    {
 lump_p->handle = storehandle;
 lump_p->position = (fileinfo->filepos);
 lump_p->size = (fileinfo->size);
 strncpy (lump_p->name, fileinfo->name, 8);
    }
    if (reloadname)
 close (handle);
}
void W_Reload (void)
{
    wadinfo_t header;
    int lumpcount;
    lumpinfo_t* lump_p;
    unsigned i;
    int handle;
    int length;
    filelump_t* fileinfo;
    if (!reloadname)
 return;
    if ( (handle = open (reloadname,00 | 0)) == -1)
 I_Error ("W_Reload: couldn't open %s",reloadname);
    read (handle, &header, sizeof(header));
    lumpcount = (header.numlumps);
    header.infotableofs = (header.infotableofs);
    length = lumpcount*sizeof(filelump_t);
    fileinfo = __builtin_alloca (length);
    lseek (handle, header.infotableofs, 0);
    read (handle, fileinfo, length);
    lump_p = &lumpinfo[reloadlump];
    for (i=reloadlump ;
  i<reloadlump+lumpcount ;
  i++,lump_p++, fileinfo++)
    {
 if (lumpcache[i])
     Z_Free (lumpcache[i]);
 lump_p->position = (fileinfo->filepos);
 lump_p->size = (fileinfo->size);
    }
    close (handle);
}
void W_InitMultipleFiles (char** filenames)
{
    int size;
    numlumps = 0;
    lumpinfo = malloc(1);
    for ( ; *filenames ; filenames++)
 W_AddFile (*filenames);
    if (!numlumps)
 I_Error ("W_InitFiles: no files found");
    size = numlumps * sizeof(*lumpcache);
    lumpcache = malloc (size);
    if (!lumpcache)
 I_Error ("Couldn't allocate lumpcache");
    memset (lumpcache,0, size);
}
void W_InitFile (char* filename)
{
    char* names[2];
    names[0] = filename;
    names[1] = ((void *)0);
    W_InitMultipleFiles (names);
}
int W_NumLumps (void)
{
    return numlumps;
}
int W_CheckNumForName (char* name)
{
    union {
 char s[9];
 int x[2];
    } name8;
    int v1;
    int v2;
    lumpinfo_t* lump_p;
    strncpy (name8.s,name,8);
    name8.s[8] = 0;
    strupr (name8.s);
    v1 = name8.x[0];
    v2 = name8.x[1];
    lump_p = lumpinfo + numlumps;
    while (lump_p-- != lumpinfo)
    {
 if ( *(int *)lump_p->name == v1
      && *(int *)&lump_p->name[4] == v2)
 {
     return lump_p - lumpinfo;
 }
    }
    return -1;
}
int W_GetNumForName (char* name)
{
    int i;
    i = W_CheckNumForName (name);
    if (i == -1)
      I_Error ("W_GetNumForName: %s not found!", name);
    return i;
}
int W_LumpLength (int lump)
{
    if (lump >= numlumps)
 I_Error ("W_LumpLength: %i >= numlumps",lump);
    return lumpinfo[lump].size;
}
void
W_ReadLump
( int lump,
  void* dest )
{
    int c;
    lumpinfo_t* l;
    int handle;
    if (lump >= numlumps)
 I_Error ("W_ReadLump: %i >= numlumps",lump);
    l = lumpinfo+lump;
    if (l->handle == -1)
    {
 if ( (handle = open (reloadname,00 | 0)) == -1)
     I_Error ("W_ReadLump: couldn't open %s",reloadname);
    }
    else
 handle = l->handle;
    lseek (handle, l->position, 0);
    c = read (handle, dest, l->size);
    if (c < l->size)
 I_Error ("W_ReadLump: only read %i of %i on lump %i",
   c,l->size,lump);
    if (l->handle == -1)
 close (handle);
}
void*
W_CacheLumpNum
( int lump,
  int tag )
{
    byte* ptr;
    if ((unsigned)lump >= numlumps)
 I_Error ("W_CacheLumpNum: %i >= numlumps",lump);
    if (!lumpcache[lump])
    {
 ptr = Z_Malloc (W_LumpLength (lump), tag, &lumpcache[lump]);
 W_ReadLump (lump, lumpcache[lump]);
    }
    else
    {
 { if (( (memblock_t *)( (byte *)(lumpcache[lump]) - sizeof(memblock_t)))->id!=0x1d4a11) I_Error("Z_CT at ""doom_amalg.c"":%i",42692); Z_ChangeTag2(lumpcache[lump],tag); };;
    }
    return lumpcache[lump];
}
void*
W_CacheLumpName
( char* name,
  int tag )
{
    return W_CacheLumpNum (W_GetNumForName(name), tag);
}
int info[2500][10];
int profilecount;
void W_Profile (void)
{
    int i;
    memblock_t* block;
    void* ptr;
    char ch;
    FILE* f;
    int j;
    char name[9];
    for (i=0 ; i<numlumps ; i++)
    {
 ptr = lumpcache[i];
 if (!ptr)
 {
     ch = ' ';
     continue;
 }
 else
 {
     block = (memblock_t *) ( (byte *)ptr - sizeof(memblock_t));
     if (block->tag < 100)
  ch = 'S';
     else
  ch = 'P';
 }
 info[i][profilecount] = ch;
    }
    profilecount++;
    f = fopen ("waddump.txt","w");
    name[8] = 0;
    for (i=0 ; i<numlumps ; i++)
    {
 memcpy (name,lumpinfo[i].name,8);
 for (j=0 ; j<8 ; j++)
     if (!name[j])
  break;
 for ( ; j<8 ; j++)
     name[j] = ' ';
 fprintf (f,"%s ",name);
 for (j=0 ; j<profilecount ; j++)
     fprintf (f,"    %c",info[i][j]);
 fprintf (f,"\n");
    }
    fclose (f);
}
