void
WI_drawOnLnode
( int n,
  patch_t* c[] )
{
    int i;
    int left;
    int top;
    int right;
    int bottom;
    boolean fits = false;
    i = 0;
    do
    {
 left = lnodes[wbs->epsd][n].x - (c[i]->leftoffset);
 top = lnodes[wbs->epsd][n].y - (c[i]->topoffset);
 right = left + (c[i]->width);
 bottom = top + (c[i]->height);
 if (left >= 0
     && right < 320
     && top >= 0
     && bottom < 200)
 {
     fits = true;
 }
 else
 {
     i++;
 }
    } while (!fits && i!=2);
    if (fits && i<2)
    {
 V_DrawPatch(lnodes[wbs->epsd][n].x, lnodes[wbs->epsd][n].y,
      0, c[i]);
    }
    else
    {
 printf("Could not place patch on level %d", n+1);
    }
}
void WI_initAnimatedBack(void)
{
    int i;
    anim_t* a;
    if (gamemode == commercial)
 return;
    if (wbs->epsd > 2)
 return;
    for (i=0;i<NUMANIMS[wbs->epsd];i++)
    {
 a = &anims[wbs->epsd][i];
 a->ctr = -1;
 if (a->type == ANIM_ALWAYS)
     a->nexttic = bcnt + 1 + (M_Random()%a->period);
 else if (a->type == ANIM_RANDOM)
     a->nexttic = bcnt + 1 + a->data2+(M_Random()%a->data1);
 else if (a->type == ANIM_LEVEL)
     a->nexttic = bcnt + 1;
    }
}
void WI_updateAnimatedBack(void)
{
    int i;
    anim_t* a;
    if (gamemode == commercial)
 return;
    if (wbs->epsd > 2)
 return;
    for (i=0;i<NUMANIMS[wbs->epsd];i++)
    {
 a = &anims[wbs->epsd][i];
 if (bcnt == a->nexttic)
 {
     switch (a->type)
     {
       case ANIM_ALWAYS:
  if (++a->ctr >= a->nanims) a->ctr = 0;
  a->nexttic = bcnt + a->period;
  break;
       case ANIM_RANDOM:
  a->ctr++;
  if (a->ctr == a->nanims)
  {
      a->ctr = -1;
      a->nexttic = bcnt+a->data2+(M_Random()%a->data1);
  }
  else a->nexttic = bcnt + a->period;
  break;
       case ANIM_LEVEL:
  if (!(state == StatCount && i == 7)
      && wbs->next == a->data1)
  {
      a->ctr++;
      if (a->ctr == a->nanims) a->ctr--;
      a->nexttic = bcnt + a->period;
  }
  break;
     }
 }
    }
}
void WI_drawAnimatedBack(void)
{
    int i;
    anim_t* a;
    if (commercial)
 return;
    if (wbs->epsd > 2)
 return;
    for (i=0 ; i<NUMANIMS[wbs->epsd] ; i++)
    {
 a = &anims[wbs->epsd][i];
 if (a->ctr >= 0)
     V_DrawPatch(a->loc.x, a->loc.y, 0, a->p[a->ctr]);
    }
}
int
WI_drawNum
( int x,
  int y,
  int n,
  int digits )
{
    int fontwidth = (num[0]->width);
    int neg;
    int temp;
    if (digits < 0)
    {
 if (!n)
 {
     digits = 1;
 }
 else
 {
     digits = 0;
     temp = n;
     while (temp)
     {
  temp /= 10;
  digits++;
     }
 }
    }
    neg = n < 0;
    if (neg)
 n = -n;
    if (n == 1994)
 return 0;
    while (digits--)
    {
 x -= fontwidth;
 V_DrawPatch(x, y, 0, num[ n % 10 ]);
 n /= 10;
    }
    if (neg)
 V_DrawPatch(x-=8, y, 0, wiminus);
    return x;
}
