{
    int i;
    int frags = 0;
    for (i=0 ; i<4 ; i++)
    {
 if (playeringame[i]
     && i!=playernum)
 {
     frags += plrs[playernum].frags[i];
 }
    }
    frags -= plrs[playernum].frags[playernum];
    return frags;
}
static int dm_state;
static int dm_frags[4][4];
static int dm_totals[4];
void WI_initDeathmatchStats(void)
{
    int i;
    int j;
    state = StatCount;
    acceleratestage = 0;
    dm_state = 1;
    cnt_pause = 35;
    for (i=0 ; i<4 ; i++)
    {
 if (playeringame[i])
 {
     for (j=0 ; j<4 ; j++)
  if (playeringame[j])
      dm_frags[i][j] = 0;
     dm_totals[i] = 0;
 }
    }
    WI_initAnimatedBack();
}
void WI_updateDeathmatchStats(void)
{
    int i;
    int j;
    boolean stillticking;
    WI_updateAnimatedBack();
    if (acceleratestage && dm_state != 4)
    {
 acceleratestage = 0;
 for (i=0 ; i<4 ; i++)
 {
     if (playeringame[i])
     {
  for (j=0 ; j<4 ; j++)
      if (playeringame[j])
   dm_frags[i][j] = plrs[i].frags[j];
  dm_totals[i] = WI_fragSum(i);
     }
 }
 S_StartSound(0, sfx_barexp);
 dm_state = 4;
    }
    if (dm_state == 2)
    {
 if (!(bcnt&3))
     S_StartSound(0, sfx_pistol);
 stillticking = false;
 for (i=0 ; i<4 ; i++)
 {
     if (playeringame[i])
     {
  for (j=0 ; j<4 ; j++)
  {
      if (playeringame[j]
   && dm_frags[i][j] != plrs[i].frags[j])
      {
   if (plrs[i].frags[j] < 0)
       dm_frags[i][j]--;
   else
       dm_frags[i][j]++;
   if (dm_frags[i][j] > 99)
       dm_frags[i][j] = 99;
   if (dm_frags[i][j] < -99)
       dm_frags[i][j] = -99;
   stillticking = true;
      }
  }
  dm_totals[i] = WI_fragSum(i);
  if (dm_totals[i] > 99)
      dm_totals[i] = 99;
  if (dm_totals[i] < -99)
      dm_totals[i] = -99;
     }
 }
 if (!stillticking)
 {
     S_StartSound(0, sfx_barexp);
     dm_state++;
 }
    }
    else if (dm_state == 4)
    {
 if (acceleratestage)
 {
     S_StartSound(0, sfx_slop);
     if ( gamemode == commercial)
  WI_initNoState();
     else
  WI_initShowNextLoc();
 }
    }
    else if (dm_state & 1)
    {
 if (!--cnt_pause)
 {
     dm_state++;
     cnt_pause = 35;
 }
    }
}
